import type { Verse } from '../types';

// Capítulos reais deste livro. Segue o mesmo formato de src/bible/genesis.ts:
// { n: <capítulo>: [ { n: <versículo>, text: '<texto>' }, ... ] }
export const EXODUS_CHAPTERS: Record<number, Verse[]> = {
  1: [
    { n: 1, text: 'Lawa i mavito ya vana va Israyele lava nga nghena eEgipta xikan\u2019we ni tatana wa vona Akobo; un\u2019wana ni un\u2019wana a nghena ni yindlu ya yena:' },
    { n: 2, text: 'Rubeni, Simiyoni, Levi, ni Yuda;' },
    { n: 3, text: 'Isakara, Zebuloni, ni Benjamini;' },
    { n: 4, text: 'Dani, ni Neftali, Gadi, ni Axere.' },
    { n: 5, text: 'Hinkwaso timbilu leti humeke exirhendzeni xa Akobo a ti ri makume-nkombo (70) wa timbilu; kasi Josefa a a ri eEgipta.' },
    { n: 6, text: 'Josefa a fa, ni vamakwerhu va yena hinkvavo, ni xitshungu xero hinkwasxo.' },
    { n: 7, text: 'Vana va Israyele va tswalana, va andza swinene, va tala, va va ni matimba lamakulu swinene; tiko ri tala hi vona.' },
    { n: 8, text: 'Kutani ku pfuka hosi leyintshwa ehenhla ka Egipta, leyi a yi nga n\u2019wi tivi Josefa.' },
    { n: 9, text: 'Yena a ku eka vanhu va yena: Vonani, vanhu va vana va Israyele va tele, naswona va ni matimba ku hi tlula.' },
    { n: 10, text: 'Tani, a hi va endleni hi vutlhari, leswaku va nga andzi; hikuva loko ku pfuka nyimpi, na vona va nga hlangana ni valala va hina, va lwa na hina, va huma etikweni.' },
    { n: 11, text: 'Hiloko va va vekela valanguteri va mintirho yo tika, ku va karhata hi mindzhwalo ya vona. Va aka miti ya vuhlayiselo ya Faro: Pitoma ni Ramese.' },
    { n: 12, text: 'Kambe hi laha va nga va karhata hakona, hi laha va nga andza ni ku hangalaka hakona; kutani va karhateka swinene hikwalaho ka vana va Israyele.' },
    { n: 13, text: 'Vaegipta va sindzisa vana va Israyele ku tirha hi tihanyi.' },
    { n: 14, text: 'Va vavisa vutomi bya vona hi vutirheli byo tika, hi ntsengeto ni maritshana, ni hi vutirheli hinkwabyo bya le masin\u2019wini; mintirho ya vona hinkwayo leyi va nga va sindzisa ku yi tirha a yi ri ya tihanyi.' },
    { n: 15, text: 'Hosi ya Egipta a vulavula ni vahlawuri va vavasati va Vaheveru, lava un\u2019wana a a vitaniwa Xifra, ni lowu un\u2019wana Pua, a ku:' },
    { n: 16, text: 'Loko mi lulamisela vavasati va Vaheveru ku tswala, mi vona n\u2019wana enhlokweni ya mbedli; loko ku ri n\u2019wana wa jaha, mi n\u2019wi dlaya, kambe loko ku ri n\u2019wana wa nhwanyana, a a hanye.' },
    { n: 17, text: 'Kambe vahlawuri va vavasati va chava Xikwembu, a va endlanga hilaha hosi ya Egipta a nga va lerisa hakona; va tshika majaha ma hanya.' },
    { n: 18, text: 'Hosi ya Egipta a vitana vahlawuri va vavasati, a ku eka vona: Ha yini mi endle sweswo, mi tshika majaha ma hanya ke?' },
    { n: 19, text: 'Vahlawuri va vavasati va ku eka Faro: Hikuva vavasati va Vaheveru a va fani ni vavasati va Vaegipta; hikuva va ni matimba; va tswala va nga si fika vahlawuri va vavasati eka vona.' },
    { n: 20, text: 'Xikwembu xi endla leswo saseka eka vahlawuri va vavasati; kutani vanhu va andza, va va ni matimba lamakulu.' },
    { n: 21, text: 'Kutani hikwalaho ka leswi vahlawuri va vavasati va nga chava Xikwembu, xi va nyika tindyandlu.' },
    { n: 22, text: 'Faro a lerisa vanhu va yena hinkvavo, a ku: Un\u2019wana ni un\u2019wana n\u2019wana wa jaha loyi a nga ta tswariwa, n\u2019wi lahleni enambini, kambe vanhwanyana hinkwavo va tshikeni va hanya.' },
  ],
  2: [
    { n: 1, text: 'Kutani wanuna wa yindlu ya Levi a ya teka n\u2019wana wa nhwanyana wa Levi.' },
    { n: 2, text: 'Wansati a mitsika, a tswala n\u2019wana wa jaha; loko a vona leswaku u sasekile swinene, a n\u2019wi fihla tin\u2019hweti tinharhu.' },
    { n: 3, text: 'Loko a nga ha koti ku n\u2019wi fihla, a n\u2019wi tekela nswatla wa mapfuta, a wu khaba hi betume ni pez, a veka n\u2019wana endzeni ka wona, a n\u2019wi veka exikarhi ka mapfuta eribuweni ra nambu.' },
    { n: 4, text: 'Kasi makwerhu wa yena wa nhwanyana a a yimile ekule, ku vona leswi nga ta n\u2019wi kela.' },
    { n: 5, text: 'N\u2019wana wa nhwanyana wa Faro a rhelela ku ta hlamba enambini; na vamakwerhu va yena va vavasati a va famba-famba eribuweni ra nambu; a vona nswatla exikarhi ka mapfuta, a rhuma nandza wa yena wa wansati ku ya wu teka.' },
    { n: 6, text: 'A pfula nswatla, a vona n\u2019wana; kutani vonani, n\u2019wana wa jaha a a rila; a n\u2019wi tsetselela, a ku: Loyi i un\u2019wana wa vana va Vaheveru.' },
    { n: 7, text: 'Makwerhu wa yena wa nhwanyana a ku eka n\u2019wana wa nhwanyana wa Faro: Xana ndzi nga ya ku vitanela wansati loyi a antswisaka exikarhi ka Vaheveru, leswaku a ku antswisela n\u2019wana loyi ke?' },
    { n: 8, text: 'N\u2019wana wa nhwanyana wa Faro a ku eka yena: Famba. Nhwanyana a famba, a vitana mhani wa n\u2019wana.' },
    { n: 9, text: 'N\u2019wana wa nhwanyana wa Faro a ku eka yena: Teka n\u2019wana loyi, u ndzi antswisela yena, ndzi ta ku nyika hofo ya wena. Wansati a teka n\u2019wana, a n\u2019wi antswisa.' },
    { n: 10, text: 'Loko n\u2019wana a kurile, a n\u2019wi tisa eka n\u2019wana wa nhwanyana wa Faro, a hundzuka n\u2019wana wa yena. A n\u2019wi thya vito ra Moxe, a ku: Hikuva ndzi n\u2019wi humesile ematini.' },
    { n: 11, text: 'Kutani emasikwini wolawo, loko Moxe a kurile, a huma a ya eka vamakwerhu va yena, a vona mindzhwalo ya vona; a vona Muegipta a baka Muheveru, un\u2019wana wa vamakwerhu va yena.' },
    { n: 12, text: 'A languta haleno ni haleno, loko a vona leswaku a ku na munhu, a dlaya Muegipta loyi, a n\u2019wi fihla exirhovini.' },
    { n: 13, text: 'A huma hi siku leri landzelaka, kutani vonani, vavanuna vambirhi va Vaheveru a va lwa; a ku eka loyi a a dyohele un\u2019wana: Ha yini u ba munhu wa kwenu ke?' },
    { n: 14, text: 'Yena a ku: I mani la nga ku veka u va ndhuna ni muavanyisi ehenhla ka hina? Xana u lava ku ndzi dlaya hilaha u nga dlayisa hakona Muegipta ke? Moxe a chava, a ku: Hakunene nchumu lowu wu tiviwile.' },
    { n: 15, text: 'Loko Faro a twa mhaka leyi, a lava ku dlaya Moxe; kambe Moxe a tsutsuma mahlweni ka Faro, a ya tshama etikweni ra Midiyani; a tshama kusuhi ni xihlovo xa mati.' },
    { n: 16, text: 'Muprista wa Midiyani a a ri ni vana va nhwanyana va nkombo; va fika va ka mati, va tata mikamberi ku nyika swifuwo swa tata wa vona mati.' },
    { n: 17, text: 'Varisi va fika, va va hlongola; kambe Moxe a pfuka, a va pfuna, a nyika swifuwo swa vona mati.' },
    { n: 18, text: 'Loko va fika eka Reguweri tata va vona, a ku eka vona: Ha yini mi vuyile hi ku hatlisa namuntlha ke?' },
    { n: 19, text: 'Va ku: Muegipta un\u2019wana u hi ponisile emavokweni ya varisi, naswona u hi kele mati, a nyika swifuwo mati.' },
    { n: 20, text: 'A ku eka vana va yena: U kwihi ke? Ha yini mi siyile wanuna loyi? N\u2019wi vitaneni leswaku a ta dya swakudya.' },
    { n: 21, text: 'Moxe a pfumela ku tshama ni wanuna loyi; yena a nyika Moxe n\u2019wana wa yena Tsipora.' },
    { n: 22, text: 'A tswala n\u2019wana wa jaha, Moxe a n\u2019wi thya vito ra Gerixoma, a ku: Ndzi vile mulyeri etikweni ra vulyeri.' },
    { n: 23, text: 'Endzhaku ka masiku yo tala hosi ya Egipta a fa; vana va Israyele va rila hikwalaho ka vutirheli, va rila; kutani ku rila ka vona ku fika eka Xikwembu hikwalaho ka vutirheli.' },
    { n: 24, text: 'Xikwembu xi twa ku rila ka vona, xi tsundzuka xihambalo xa xona na Abrahama, Isaka, na Akobo.' },
    { n: 25, text: 'Xikwembu xi vona vana va Israyele, kutani Xikwembu xi va twisisa.' },
  ],
  3: [
    { n: 1, text: 'Moxe a a risa swifuwo va Yetro mukon\u2019wana wa yena, muprista wa Midiyani; a fambisa swifuwo endzhaku ka mananga, a fika eHorebe, xitsunga xa Xikwembu.' },
    { n: 2, text: 'Ntsumi ya Yehovha yi n\u2019wi humelela hi langavi ra ndzilo exikarhi ka xihlahla xa mintwa; a languta, kutani vonani, xihlahla a xi pfurha ndzilo, kambe a xi nga tswi.' },
    { n: 3, text: 'Moxe a ku: Ndzi ta tshinela ndzi vona xivono lexi lexikulu, leswaku ha yini xihlahla xi nga tswi ke.' },
    { n: 4, text: 'Loko Yehovha a vona leswaku wa tshinela ku ta vona, Xikwembu xi n\u2019wi vitana exikarhi ka xihlahla, xi ku: Moxe, Moxe! Yena a ku: Ndzi kwala.' },
    { n: 5, text: 'Xi ku: U nga tshineli kwala; humesa tinhangilasera emilengeni ya wena, hikuva ndhawu leyi u yimeke ka yona i misava yo kwetsima.' },
    { n: 6, text: 'Xi tlhela xi ku: Ndzi Xikwembu xa tata wa wena, Xikwembu xa Abrahama, Xikwembu xa Isaka, ni Xikwembu xa Akobo. Moxe a fihla xikandza xa yena, hikuva a a chava ku languta Xikwembu.' },
    { n: 7, text: 'Yehovha a ku: Hakunene ndzi vonile ku karhateka ka vanhu va mina lava nga eEgipta, ndzi twile ni ku rila ka vona hikwalaho ka valanguteri va vona; hikuva ndzi tiva ku vaviseka ka vona.' },
    { n: 8, text: 'Ndzi rhelerile ku ta va ponisa emavokweni ya Vaegipta, ni ku va humesa etikweni rero ndzi va yisa etikweni leri nene ni ro anama, etikweni leri khulukaka ntswamba ni vulombe, endhawini ya Vakanana, Vaheti, Vaamori, Vaperezi, Vahivi, ni Vayebusi.' },
    { n: 9, text: 'Sweswi, vonani, ku rila ka vana va Israyele ku fikile eka mina; ndzi vonile ni ku tlimbiwa loku Vaegipta va va tlimbaka ha kona.' },
    { n: 10, text: 'Tani sweswi, ndzi ta ku rhuma eka Faro, leswaku u humesa vanhu va mina, vana va Israyele, eEgipta.' },
    { n: 11, text: 'Moxe a ku eka Xikwembu: Hi mina mani leswaku ndzi nga ya eka Faro, ndzi humesa vana va Israyele eEgipta ke?' },
    { n: 12, text: 'Xi ku: Hakunene ndzi ta va na wena; xikombiso lexi nga ta ku komba leswaku ndzi ku rhumile hi lexi: Loko u humesile vanhu eEgipta, mi ta gandzela Xikwembu exitsungeni lexi.' },
    { n: 13, text: 'Moxe a ku eka Xikwembu: Vonani, loko ndzi fika eka vana va Israyele, ndzi ku eka vona: \u2018Xikwembu xa vatata wa n\u2019wina xi ndzi rhumile eka n\u2019wina\u2019, kutani va ndzi vutisa va ku: \u2018Vito ra xona i mani ke?\u2019 Ndzi ta ku yini eka vona?' },
    { n: 14, text: 'Xikwembu xi ku eka Moxe: NDZI NTIYISO NDZI LEYI NDZI NGA YONA. Xi tlhela xi ku: U ta vula tano eka vana va Israyele: \u2018NDZI LEYI NDZI NGA YONA u ndzi rhumile eka n\u2019wina.\u2019' },
    { n: 15, text: 'Xikwembu xi tlhela xi ku eka Moxe: U ta vula tano eka vana va Israyele: \u2018Yehovha, Xikwembu xa vatata wa n\u2019wina, Xikwembu xa Abrahama, Xikwembu xa Isaka, ni Xikwembu xa Akobo, u ndzi rhumile eka n\u2019wina; leri i vito ra mina leri nga heriki, ni xitsundzuxo xa mina xitshungu ni xitshungu.\u2019' },
    { n: 16, text: 'Famba, u hlengeleta vakhalabye va Israyele, u ku eka vona: \u2018Yehovha, Xikwembu xa vatata wa n\u2019wina, Xikwembu xa Abrahama, Isaka, ni Akobo, u ndzi humelele, a ku: Ndzi mi endlerile vuxaka, ndzi vonile ni leswi mi endliwangra swona eEgipta.\u2019' },
    { n: 17, text: 'Ndzi tsarile ndzi ku: \u2018Ndzi ta mi humesa eku karhatekeni ka Egipta ndzi mi yisa etikweni ra Vakanana, Vaheti, Vaamori, Vaperezi, Vahivi, ni Vayebusi, etikweni leri khulukaka ntswamba ni vulombe.\u2019' },
    { n: 18, text: 'Va ta yingisela rito ra wena; u ta nghena, wena ni vakhalabye va Israyele, eka hosi ya Egipta, mi ku eka yena: \u2018Yehovha, Xikwembu xa Vaheveru, xi hlangane na hina; sweswi, hi kombela u hi pfumelela hi famba riendzo la masiku manharhu emananga, hi ya tlhavela Yehovha Xikwembu xa hina ntsengo.\u2019' },
    { n: 19, text: 'Kambe ndzi tiva leswaku hosi ya Egipta a yi nga mi pfumeleli ku famba, handle ka loko yi tlimbiwa hi voko ra matimba.' },
    { n: 20, text: 'Ndzi ta navisa voko ra mina, ndzi ba Egipta hi hinkwaswo swihlamariso va mina leswi ndzi nga ta va na swona exikarhi ka yena; endzhaku ka swilo leswi u ta mi pfumelela ku famba.' },
    { n: 21, text: 'Ndzi ta nyika vanhu lava tintswalo emantweni ya Vaegipta; kutani ku ta va leswaku loko mi famba, mi nga ka mi nga fambi mi nga ri na nchumu;' },
    { n: 22, text: 'kambe wansati un\u2019wana ni un\u2019wana u ta kombela eka muakelani wa yena, ni le ka loyi a tshamaka endlwini ya yena, swilo swa silivhere, swilo swa nsuku, ni tinguvu, mi swi veka ehenhla ka vana va n\u2019wina va majaha ni va vanhwanyana; kutani mi ta phanga Vaegipta.' },
  ],
  4: [
    { n: 1, text: 'Moxe a hlamula, a ku: Kambe vonani, a va nga ndzi pfumeli, naswona a va nga yingiseli rito ra mina, hikuva va ta ku: \u2018Yehovha a nga ku humelelanga.\u2019' },
    { n: 2, text: 'Yehovha a ku eka yena: I yini leswi nga evokweni ra wena ke? Yena a ku: I nhonga.' },
    { n: 3, text: 'Xi ku: Yi lahle hansi. A yi lahla hansi, hiloko yi hundzuka nyoka; Moxe a tsutsuma mahlweni ka yona.' },
    { n: 4, text: 'Yehovha a ku eka Moxe: Navisa voko ra wena, u yi khoma hi ncila. A navisa voko ra yena, a yi khoma, hiloko yi hundzuka nhonga evokweni ra yena.' },
    { n: 5, text: 'Xi ku: Leswaku va pfumela leswaku Yehovha, Xikwembu xa vatata wa vona, Xikwembu xa Abrahama, Xikwembu xa Isaka, ni Xikwembu xa Akobo, u ku humelele.' },
    { n: 6, text: 'Yehovha a tlhela a ku eka yena: Nghenisa voko ra wena exifuvenini xa wena. A nghenisa voko ra yena exifuvenini xa yena; loko a xi humesa, vonani, voko ra yena a ri tele hi nhlokonho, ri basa ku fana ni gamba.' },
    { n: 7, text: 'Xi ku: Tlherisela voko ra wena exifuvenini xa wena. A tlherisela voko ra yena exifuvenini xa yena; loko a xi humesa exifuvenini xa yena, vonani, a ri hundzukile ri fana ni nyama ya yena leyin\u2019wana.' },
    { n: 8, text: 'Xi ku: Loko swi ta va leswaku a va ku pfumeli, naswona a va yingiseli rito ra xikombiso xo sungula, va ta pfumela rito ra xikombiso lexi landzelaka.' },
    { n: 9, text: 'Loko swi ta va leswaku a va pfumeli ni swikombiso leswi swimbirhi, naswona a va yingiseli rito ra wena, u ta teka mati ya nambu, u ya lahla enhlabanyini; kutani mati lawa u nga ta ya teka enambini ya ta hundzuka ngati enhlabanyini.' },
    { n: 10, text: 'Moxe a ku eka Yehovha: O n\u2019wini wa mina, a ndzi n\u2019winyi wa marito, hambi eka ma-tolo, hambi eka masiku lama hundzeke, hambi kusukela loko u vulavurile ni nandza wa wena; hikuva ndzi na rito lera kulu ni ririmi leri tikaka.' },
    { n: 11, text: 'Yehovha a ku eka yena: I mani la nga endla nomu wa munhu ke? Kumbe i mani la endlaka mbheveve, kumbe la feke tindleve, kumbe la vonaka, kumbe la feke mahlo ke? Xana a hi mina Yehovha ke?' },
    { n: 12, text: 'Tani sweswi famba, ndzi ta va ni nomu wa wena, ndzi ku dyondzisa leswi u faneleke ku swi vula.' },
    { n: 13, text: 'Kambe Moxe a ku: O n\u2019wini wa mina, ndzi kombela u rhuma hi voko ra loyi u rhandzaka ku n\u2019wi rhuma.' },
    { n: 14, text: 'Kutani ku hlundguka ka Yehovha ku pfurha ehenhla ka Moxe, a ku: Xana Aroni Mulevi a hi makwerhu wa wena ke? Ndzi tiva leswaku yena wa swi kota ku vulavula kahle; naswona vona, wa huma ku ta hlangana na wena, kutani loko a ku vona, u ta tsaka mbilu.' },
    { n: 15, text: 'U ta vulavula na yena, u veka marito enon\u2019wini wa yena; ndzi ta va ni nomu wa wena, ni nomu wa yena, ndzi mi komba leswi mi faneleke ku swi endla.' },
    { n: 16, text: 'Yena u ta vulavula ni vanhu hikwalaho ka wena; u ta va nomu eka wena, kutani wena u ta va Xikwembu eka yena.' },
    { n: 17, text: 'U ta teka nhonga leyi evokweni ra wena, leyi u nga ta endla swikombiso ha yona.' },
    { n: 18, text: 'Moxe a suka, a vuyela eka Yetro mukon\u2019wana wa yena, a ku eka yena: Ndzi kombela u ndzi pfumelela ndzi famba ndzi vuyela eka vamakwerhu lava nga eEgipta, ndzi ya vona loko va ha hanya. Yetro a ku eka Moxe: Famba hi ku rhula.' },
    { n: 19, text: 'Yehovha a ku eka Moxe eMidiyani: Famba, vuyela eEgipta, hikuva vavanuna hinkvavo lava a va lava vutomi bya wena va file.' },
    { n: 20, text: 'Moxe a teka nsati wa yena ni vana va yena va majaha, a va fambisa ehenhla ka mbanga, a vuyela etikweni la Egipta; Moxe a teka ni nhonga ya Xikwembu evokweni ra yena.' },
    { n: 21, text: 'Yehovha a ku eka Moxe: Loko u vuyela eEgipta, vona leswaku u endla mahlweni ka Faro hinkwaswo swihlamariso leswi ndzi nga swi veka evokweni ra wena; kambe ndzi ta tiyisa mbilu ya yena, a nga ka a nga va pfumeleli vanhu ku famba.' },
    { n: 22, text: 'U ta vula eka Faro: \u2018Yehovha u ku: Israyele i n\u2019wana wa mina, mativula ya mina.\u2019' },
    { n: 23, text: 'Ndzi ku eka wena: \u2018Pfumelela n\u2019wana wa mina a famba leswaku a ndzi gandzela\u2019; kambe loko u ala ku n\u2019wi pfumelela ku famba, vona, ndzi ta dlaya n\u2019wana wa wena, mativula ya wena.' },
    { n: 24, text: 'Kutani endleleni, endhawini ya vuyiselo, Yehovha a hlangana na yena, a lava ku n\u2019wi dlaya.' },
    { n: 25, text: 'Tsipora a teka ribye ro tsema, a tsema nguvu ya vutomi ya n\u2019wana wa yena, a yi lahla emilengeni ya yena, a ku: Hakunene u nuna wa ngati eka mina.' },
    { n: 26, text: 'Hiloko Yehovha a n\u2019wi tshika. Hi nkarhi wolowo a ku: \u2018Nuna wa ngati\u2019, hikwalaho ka ku tsemiwa ka nguvu ya vutomi (nguvu ya ku gimbila).' },
    { n: 27, text: 'Yehovha a ku eka Aroni: Famba emananga u ya hlangana na Moxe. A famba, a hlangana na yena exitsungeni xa Xikwembu, a n\u2019wi ntswontswa.' },
    { n: 28, text: 'Moxe a hlamusela Aroni hinkwaswo marito ya Yehovha lawa a nga n\u2019wi rhuma ha wona, ni swikombiso hinkwaswo leswi a nga n\u2019wi lerisa swona.' },
    { n: 29, text: 'Moxe na Aroni va famba, va hlengeleta vakhalabye hinkvavo va vana va Israyele.' },
    { n: 30, text: 'Aroni a vulavula hinkwaswo marito lawa Yehovha a nga ma vula eka Moxe, a endla ni swikombiso mahlweni ka vanhu.' },
    { n: 31, text: 'Vanhu va pfumela; loko va twa leswaku Yehovha u endlerile vana va Israyele vuxaka, ni leswaku u vonile ku karhateka ka vona, va khinsama, va gandzela.' },
  ],
  5: [
    { n: 1, text: 'Endzhaku ka swilo leswi, Moxe na Aroni va nghena, va ku eka Faro: Yehovha, Xikwembu xa Israyele, u ku: \u2018Pfumelela vanhu va mina ku famba, leswaku va ndzi endlela nkhuvo emananga.\u2019' },
    { n: 2, text: 'Faro a ku: I mani Yehovha leswaku ndzi nga yingisela rito ra yena ku pfumelela Israyele ku famba ke? A ndzi n\u2019wi tivi Yehovha, naswona a ndzi nga n\u2019wi pfumeleli Israyele ku famba.' },
    { n: 3, text: 'Va ku: Xikwembu xa Vaheveru xi hlangane na hina; sweswi, hi kombela u hi pfumelela hi famba riendzo la masiku manharhu emananga, hi ya tlhavela Yehovha Xikwembu xa hina ntsengo, leswaku a nga hi lwi hi ntungu kumbe hi banga.' },
    { n: 4, text: 'Hosi ya Egipta a ku eka vona: Moxe na Aroni, ha yini mi hlongola vanhu emintirhweni ya vona ke? Fambani emindzhwalweni ya n\u2019wina.' },
    { n: 5, text: 'Faro a tlhela a ku: Vonani, sweswi vanhu va tiko va tele, kutani n\u2019wina mi va wisisa emindzhwalweni ya vona.' },
    { n: 6, text: 'Hi siku rero Faro a lerisa valanguteri va vanhu ni varhangeri va vona, a ku:' },
    { n: 7, text: 'Mi nga ha tlheli mi nyika vanhu byanyi bya ku endla maritshana ku fana ni le mahlweni; a va tinyikele ku ya tihlengeletela byanyi hinkwako.' },
    { n: 8, text: 'Kambe ntsengo wa maritshana lawa va nga ma endla mahlweni, mi ta va vekela wona; mi nga ha hunguti nchumu; hikuva va loloha; hikwalaho va rilaka, va ku: \u2018Hi pfumelele ku famba hi ya tlhavela Xikwembu xa hina ntsengo.\u2019' },
    { n: 9, text: 'Vutirheli a bu tike ehenhla ka vavanuna lava, leswaku va endla byona, va nga yingiseli marito ya ku hemba.' },
    { n: 10, text: 'Valanguteri va vanhu ni varhangeri va vona va huma, va ku eka vanhu: Faro u ku: \u2018A ndzi mi nyiki byanyi.\u2019' },
    { n: 11, text: 'Fambani n\u2019wina, mi ya ti-kela byanyi lomu mi nga ta bu kuma kona; hikuva vutirheli bya n\u2019wina a byi hungutiwi na hansi.' },
    { n: 12, text: 'Hiloko vanhu va hangalaka etikweni hinkwaro ra Egipta ku ya hlengeleta swikon\u2019wana swa masimu matshan\u2019wini ya byanyi.' },
    { n: 13, text: 'Valanguteri a va va sindzisa, va ku: Hetisani vutirheli bya n\u2019wina, ntirho wa siku ni siku, ku fana ni nkarhi lowu a ku ri ni byanyi.' },
    { n: 14, text: 'Varhangeri va vana va Israyele, lava valanguteri va Faro va nga va veka ehenhla ka vona, va biwa, va vutisiwa va ku: Ha yini mi nga hetisanga ntsengo wa n\u2019wina wa maritshana tolo ni namuntlha ku fana ni le mahlweni ke?' },
    { n: 15, text: 'Varhangeri va vana va Israyele va fika va rila eka Faro, va ku: Ha yini u endla tano eka malandza ya wena ke?' },
    { n: 16, text: 'A ku na byanyi lebyi nyikiwaka malandza ya wena, kambe va ku eka hina: \u2018Endlani maritshana.\u2019 Kutani vona, malandza ya wena ma biwa; kambe nandzu i wa vanhu va wena.' },
    { n: 17, text: 'Yena a ku: Mi loloha swinene, mi loloha! Hikwalaho mi vulaka, mi ku: \u2018Hi pfumelele ku famba hi ya tlhavela Yehovha ntsengo.\u2019' },
    { n: 18, text: 'Tani sweswi fambani, mi ya tirha; hikuva a mi nga nyikiwi byanyi, kambe mi ta tisa ntsengo lowu faneleke wa maritshana.' },
    { n: 19, text: 'Varhangeri va vana va Israyele va vona leswaku va le khombyeni, loko va ku eka vona: \u2018Mi nga ha hunguti nchumu eka maritshana ya n\u2019wina ya siku ni siku.\u2019' },
    { n: 20, text: 'Va hlangana na Moxe na Aroni lava a va yimile va va rindzerile loko va huma eka Faro;' },
    { n: 21, text: 'va ku eka vona: Yehovha a a mi langute, a mi avanyisa; hikuva mi endle leswaku hi nyenyiwa emantweni ya Faro ni le mantweni ya malandza ya yena, mi veka banga emavokweni ya vona ku hi dlaya.' },
    { n: 22, text: 'Moxe a vuyela eka Yehovha, a ku: N\u2019wini wa mina, ha yini u karhateke vanhu lava ke? Ha yini u ndzi rhumile ke?' },
    { n: 23, text: 'Hikuva kusukela loko ndzi nghenile eka Faro ku vulavula hi vito ra wena, u karhateke vanhu lava swinene, naswona a u va ponisanga vanhu va wena.' },
  ],
  6: [
    { n: 1, text: 'Yehovha a ku eka Moxe: Sweswi u ta vona leswi ndzi nga ta swi endla eka Faro; hikuva hi voko ra matimba u ta va pfumelela ku famba, naswona hi voko ra matimba u ta va hlongola etikweni ra yena.' },
    { n: 2, text: 'Xikwembu xi vulavula na Moxe, xi ku eka yena: Ndzi Yehovha.' },
    { n: 3, text: 'Ndzi humelele Abrahama, Isaka, ni Akobo tanihi Xikwembu xa Matimba Hinkwako; kambe hi vito ra mina Yehovha a ndzi nga tivikananga eka vona.' },
    { n: 4, text: 'Ndzi tlhele ndzi veka xihambalo xa mina na vona, ku va nyika tiko ra Kanana, tiko ra ku rhendzeleka ka vona lomu va nga luva kona.' },
    { n: 5, text: 'Ndzi twile ni ku rila ka vana va Israyele, lava Vaegipta va va endlaka mahlonga, naswona ndzi tsundzukile xihambalo xa mina.' },
    { n: 6, text: 'Hikwalaho ku eka vana va Israyele: \u2018Ndzi Yehovha; ndzi ta mi humesa ehansi ka mindzhwalo ya Vaegipta, ndzi mi ponisa evuhlongeni bya vona, ndzi mi kutsula hi voko leri navisiweke ni hi ku avanyisa lokukulu.\u2019' },
    { n: 7, text: 'Ndzi ta mi teka mi va vanhu va mina, ndzi va Xikwembu xa n\u2019wina; kutani mi ta tiva leswaku ndzi Yehovha Xikwembu xa n\u2019wina, loyi a mi humesaka ehansi ka mindzhwalo ya Vaegipta.' },
    { n: 8, text: 'Ndzi ta mi nghenisa etikweni leri ndzi nga tlakusa voko ra mina ku ri nyika Abrahama, Isaka, ni Akobo; ndzi ta mi nyika rona ri va tshomba ra n\u2019wina; ndzi Yehovha.' },
    { n: 9, text: 'Moxe a hlamusela vana va Israyele tano; kambe a va yingiselanga Moxe hikwalaho ka ku karhateka ka mimoya ya vona ni hikwalaho ka vutirheli byo tika.' },
    { n: 10, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 11, text: 'Nghena, u ya vulavula na Faro hosi ya Egipta, leswaku a pfumelela vana va Israyele ku huma etikweni ra yena.' },
    { n: 12, text: 'Moxe a vulavula mahlweni ka Yehovha, a ku: Vonani, vana va Israyele a va ndzi yingiselanga; kutani Faro a nga ndzi yingisela njhani, kasi ndzi na milomu leyi nga tsemiwangiki (leyi tikaka) ke?' },
    { n: 13, text: 'Yehovha a vulavula na Moxe ni ka Aroni, a va nyika xileriso eka vana va Israyele ni le ka Faro hosi ya Egipta, ku humesa vana va Israyele etikweni ra Egipta.' },
    { n: 14, text: 'Lawa i tinhloko ta tindyandlu ta vatatana va vona: Vana va Rubeni mativula ya Israyele: Hanoki, na Palu, Hezroni, na Karmi; lawa i mindyangu ya Rubeni.' },
    { n: 15, text: 'Vana va Simiyoni: Yemuwele, na Yamini, na Ohade, na Yakini, na Tsohari, na Xawulo n\u2019wana wa wansati wa Mukanana; lawa i mindyangu ya Simiyoni.' },
    { n: 16, text: 'Lawa i mavito ya vana va Levi hi ku landza ku tswariwa ka vona: Gerixoni, na Kohati, na Merari; naswona malembe ya vutomi bya Levi ma ve dzenge ra malembe ya mune-khume ni makume-nharhu na nkombo (137).' },
    { n: 17, text: 'Vana va Gerixoni: Libni, na Ximeyi, hi mindyangu va vona.' },
    { n: 18, text: 'Vana va Kohati: Amrami, na Izahare, na Hebroni, na Uziyele; naswona malembe ya vutomi bya Kohati ma ve dzenge ra malembe ya mune-khume ni makume-nharhu na nharhu (133).' },
    { n: 19, text: 'Vana va Merari: Maheli, na Muxi; lawa i mindyangu ya Levi hi ku landza ku tswariwa ka vona.' },
    { n: 20, text: 'Amrami a teka Yokebede hahani wa yena ku va nsati wa yena; a n\u2019wi tswaleri Aroni na Moxe; naswona malembe ya vutomi bya Amrami ma ve dzenge ra malembe ya mune-khume ni makume-nharhu na nkombo (137).' },
    { n: 21, text: 'Vana va Izahare: Kora, na Nefegi, na Zikri.' },
    { n: 22, text: 'Vana va Uziyele: Mixayele, na Elizafani, na Sitri.' },
    { n: 23, text: 'Aroni a teka Elixeba, n\u2019wana wa nhwanyana wa Aminadabu, makwerhu wa Naxoni, ku va nsati wa yena; a n\u2019wi tswaleri Nadabu, na Abihu, na Eliyazari, na Itamari.' },
    { n: 24, text: 'Vana va Kora: Asiri, na Elkana, na Abiyasafa; lawa i mindyangu ya Kora.' },
    { n: 25, text: 'Eliyazari n\u2019wana wa Aroni a teka un\u2019wana wa vana va nhwanyana va Putiyeli ku va nsati wa yena; a n\u2019wi tswaleri Finehasi. Tinhloko ta vatatana va Valevi hi mindyangu ya vona hi teto.' },
    { n: 26, text: 'Hi vona vana lava va Aroni na Moxe, lava Yehovha a nga ku eka vona: \u2018Humesani vana va Israyele etikweni ra Egipta hi ku landza mavandla ya vona.\u2019' },
    { n: 27, text: 'Hi vona lava nga vulavula na Faro hosi ya Egipta, ku humesa vana va Israyele eEgipta; hi vona Moxe na Aroni lava.' },
    { n: 28, text: 'Kutani hi siku leri Yehovha a nga vulavula na Moxe etikweni ra Egipta,' },
    { n: 29, text: 'Yehovha a ku eka Moxe: Ndzi Yehovha; vulavula na Faro hosi ya Egipta hinkwaswo leswi ndzi ku byelaka swona.' },
    { n: 30, text: 'Kambe Moxe a ku mahlweni ka Yehovha: Vonani, ndzi na milomu leyi tikaka; kutani Faro a nga ndzi yingisela njhani ke?' },
  ],
  7: [
    { n: 1, text: 'Yehovha a ku eka Moxe: Vona, ndzi ku endlile Xikwembu eka Faro; kutani Aroni makwerhu wa wena u ta va muprofeta wa wena.' },
    { n: 2, text: 'Wena u ta vula hinkwaswo leswi ndzi nga ta ku lerisa swona; kutani Aroni makwerhu wa wena u ta vulavula na Faro, leswaku a pfumelela vana va Israyele ku huma etikweni ra yena.' },
    { n: 3, text: 'Kambe ndzi ta tiyisa mbilu ya Faro, ndzi andzisa swikombiso swa mina ni swihlamariso swa mina etikweni ra Egipta.' },
    { n: 4, text: 'Faro a nga ka a nga mi yingiseli; kutani ndzi ta veka voko ra mina ehenhla ka Egipta, ndzi humesa mavandla ya mina, vanhu va mina, vana va Israyele, etikweni ra Egipta hi ku avanyisa lokukulu.' },
    { n: 5, text: 'Vaegipta va ta tiva leswaku ndzi Yehovha, loko ndzi navisa voko ra mina ehenhla ka Egipta, ndzi humesa vana va Israyele exikarhi ka vona.' },
    { n: 6, text: 'Moxe na Aroni va endla tano; hilaha Yehovha a nga va lerisa hakona, va endla tano pfee.' },
    { n: 7, text: 'Moxe a a ri ni makume-nhalo (80) wa malembe, naswona Aroni a a ri ni makume-nhalo na nharhu (83) wa malembe loko va vulavula na Faro.' },
    { n: 8, text: 'Yehovha a vulavula na Moxe ni ka Aroni, a ku:' },
    { n: 9, text: 'Loko Faro a vulavula na n\u2019wina, a ku: \u2018Endlani xihlamariso\u2019; u ta ku eka Aroni: \u2018Teka nhonga ya wena, yi lahle mahlweni ka Faro\u2019, kutani yi ta hundzuka nyoka leyikulu.' },
    { n: 10, text: 'Moxe na Aroni va nghena eka Faro, va endla hilaha Yehovha a nga va lerisa hakona; Aroni a lahla nhonga ya yena mahlweni ka Faro ni mahlweni ka malandza ya yena, hiloko yi hundzuka nyoka leyikulu.' },
    { n: 11, text: 'Kambe Faro a vitana tintlhari ni valoyi; kutani na vona, vaaki va vutlhari va Egipta, va endla tano hi vutlhari bya vona bya xihundla.' },
    { n: 12, text: 'Hikuva un\u2019wana ni un\u2019wana a lahla nhonga ya yena, hiloko ti hundzuka tinyoka; kambe nhonga ya Aroni yi mita tinhonga va vona.' },
    { n: 13, text: 'Mbilu ya Faro yi tiya, a nga va yingiselanga, hilaha Yehovha a nga vula hakona.' },
    { n: 14, text: 'Yehovha a ku eka Moxe: Mbilu ya Faro yi tikile, wa ala ku pfumelela vanhu ku famba.' },
    { n: 15, text: 'Yana eka Faro ntshengula; vona, wa huma a ya ematini; u n\u2019wi rindzela eribuweni ra nambu; nhonga leyi nga hundzuka nyoka u yi teka evokweni ra wena.' },
    { n: 16, text: 'U ta ku eka yena: \u2018Yehovha, Xikwembu xa Vaheveru, u ndzi rhumile eka wena, a ku: Pfumelela vanhu va mina ku famba leswaku va ndzi gandzela emananga; kambe vona, ku fikela sweswi a u yingiselanga.\u2019' },
    { n: 17, text: 'Yehovha u ku: \u2018Hi leswi u nga ta tiva leswaku ndzi Yehovha: Vona, ndzi ta ba mati ya nambu hi nhonga leyi nga evokweni ra mina, kutani ya ta hundzuka ngati.\u2019' },
    { n: 18, text: 'Tinhlampfi leti nga enambini ti ta fa, nambu wu ta nuha, kutani Vaegipta va ta karhateka ku nwa mati ya nambu.' },
    { n: 19, text: 'Yehovha a ku eka Moxe: Ku eka Aroni: \u2018Teka nhonga ya wena, u navisa voko ra wena ehenhla ka mati ya Egipta, ehenhla ka milambu ya vona, ehenhla ka migero ya vona, ehenhla ka madziva ya vona, ni le henhla ka hinkwako ku hlengeletana ka mati ya vona, leswaku ma hundzuka ngati; ku ta va ni ngati etikweni hinkwaro ra Egipta, hambi swi ri swibya swa timhandze hambi swi ri swibya swa maribye.\u2019' },
    { n: 20, text: 'Moxe na Aroni va endla hilaha Yehovha a nga va lerisa hakona; a tlakusa nhonga, a ba mati ya nambu mahlweni ka Faro ni mahlweni ka malandza ya yena; kutani mati hinkwaso ya nambu ya hundzuka ngati.' },
    { n: 21, text: 'Tinhlampfi leti a ti ri enambini ti fa, nambu wu nuha, kutani Vaegipta a va nga ha koti ku nwa mati ya nambu; ku va ni ngati etikweni hinkwaro ra Egipta.' },
    { n: 22, text: 'Valoyi va Egipta va endla tano hi vutlhari bya vona; mbilu ya Faro yi tiya, a nga va yingiselanga, hilaha Yehovha a nga vula hakona.' },
    { n: 23, text: 'Faro a hundzuka, a nghena endlwini ya yena, a nga vekanga na mbilu ya yena emhakeni leyi.' },
    { n: 24, text: 'Vaegipta hinkvavo va kela kusuhi ni nambu ku lava mati yo nwa, hikuva a va nga koti ku nwa mati ya nambu.' },
    { n: 25, text: 'Ku hela masiku ya nkombo endzhaku ka loko Yehovha a nga ba nambu.' },
  ],
  8: [
    { n: 1, text: 'Yehovha a ku eka Moxe: Nghena eka Faro, u ku eka yena: Yehovha u ku: \u2018Pfumelela vanhu va mina ku famba leswaku va ndzi gandzela.\u2019' },
    { n: 2, text: 'Loko u ala ku va pfumelela ku famba, vona, ndzi ta ba hinkwaro tiko ra wena hi tinhlafi (matshelevhete).' },
    { n: 3, text: 'Nambu wu ta tala hi tinhlafi, ti ta huma, ti nghena endlwini ya wena, emalawini ya wena, ehenhla ka mbedli ya wena, ni le tindlwini va malandza ya wena, ni le ka vanhu va wena, ni le ka mitshengula ya wena, ni le ka swibya swa wena swo paka.' },
    { n: 4, text: 'Tinhlafi ti ta tlakukela ehenhla ka wena, ni le henhla ka vanhu va wena, ni le henhla ka malandza ya wena hinkwaso.' },
    { n: 5, text: 'Yehovha a ku eka Moxe: Ku eka Aroni: \u2018Navisa voko ra wena hi nhonga ya wena ehenhla ka milambu, ehenhla ka migero, ni le henhla ka madziva, u tlhandlasa tinhlafi ehenhla ka tiko ra Egipta.\u2019' },
    { n: 6, text: 'Aroni a navisa voko ra yena ehenhla ka mati ya Egipta, kutani tinhlafi ti tlhandluka, ti funengeta tiko ra Egipta.' },
    { n: 7, text: 'Valoyi va endla tano hi vutlhari bya vona, va tlhandlasa tinhlafi ehenhla ka tiko ra Egipta.' },
    { n: 8, text: 'Faro a vitana Moxe na Aroni, a ku: Khongelani eka Yehovha leswaku a susa tinhlafi eka mina ni le ka vanhu va mina; kutani ndzi ta pfumelela vanhu ku famba ku ya tlhavela Yehovha ntsengo.' },
    { n: 9, text: 'Moxe a ku eka Faro: Ndzi nyike lunghelo ro ku byela: Ndzi ta ku khongelela rini, wena ni malandza ya wena, ni vanhu va wena, ku dlayisa tinhlafi eka wena ni le tindlwini va wena, leswaku ti sala enambini ntsena ke?' },
    { n: 10, text: 'Yena a ku: Mundzuku. Moxe a ku: Swi ta endleka hilaha u vuleke hakona, leswaku u tiva leswaku a ku na un\u2019wana la fanaka na Yehovha Xikwembu xa hina.' },
    { n: 11, text: 'Tinhlafi ti ta suka eka wena, ni le tindlwini va wena, ni le ka malandza ya wena, ni le ka vanhu va wena; ti ta sala enambini ntsena.' },
    { n: 12, text: 'Moxe na Aroni va huma mahlweni ka Faro; Moxe a rila eka Yehovha hikwalaho ka tinhlafi leti a nga ti tisa eka Faro.' },
    { n: 13, text: 'Yehovha a endla hilaha rito ra Moxe ri nga kombela hakona; tinhlafi ti fa etindlwini, ematshangeni, ni le masin\u2019wini.' },
    { n: 14, text: 'Va ti hlengeleta hi tinhuntsu to tala swinene; kutani tiko ri nuha.' },
    { n: 15, text: 'Loko Faro a vona leswaku ku vile ni ku wisa, a titimisa mbilu ya yena, a nga va yingiselanga, hilaha Yehovha a nga vula hakona.' },
    { n: 16, text: 'Yehovha a ku eka Moxe: Ku eka Aroni: \u2018Navisa nhonga ya wena, u ba ritshuri ra misava, leswaku ri hundzuka tinhwala etikweni hinkwaro ra Egipta.\u2019' },
    { n: 17, text: 'Va endla tano; Aroni a navisa voko ra yena hi nhonga ya yena, a ba ritshuri ra misava, hiloko ku va ni tinhwala ehenhla ka vanhu ni le henhla ka swifuwo; ritshuri hinkwaro ra misava ri hundzuka tinhwala etikweni hinkwaro ra Egipta.' },
    { n: 18, text: 'Valoyi va ringeta hi vutlhari bya vona ku humesa tinhwala, kambe va tsandzeka; kutani ku va ni tinhwala ehenhla ka vanhu ni le henhla ka swifuwo.' },
    { n: 19, text: 'Valoyi va ku eka Faro: Leri i tiko ra Xikwembu! Kambe mbilu ya Faro yi tiya, a nga va yingiselanga, hilaha Yehovha a nga vula hakona.' },
    { n: 20, text: 'Yehovha a ku eka Moxe: Pfuka ntshengula swinene, u yima mahlweni ka Faro, loko a huma a ya ematini, u ku eka yena: Yehovha u ku: \u2018Pfumelela vanhu va mina ku famba leswaku va ndzi gandzela.\u2019' },
    { n: 21, text: 'Hikuva loko u nga pfumeleli vanhu va mina ku famba, vona, ndzi ta rhuma mathlandzi ya tibon\u2019wa ehenhla ka wena, ni le henhla ka malandza ya wena, ni le henhla ka vanhu va wena, ni le tindlwini va wena; tindyangu va Vaegipta ti ta tala hi mathlandzi, ni misava leyi va tshamaka ehenhla ka yona.' },
    { n: 22, text: 'Kambe hi siku rero ndzi ta hlawula tiko ra Goxeni, lomu vanhu va mina va tshamaka kona, leswaku ku nga vi ni mathlandzi ya tibon\u2019wa kona; leswaku u tiva leswaku ndzi Yehovha exikarhi ka misava.' },
    { n: 23, text: 'Ndzi ta veka ku hambana exikarhi ka vanhu va mina ni vanhu va wena; mundzuku xikombiso lexi xi ta endleka.' },
    { n: 24, text: 'Yehovha a endla tano; ku nghena mathlandzi yo tala lawa ya vavisaka swinene endlwini ya Faro, ni le tindlwini va malandza ya yena, ni le tikweni hinkwaro ra Egipta; tiko ri onhiwa hi mathlandzi.' },
    { n: 25, text: 'Faro a vitana Moxe na Aroni, a ku: Fambani mi ya tlhavela Xikwembu xa n\u2019wina ntsengo etikweni leri.' },
    { n: 26, text: 'Moxe a ku: A swi sasekanga ku endla tano; hikuva leswi hi nga ta swi tlhavela Yehovha Xikwembu xa hina i swilo swo nyenyetsa eka Vaegipta; xana loko hi tlhavela swilo swo nyenyetsa mahlweni ka Vaegipta, a va nga hi gandi hi maribye ke?' },
    { n: 27, text: 'Hi ta famba riendzo la masiku manharhu emananga, hi ya tlhavela Yehovha Xikwembu xa hina ntsengo, hilaha a nga ta hi lerisa hakona.' },
    { n: 28, text: 'Faro a ku: Ndzi ta mi pfumelela ku famba, mi ya tlhavela Yehovha Xikwembu xa n\u2019wina ntsengo emananga; ntsena mi nga fambi kule swinene. Ndzi khongeleleni.' },
    { n: 29, text: 'Moxe a ku: Vona, ndzi huma mahlweni ka wena, ndzi ta khongela eka Yehovha leswaku mathlandzi ya suka eka Faro, ni le ka malandza ya yena, ni le ka vanhu va yena mundzuku; ntsena Faro a nga ha hembeli vanhu ku ala ku va pfumelela ku famba ku ya tlhavela Yehovha ntsengo.' },
    { n: 30, text: 'Moxe a huma mahlweni ka Faro, a ya khongela eka Yehovha.' },
    { n: 31, text: 'Yehovha a endla hilaha rito ra Moxe ri nga kombela hakona; a susa mathlandzi eka Faro, ni le ka malandza ya yena, ni le ka vanhu va yena; a ku salanga na rin\u2019we.' },
    { n: 32, text: 'Kambe Faro a titimisa mbilu ya yena ni le ka nkarhi lowu, a nga va pfumelelanga vanhu ku famba.' },
  ],
  9: [
    { n: 1, text: 'Yehovha a ku eka Moxe: Nghena eka Faro, u ku eka yena: Yehovha, Xikwembu xa Vaheveru, u ku: \u2018Pfumelela vanhu va mina ku famba leswaku va ndzi gandzela.\u2019' },
    { n: 2, text: 'Hikuva loko u ala ku va pfumelela ku famba, u ha va khomile,' },
    { n: 3, text: 'vona, voko ra Yehovha ri ta va ehenhla ka swifuwo va wena leswi nga emasin\u2019wini, ehenhla ka tihanci, ehenhla ka timbanga, ehenhla ka tikamela, ehenhla ka tihomu, ni le henhla ka tinyimpfu: ku ta va ni ntungu lowukulu swinene.' },
    { n: 4, text: 'Yehovha u ta hambanisa exikarhi ka swifuwo va Israyele ni swifuwo va Egipta; kutani a ku nga fi na nchumu eka hinkwaswo swa vana va Israyele.' },
    { n: 5, text: 'Yehovha a veka nkarhi, a ku: Mundzuku Yehovha u ta endla nchumu lowu etikweni.' },
    { n: 6, text: 'Yehovha a endla nchumu lowu hi siku leri landzelaka; swifuwo hinkwaso va Vaegipta swi fa, kambe eka swifuwo va vana va Israyele a ku fanga na xin\u2019we.' },
    { n: 7, text: 'Faro a rhuma vanhu ku ya vona, kutani vonani, a ku fanga na xifuwo na xin\u2019we xa vana va Israyele. Kambe mbilu ya Faro a yi tiyile, a nga va pfumelelanga vanhu ku famba.' },
    { n: 8, text: 'Yehovha a ku eka Moxe ni ka Aroni: Tekani mavoko ya n\u2019wina ya tele hi nkuma wa lapi, kutani Moxe a a wu lahlele ehenhla emilengeni ya Faro.' },
    { n: 9, text: 'Wu ta hundzuka ritshuri leri nene etikweni hinkwaro ra Egipta, wu ta va swirhumbana leswi pfukaka timbanga ehenhla ka vanhu ni le henhla ka swifuwo, etikweni hinkwaro ra Egipta.' },
    { n: 10, text: 'Va teka nkuma wa lapi, va yima mahlweni ka Faro; Moxe a wu lahlela ehenhla, hiloko wu hundzuka swirhumbana leswi pfukaka timbanga ehenhla ka vanhu ni le henhla ka swifuwo.' },
    { n: 11, text: 'Valoyi a va nga koti ku yima mahlweni ka Moxe hikwalaho ka swirhumbana; hikuva swirhumbana a swi ri ehenhla ka valoyi ni le henhla ka Vaegipta hinkvavo.' },
    { n: 12, text: 'Kambe Yehovha a tiyisa mbilu ya Faro, a nga va yingiselanga, hilaha Yehovha a nga vula hakona eka Moxe.' },
    { n: 13, text: 'Yehovha a ku eka Moxe: Pfuka ntshengula swinene, u yima mahlweni ka Faro, u ku eka yena: Yehovha, Xikwembu xa Vaheveru, u ku: \u2018Pfumelela vanhu va mina ku famba leswaku va ndzi gandzela.\u2019' },
    { n: 14, text: 'Hikuva nkarhi lowu ndzi ta rhuma hinkwato timbanga va mina ehenhla ka mbilu ya wena, ni le henhla ka malandza ya wena, ni le henhla ka vanhu va wena, leswaku u tiva leswaku a ku na loyi a fanaka na mina emisaveni hinkwayo.' },
    { n: 15, text: 'Hikuva sweswi ndzi nga va ndzi navisile voko ra mina ndzi ku ba, wena ni vanhu va wena hi ntungu, kutani u nga va u dlayiwile emisaveni;' },
    { n: 16, text: 'kambe hikwalaho ka leswi ndzi ku yimisaka: leswaku ndzi ku komba matimba va mina, ni leswaku vito ra mina ri tivisiwa emisaveni hinkwayo.' },
    { n: 17, text: 'Xana u ha tikurisa ehenhla ka vanhu va mina, u ala ku va pfumelela ku famba ke?' },
    { n: 18, text: 'Vona, mundzuku hi nkarhi lowu ndzi ta nisa xihangu lexikulu swinene, lexi nga vangiki kona eEgipta kusukela siku leri ri nga tsemiwa ha rona ku fikela sweswi.' },
    { n: 19, text: 'Tani sweswi rhuma vanhu ku ya hlengeleta swifuwo va wena ni hinkwaswo leswi u nga na swona emasin\u2019wini; un\u2019wana ni un\u2019wana loyi a nga ta kumiwa emasin\u2019wini a nga hlengeletiwanga endlwini, xihangu xi ta rhelela ehenhla ka yena, kutani u ta fa.' },
    { n: 20, text: 'Loyi a nga chava rito ra Yehovha exikarhi ka malandza ya Faro a tisa malandza ya yena ni swifuwo va yena etindlwini;' },
    { n: 21, text: 'kambe loyi a nga vekangiki mbilu ya yena erito ra Yehovha a tshika malandza ya yena ni swifuwo va yena emasin\u2019wini.' },
    { n: 22, text: 'Yehovha a ku eka Moxe: Navisa voko ra wena ehenhla, leswaku ku va ni xihangu etikweni hinkwaro ra Egipta, ehenhla ka vanhu, ehenhla ka swifuwo, ni le henhla ka hinkwabyo byanyi bya masimu, etikweni ra Egipta.' },
    { n: 23, text: 'Moxe a navisela nhonga ya yena ehenhla; Yehovha a nisa rimpfumo ni xihangu, ndzilo wu tsutsumela hansi emisaveni; Yehovha a nisa xihangu ehenhla ka tiko ra Egipta.' },
    { n: 24, text: 'Kutani ku va ni xihangu, ni ndzilo lowu pfurhaka exikarhi ka xihangu, lowukulu swinene, lowu nga vangiki kona etikweni hinkwaro ra Egipta kusukela loko ri vile tiko.' },
    { n: 25, text: 'Xihangu xi ba etikweni hinkwaro ra Egipta hinkwaswo leswi a swi ri emasin\u2019wini, hambi ku ri vanhu hambi ku ri swifuwo; xi ba ni hinkwabyo byanyi va masimu, xi tshovelela ni hinkwato timhandze va masimu.' },
    { n: 26, text: 'Ntsena etikweni ra Goxeni, lomu vana va Israyele a va ri kona, a ku na xihangu.' },
    { n: 27, text: 'Faro a vitana Moxe na Aroni, a ku eka vona: Ndzi dyohile emhakeni leyi; Yehovha i lulami, kasi mina ni vanhu va mina hi vadyohi.' },
    { n: 28, text: 'Khongelani eka Yehovha, hikuva ku fikile swirilo swa Xikwembu ni xihangu; ndzi ta mi pfumelela ku famba, a mi nga ha tshami.' },
    { n: 29, text: 'Moxe a ku eka yena: Loko ndzi humile emutini, ndzi ta navisa mavoko ya mina eka Yehovha; rimpfumo ri ta hela, ni xihangu a xi nga ha vi kona, leswaku u tiva leswaku misava i ya Yehovha.' },
    { n: 30, text: 'Kambe loko ku ri wena ni malandza ya wena, ndzi tiva leswaku a mi si chava Yehovha Xikwembu.' },
    { n: 31, text: 'Lapi ni maxalana swi onhiwa; hikuva maxalana a ya ri ni swihluke, kutani lapi a ri pfurha.' },
    { n: 32, text: 'Kambe mavele ni trigo a swi onhiwanga, hikuva swi hlwela ku mila.' },
    { n: 33, text: 'Moxe a huma mahlweni ka Faro, a ya ehandle ka muti, a navisa mavoko ya yena eka Yehovha; rimpfumo ni xihangu swi hela, ni mpfula a yi nga ha chulukeli emisaveni.' },
    { n: 34, text: 'Loko Faro a vona leswaku mpfula ni xihangu ni rimpfumo swi herile, a tlhela a dyoha, a tiyisa mbilu ya yena, yena ni malandza ya yena.' },
    { n: 35, text: 'Mbilu ya Faro yi tiya, a nga va pfumelelanga vana va Israyele ku famba, hilaha Yehovha a nga vula hakona hi nomu wa Moxe.' },
  ],
  10: [
    { n: 1, text: 'Yehovha a ku eka Moxe: Nghena eka Faro; hikuva ndzi tiyisile mbilu ya yena ni timbilu va malandza ya yena, leswaku ndzi endla swikombiso va mina leswi exikarhi ka vona,' },
    { n: 2, text: 'ni leswaku u ta hlayisela tindleve va n\u2019wana wa wena, ni le ka vana va vana va wena, leswi ndzi nga swi endla eEgipta, ni swikombiso va mina leswi ndzi nga va komba swona, leswaku mi tiva leswaku ndzi Yehovha.' },
    { n: 3, text: 'Moxe na Aroni va nghena eka Faro, va ku eka yena: Yehovha, Xikwembu xa Vaheveru, u ku: \u2018Ku fikela rini u ala ku titsongahata mahlweni ka mina ke? Pfumelela vanhu va mina ku famba leswaku va ndzi gandzela.\u2019' },
    { n: 4, text: 'Hikuva loko u ala ku pfumelela vanhu va mina ku famba, vona, mundzuku ndzi ta tisa tinjiya endhawini ya wena.' },
    { n: 5, text: 'Ti ta funengeta xikandza xa misava, leswaku ku nga vi ni loyi a kotaka ku vona misava; ti ta dya hinkwaswo leswi saleke eka n\u2019wina leswi pongeke eka xihangu, ti ta dya ni hinkwato timhandze leti milaka emasin\u2019wini ya n\u2019wina.' },
    { n: 6, text: 'Ti ta tala etindlwini va wena, ni le tindlwini va malandza ya wena hinkwaso, ni le tindlwini va Vaegipta hinkvavo; nchumu lowu vatatana va wena ni vakokwana va wena va nga ku vonangiki kusukela siku leri va nga va kona emisaveni ku fikela namuntlha. A hundzuka, a huma mahlweni ka Faro.' },
    { n: 7, text: 'Malandza va Faro ya ku eka yena: Ku fikela rini wanuna loyi a nga ta va ntlhamu eka hina ke? Pfumelela vavanuna lava ku famba leswaku va ya gandzela Yehovha Xikwembu xa vona. Xana a u si tiva leswaku Egipta ri onhekile ke?' },
    { n: 8, text: 'Moxe na Aroni va vuyisela eka Faro; yena a ku eka vona: Fambani mi ya gandzela Yehovha Xikwembu xa n\u2019wina; kambe hi vamani lava nga ta famba ke?' },
    { n: 9, text: 'Moxe a ku: Hi ta famba ni vatsongo va hina ni vakhalabye va hina; hi ta famba ni vana va hina va majaha ni va vanhwanyana, ni tinyimpfu ta hina, ni tihomu ta hina, hikuva hi fanele ku endlela Yehovha nkhuvo.' },
    { n: 10, text: 'Yena a ku eka vona: Yehovha a a ve na n\u2019wina, loko ndzi mi pfumelela ku famba ni vana va n\u2019wina lava ntsongo! Vonani, ku ni vubihi mahlweni ka n\u2019wina.' },
    { n: 11, text: 'A swi nga vi tano! Fambani n\u2019wina vavanuna, mi ya gandzela Yehovha, hikuva hi leswi mi nga swi kombela. Kutani va hlongoriwa mahlweni ka Faro.' },
    { n: 12, text: 'Yehovha a ku eka Moxe: Navisa voko ra wena ehenhla ka tiko ra Egipta hikwalaho ka tinjiya, leswaku ti tlhandluka ehenhla ka tiko ra Egipta, ti dya hinkwabyo byanyi va masimu, hinkwaswo leswi pongeke eka xihangu.' },
    { n: 13, text: 'Moxe a navisa nhonga ya yena ehenhla ka tiko ra Egipta, kutani Yehovha a tisa mheho ya le vuxeni ehenhla ka tiko siku rero hinkwaro ni vusiku hinkwabyo; loko ku tsha, mheho ya le vuxeni yi tisa tinjiya.' },
    { n: 14, text: 'Tinjiya ti tlhandluka ehenhla ka tiko hinkwaro ra Egipta, ti tshama endhawini hinkwayo ra Egipta, ti tala swinene; mahlweni ka tona a ku nga vangiki ni tinjiya to fana na tona, naswona endzhaku ka tona a ku nga ha vi na tona.' },
    { n: 15, text: 'Hikuva ti funengeta xikandza hinkwaro ra misava, tiko ri hundzuka munyama; ti dya hinkwabyo byanyi va masimu, ni hinkwavo mhandze va timhandze leti xihangu xi nga ti tshika; a ku salanga na nchumu wa rihlaza etimhandzeni hambi ebyanyini bya masimu, etikweni hinkwaro ra Egipta.' },
    { n: 16, text: 'Faro a hatlisa ku vitana Moxe na Aroni, a ku: Ndzi dyohile eka Yehovha Xikwembu xa n\u2019wina ni le ka n\u2019wina.' },
    { n: 17, text: 'Tani sweswi, ndzi kombela u ndzi rivalela xidyoho xa mina ka xin\u2019we ntsena, mi khongela eka Yehovha Xikwembu xa n\u2019wina leswaku a susa rifu leri ntsena eka mina.' },
    { n: 18, text: 'A huma mahlweni ka Faro, a ya khongela eka Yehovha.' },
    { n: 19, text: 'Yehovha a hundzuluxa mheho, a tisa mheho ya matimba swinene ya le vuxikwini (mponya-mbyana), yi teka tinjiya, yi ti lahlela eLwandle ro Tshuka; a ku salanga na njiya na yin\u2019we endhawini hinkwayo ra Egipta.' },
    { n: 20, text: 'Kambe Yehovha a tiyisa mbilu ya Faro, a nga va pfumelelanga vana va Israyele ku famba.' },
    { n: 21, text: 'Yehovha a ku eka Moxe: Navisa voko ra wena ehenhla, leswaku ku va ni munyama ehenhla ka tiko ra Egipta, munyama lowu kotaka ku khomiwa.' },
    { n: 22, text: 'Moxe a navisa voko ra yena ehenhla; kutani ku va ni munyama lowukulu swinene etikweni hinkwaro ra Egipta masiku manharhu.' },
    { n: 23, text: 'A ku na loyi a nga vona un\u2019wana, naswona a ku na loyi a nga pfuka endhawini ya yena masiku manharhu; kambe eka vana va Israyele hinkvavo a ku ri ni ku vonakala etindlwini va vona.' },
    { n: 24, text: 'Faro a vitana Moxe, a ku: Fambani mi ya gandzela Yehovha; ntsena tinyimpfu ta n\u2019wina ni tihomu ta n\u2019wina ti ta sala; vana va n\u2019wina lava ntsongo na vona va nga famba na n\u2019wina.' },
    { n: 25, text: 'Moxe a ku: Wena u fanele ku hi nyika na ntsengo ni switlhabelo leswaku hi ya endlela Yehovha Xikwembu xa hina ntsengo.' },
    { n: 26, text: 'Swifuwo va hina na swona swi ta famba na hina, a ku nga sali na nenge na wun\u2019we; hikuva hi fanele ku teka swin\u2019wana eka swona ku ya gandzela Yehovha Xikwembu xa hina; hikuva a hi tivi leswi hi nga ta gandzela Yehovha ha kona ku fikela loko hi fika kona.' },
    { n: 27, text: 'Kambe Yehovha a tiyisa mbilu ya Faro, a nga rhandzanga ku va pfumelela ku famba.' },
    { n: 28, text: 'Faro a ku eka yena: Suka mahlweni ka mina! Tivonele, u nga ha tshuki u vona xikandza xa mina; hikuva hi siku leri u nga ta vona xikandza xa mina u ta fa.' },
    { n: 29, text: 'Moxe a ku: U vurile; a ndzi nga ha tlheli ndzi vona xikandza xa wena.' },
  ],
  11: [
    { n: 1, text: 'Yehovha a ku eka Moxe: Ndzi ta tlhela ndzi tisa khombo rin\u2019we ehenhla ka Faro ni le henhla ka Egipta; endzhaku ka sweswo u ta mi pfumelela ku huma laha; loko a mi pfumelela ku famba, kunene u ta mi hlongola hinkwenu ntsena.' },
    { n: 2, text: 'Vulavula sweswi etindleveni ta vanhu, leswaku wanuna un\u2019wana ni un\u2019wana a kombela eka muakelani wakwe, ni wansati un\u2019wana ni un\u2019wana eka muakelani wakwe, swibya swa silivhere ni swibya swa nsuku.' },
    { n: 3, text: 'Yehovha a endla leswaku vanhu va rhandzeka ematlhweni ka Vaegipta. Kunene, wanuna loyi Moxe a a ri nchumu lowukulu swinene etikweni ra Egipta, mahlweni ka malandza ya Faro ni mahlweni ka vanhu.' },
    { n: 4, text: 'Moxe a ku: Yehovha u ku: \u2018Exikarhi ka vusiku ndzi ta huma ndzi nghena exikarhi ka Egipta;\u2019' },
    { n: 5, text: '\u2018kutani mativula hinkwawo etikweni ra Egipta ma ta fa, kusukela eka mativula ya Faro loyi a tshamaka exiluvelweni xa yena, ku fikela eka mativula ya khamba ra xisati leri nga endzhaku ka xigayo, ni mativula hinkwawo ya swifuwo.\u2019' },
    { n: 6, text: '\u2018Ku ta va ni xirilo lexikulu etikweni hinkwaro ra Egipta, lexi nga vangiki kona khale, naswona xi nga ka xi nga ha vi kona.\u2019' },
    { n: 7, text: '\u2018Kambe eka vana va Israyele hinkwavo, hambi ku ri mbyana a yi nga ka yi nga va vukuli, hambi ku ri munhu hambi ku ri xifuwo, leswaku mi ta tiva leswaku Yehovha wa hambanisa exikarhi ka Egipta na Israyele.\u2019' },
    { n: 8, text: '\u2018Kutani malandza ya wena lawa hinkwawo ya ta rhelela eka mina, ya ndzi nkhinsamela, ya ku: \u201cHumani, wena ni vanhu hinkwavo lava ku landzelaka!\u201d Endzhaku ka sweswo ndzi ta huma.\u2019 Hiloko a huma mahlweni ka Faro a hlundzukile swinene.' },
    { n: 9, text: 'Yehovha a ku eka Moxe: Faro a nga ka a nga mi yingiseli, leswaku swihlamariso swa mina swi andziswa etikweni ra Egipta.' },
    { n: 10, text: 'Moxe na Aroni va endla swihlamariso leswi hinkwaswo mahlweni ka Faro; kambe Yehovha a tiyisa mbilu ya Faro, kutani a nga va pfumelelanga vana va Israyele ku huma etikweni ra yena.' },
  ],
  12: [
    { n: 1, text: 'Yehovha a vulavula na Moxe ni ka Aroni etikweni ra Egipta, a ku:' },
    { n: 2, text: 'N\u2019weti lowu wu ta va masungulo ya tin\u2019weti eka n\u2019wina; wu ta va n\u2019weti wo sungula wa lembe eka n\u2019wina.' },
    { n: 3, text: 'Vulavulani ni nhlengeletano hinkwayo ya Israyele, mi ku: Hi siku ra vukhume ra n\u2019weti lowu, un\u2019wana ni un\u2019wana a a titekele xinyimpfana hi ku ya hi tindyangu ta vatatana va vona, xinyimpfana xin\u2019we hi ndyangu.' },
    { n: 4, text: 'Kambe loko ndyangu wu ri wuntsongo eka xinyimpfana, yena ni muakelani wakwe la nga kusuhi ni yindlu yakwe va ta xi teka hi ku ya hi ntsengo wa mimoya; mi ta tsema ntsengo wa xinyimpfana hi ku ya hi leswi un\u2019wana ni un\u2019wana a swi dyaka.' },
    { n: 5, text: 'Xinyimpfana xa n\u2019wina xi fanele ku va lexi nga riki na vusoloki, xa ntswele xa lembe rin\u2019we; mi nga xi teka eka tinyimpfu kumbe eka timbuti.' },
    { n: 6, text: 'Mi ta xi hlayisa ku fikela hi siku ra vukhume-mune ra n\u2019weti lowu, kutani nhlengeletano hinkwayo ya vandla ra Israyele yi ta xi tlhabela ntsengo hi nkarhi wa madyambu.' },
    { n: 7, text: 'Va ta teka ngati ya xona, va yi faka etimhandzeni hinkwato timbirhi ta timbanti, ni le henhla ka mhandze ya le henhla ya timbanti, ya tindlu leti va nga ta xi dyela eka tona.' },
    { n: 8, text: 'Kutani va ta dya nyama ya xona hi vusiku byebyo; va ta yi dya yi oxiwile endzilweni, yi ri ni swinkwa leswi nga riki na comela, ni matsavu yo bava.' },
    { n: 9, text: 'Mi nga dyi nchumu lowu nga mbisi kumbe lowu nga tsembiwa hi mati, kambe wu oxiwile endzilweni; nhloko ya xona, ni milenge ya xona, ni swirho swa xona swa le ndzeni.' },
    { n: 10, text: 'Mi nga tshiki nchumu wa xona ku fikela nimixo; loko ku ri ni leswi salaka ku fikela nimixo, mi swi hisa hi ndzilo.' },
    { n: 11, text: 'Kutani mi ta xi dyisa leswi: mi bohile tihlunu ta n\u2019wina, mi rhandzele maphaxane ya n\u2019wina emilengeni ya n\u2019wina, ni tinhonga ta n\u2019wina tivokweni ta n\u2019wina; mi ta xi dya hi ku hatlisa; i Pasika ya Yehovha.' },
    { n: 12, text: 'Hikuva ndzi ta hundza hi le tikweni ra Egipta hi vusiku byebyo, ndzi ta ba mativula hinkwawo etikweni ra Egipta, kusukela eka vanhu ku fikela eka swifuwo; ndzi ta endla ku avanyisa eka swikwembu hinkwaswo swa Egipta. Ndzi Yehovha.' },
    { n: 13, text: 'Kutani ngati yi ta va xikombiso eka n\u2019wina ehenhla ka tindlu leti mi tshamaka eka tona; loko ndzi vona ngati, ndzi ta mi tlula, kutani ntungu a nga ka a nga mi dlayi loko ndzi ba tiko ra Egipta.' },
    { n: 14, text: 'Siku leri ri ta va xitsundzuxo eka n\u2019wina, naswona mi ta ri endlela nkhuvo eka Yehovha emixakabyini ya n\u2019wina hinkwayo; mi ta ri endlela nkhuvo hi nawu lowu nga heriki.' },
    { n: 15, text: 'Masiku ya nkombo mi ta dya swinkwa leswi nga riki na comela; kunene hi siku ro sungula mi ta susa comela etindlwini ta n\u2019wina; hikuva un\u2019wana ni un\u2019wana loyi a dyaka swinkwa leswi nga ni comela, kusukela hi siku ro sungula ku fikela hi siku ra nkombo, moya lowu u ta tsemiwa exikarhi ka Israyele.' },
    { n: 16, text: 'Hi siku ro sungula ku ta va ni nhlengeletano yo kwetsima, ni hi siku ra nkombo ku ta va ni nhlengeletano yo kwetsima eka n\u2019wina; a ku nga endliwi ntirho na wun\u2019we hi masiku wolawo, ntsena lowu fanelaka ku dyiwa hi un\u2019wana ni un\u2019wana, hi wona ntsena lowu nga endliwaka hi n\u2019wina.' },
    { n: 17, text: 'Mi ta hlayisa nkhuvo wa swinkwa leswi nga riki na comela, hikuva hi siku leri ntsena ndzi humeseke mavandla ya n\u2019wina etikweni ra Egipta; hikwalaho mi ta hlayisa siku leri emixakabyini ya n\u2019wina hi nawu lowu nga heriki.' },
    { n: 18, text: 'Hi n\u2019weti wo sungula, hi siku ra vukhume-mune ra n\u2019weti hi madyambu, mi ta dya swinkwa leswi nga riki na comela ku fikela hi siku ra vukhume-rin\u2019we ra n\u2019weti hi madyambu.' },
    { n: 19, text: 'Masiku ya nkombo ku nga tshuki ku kumiwa comela etindlwini ta n\u2019wina; hikuva un\u2019wana ni un\u2019wana loyi a dyaka nchumu lowu nga ni comela, moya wolowo wu ta tsemiwa enhlengeletanweni ya Israyele, hambi a ri muluveri hambi a tswariwe etikweni.' },
    { n: 20, text: 'Mi nga dyi nchumu lowu nga ni comela; etindhawini hinkwato leti mi tshamaka eka tona mi ta dya swinkwa leswi nga riki na comela.' },
    { n: 21, text: 'Moxe a vitana vakulukumba hinkvavo va Israyele, a ku eka vona: Fambani, mi titekele swinyimpfana hi ku ya hi tindyangu ta n\u2019wina, mi tlhabela Pasika.' },
    { n: 22, text: 'Mi ta teka ntsandza wa hisopa, mi wu peta engatini leyi nga exibyani, mi faka ehenhla ka mhandze ya le henhla ya munti ni le timhandzeni ta timbiri ta munti hi ngati leyi nga exibyani; un\u2019wana ni un\u2019wana wa n\u2019wina a nga tshuki a huma hi munti wa yindlu yakwe ku fikela nimixo.' },
    { n: 23, text: 'Hikuva Yehovha u ta hundza a ba Vaegipta; loko a vona ngati ehenhla ka mhandze ya le henhla ni le timhandzeni ta timbiri ta munti, Yehovha u ta tlula nyangwa, a nga pfumeleli mudlayi ku nghena etindlwini ta n\u2019wina ku mi ba.' },
    { n: 24, text: 'Mi ta hlayisa mhaka leyi tanihi nawu eka wena ni le ka vana va wena hilaha nga heriki.' },
    { n: 25, text: 'Kutani loko mi fika etikweni leri Yehovha a nga ta mi nyika rona, hilaha a nga vula hakona, mi ta hlayisa ntirho lowu.' },
    { n: 26, text: 'Loko vana va n\u2019wina va ku eka n\u2019wina: \u2018Xana ntirho lowu wu vula yini eka n\u2019wina ke?\u2019' },
    { n: 27, text: 'Mi ta ku: \u2018I ntsengo wa Pasika ya Yehovha, loyi a nga tlula tindlu ta vana va Israyele eEgipta, loko a ba Vaegipta, a ponisa tindlu ta hina.\u2019 Kutani vanhu va korhama, va nkhinsama.' },
    { n: 28, text: 'Vana va Israyele va famba, va endla tano; hilaha Yehovha a nga lerisa Moxe na Aroni hakona, va endla tano pfee.' },
    { n: 29, text: 'Kutani ku ri exikarhi ka vusiku, Yehovha a ba mativula hinkwawo etikweni ra Egipta, kusukela eka mativula ya Faro loyi a tshamaka exiluvelweni xa yena ku fikela eka mativula ya mukhotsi loyi a a ri endlwini ya khotso, ni mativula hinkwawo ya swifuwo.' },
    { n: 30, text: 'Faro a pfuka hi vusiku byebyo, yena ni malandza ya yena hinkwawo, ni Vaegipta hinkvavo; kutani ku va ni xirilo lexikulu eEgipta, hikuva a ku nga ri na yindlu leyi ku nga riki na loyi a feke eka yona.' },
    { n: 31, text: 'Hiloko a vitana Moxe na Aroni hi vusiku byebyo, a ku: Pfukani, humani exikarhi ka vanhu va mina, n\u2019wina ni vana va Israyele; fambani mi ya gandzela Yehovha, hilaha mi vuleke hakona.' },
    { n: 32, text: 'Tekani na tinyimpfu ta n\u2019wina ni tihomu ta n\u2019wina, hilaha mi vuleke hakona, mi famba; naswona mi ndzi katekisa na mina.' },
    { n: 33, text: 'Vaegipta va sindzisa vanhu ku hatlisa ku va humesa etikweni, hikuva va ku: Hi ta fa hinkwerhu.' },
    { n: 34, text: 'Vanhu va teka mfulo wa vona lowu nga si hunguka, ni swibya swa vona swo paka swi bohiwile hi tinguvu ta vona emakatleni ya vona.' },
    { n: 35, text: 'Vana va Israyele va endla hilaha rito ra Moxe ri nga vula hakona; va kombela eka Vaegipta swibya swa silivhere ni swibya swa nsuku, ni tinguvu.' },
    { n: 36, text: 'Yehovha a endla leswaku vanhu va rhandzeka mahlweni ka Vaegipta, hiloko va va nyika leswi va nga swi kombela. Kutani va phangha Vaegipta.' },
    { n: 37, text: 'Vana va Israyele va suka eRamesese va ya eSukoti, va lava ku va gidi ra makhume-tsevu (600,000) wa vavanuna lava fambaka hi milenge, handle ka vana.' },
    { n: 38, text: 'Kutani ntshungu lowukulu wa vanhu va tinxaka-xaka wu famba na vona, ni swifuwo, tinyimpfu ni tihomu to tala swinene.' },
    { n: 39, text: 'Va baka swinkwa leswi nga riki na comela hi mfulo lowu va nga wu humesa eEgipta, hikuva a wu nga ri na comela; hikuva va hlongoriwile eEgipta, a va nga koti ku hlwela, naswona a va nga tivonanga swakudya swa riendzo.' },
    { n: 40, text: 'Kutani ku tshama ka vana va Israyele, lava nga tshama eEgipta, ku vile malembe ya madzana ya mune na mune-khume (430).' },
    { n: 41, text: 'Kutsheleketa ku hela malembe ya madzana ya mune na mune-khume (430), hi siku rero ntsena, mavandla hinkwawo ya Yehovha ya huma etikweni ra Egipta.' },
    { n: 42, text: 'I vusiku byo hlayisiwa swinene eka Yehovha hikwalaho ko va humesa etikweni ra Egipta; vusiku byebyo i bya Yehovha, byo hlayisiwa hi vana va Israyele hinkvavo emixakabyini ya vona.' },
    { n: 43, text: 'Yehovha a ku eka Moxe na Aroni: Leri i nawu wa Pasika: Muyeni a nga tshuki a xi dya;' },
    { n: 44, text: 'kambe nandza un\u2019wana ni un\u2019wana loyi a xaviweke hi mali, loko u n\u2019wi tsemberile, u nga xi dya;' },
    { n: 45, text: 'muluveri kumbe nandza la xaviweke a nga ka a nga xi dyi.' },
    { n: 46, text: 'Xi ta dyeriwa endlwini yin\u2019we ntsena; u nga tshuki u humesa nyama ya xona ehandle ka yindlu; naswona mi nga tshuki mi tshova rhangula ra xona.' },
    { n: 47, text: 'Nhlengeletano hinkwayo ya Israyele yi ta hlayisa nkhuvo lowu.' },
    { n: 48, text: 'Loko muluveri a tshamile na wena, a lava ku hlayisela Yehovha Pasika, un\u2019wana ni un\u2019wana wa xinuna wa yena a a tsemberiwe, kutani a nga tshinela ku yi hlayisa; u ta va tanihi loyi a tswariweke etikweni; kambe munhu loyi a nga tsemberiwangiki a nga tshuki a yi dya.' },
    { n: 49, text: 'Nawu wu ta va wun\u2019we eka loyi a tswariweke etikweni ni le ka muluveri loyi a tshamaka exikarhi ka n\u2019wina.' },
    { n: 50, text: 'Vana va Israyele hinkvavo va endla tano; hilaha Yehovha a nga lerisa Moxe na Aroni hakona, va endla tano pfee.' },
    { n: 51, text: 'Kutsheleketa hi siku rero ntsena, Yehovha a humesa vana va Israyele etikweni ra Egipta hi mavandla ya vona.' },
  ],
  13: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: 'Ndzi kwetsimisele mativula hinkwawo, un\u2019wana ni un\u2019wana loyi a pfulaka mbeleko exikarhi ka vana va Israyele, hambi a ri munhu hambi a ri xifuwo; i swa mina.' },
    { n: 3, text: 'Moxe a ku eka vanhu: Tsundzukani siku leri, leri mi nga huma ha rona eEgipta, endlwini ya vuhlonga; hikuva Yehovha u mi humesile laha hi voko ra matimba; ku nga tshuki ku dyiwa nchumu lowu nga ni comela.' },
    { n: 4, text: 'Namuntlha, hi n\u2019weti wa Abibi, mi nga huma.' },
    { n: 5, text: 'Kutani loko Yehovha a ku nghenisile etikweni ra Vakanana, ni Vahiti, ni Vaamori, ni Vahivi, ni Vayebusi, leri a nga hlambanya eka vatatana va wena leswaku u ta ku nyika rona, tiko leri khulukaka ntswamba ni vulombe, u ta hlayisa ntirho lowu hi n\u2019weti lowu.' },
    { n: 6, text: 'Masiku ya nkombo u ta dya swinkwa leswi nga riki na comela, naswona hi siku ra nkombo ku ta va ni nkhuvo wa Yehovha.' },
    { n: 7, text: 'Swinkwa leswi nga riki na comela swi ta dyiwa hi masiku ya nkombo; ku nga tshuki ku voniwa swinkwa leswi nga ni comela eka wena, naswona ku nga tshuki ku voniwa comela eka wena endhawini hinkwayo ya wena.' },
    { n: 8, text: 'U ta byela n\u2019wana wa wena hi siku rero, u ku: \u2018Swi tano hikwalaho ka leswi Yehovha a nga ndzi endlela swona loko ndzi huma eEgipta.\u2019' },
    { n: 9, text: 'Kutani swi ta va xikombiso eka wena evokweni ra wena, ni xitsundzuxo exikarhi ka mahlo ya wena, leswaku nawu wa Yehovha wu va enon\u2019wini wa wena; hikuva Yehovha u ku humesile eEgipta hi voko ra matimba.' },
    { n: 10, text: 'Hikwalaho u ta hlayisa nawu lowu hi nkarhi wa wona, lembe ni lembe.' },
    { n: 11, text: 'Loko Yehovha a ku nghenisile etikweni ra Vakanana, hilaha a nga hlambanya hakona eka wena ni le ka vatatana va wena, a ku nyika rona,' },
    { n: 12, text: 'u ta nyikela eka Yehovha un\u2019wana ni un\u2019wana loyi a pfulaka mbeleko, ni mativula hinkwawo ya swifuwo leswi u nga na swona; swa xinuna swi ta va swa Yehovha.' },
    { n: 13, text: 'Kambe mativula hinkwawo ya mbongolo u ta ya kutsula hi xinyimpfana; loko u nga yi kutsuli, u ta yi tshova nhlana; naswona mativula hinkwawo ya vanhu exikarhi ka vana va wena u ta ya kutsula.' },
    { n: 14, text: 'Kutani loko n\u2019wana wa wena a ku vutisa mundzuku, a ku: \u2018Xana swi vula yini leswi ke?\u2019 U ta ku eka yena: \u2018Hi voko ra matimba Yehovha u hi humesile eEgipta, endlwini ya vuhlonga;\u2019' },
    { n: 15, text: '\u2018kutani loko Faro a tiyisile mbilu ya yena a ala ku hi pfumelela ku famba, Yehovha a dlayile mativula hinkwawo etikweni ra Egipta, kusukela eka mativula ya vanhu ku fikela eka mativula ya swifuwo; hikwalaho ndzi tlhavela Yehovha un\u2019wana ni un\u2019wana wa xinuna loyi a pfulaka mbeleko, kambe mativula hinkwawo ya vana va mina ndzi ya kutsula.\u2019' },
    { n: 16, text: 'Kutani swi ta va xikombiso evokweni ra wena, ni le xikarhi ka mahlo ya wena, hikuva Yehovha u hi humesile eEgipta hi voko ra matimba.' },
    { n: 17, text: 'Kona loko Faro a pfumelerile vanhu ku famba, Xikwembu a xi va fambisanga hi ndlela ya tiko ra Vafilista, hambileswi a yi ri kusuhi; hikuva Xikwembu xi te: \u2018Leswaku vanhu va nga tshuki va tisola loko va vona nyimpi, va tlhela va vuyela eEgipta.\u2019' },
    { n: 18, text: 'Kambe Xikwembu xi rindzelerisa vanhu hi ndlela ya mananga ya Lwandle ro Tshuka; vana va Israyele va huma etikweni ra Egipta va hlomile swinene.' },
    { n: 19, text: 'Moxe a teka marhambu ya Yosefa na yena; hikuva a a hlambanyisile vana va Israyele swinene, a ku: \u2018Kunene Xikwembu xi ta mi endzela, kutani mi ta humesa marhambu ya mina laha na n\u2019wina.\u2019' },
    { n: 20, text: 'Va suka eSukoti, va goha eEtama, emun\u2019wini wa mananga.' },
    { n: 21, text: 'Yehovha a a famba mahlweni ka vona hi nhlikanhi hi mupapa wa maru ku va fambisa hi ndlela, ni hi vusiku hi mupapa wa ndzilo ku va nyika ku vonakala, leswaku va famba nhlikanhi ni vusiku.' },
    { n: 22, text: 'Mupapa wa maru a wu sukanga mahlweni ka vanhu hi nhlikanhi, hambi e mupapa wa ndzilo hi vusiku.' },
  ],
  14: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: 'Byela vana va Israyele leswaku va hundzuka, va goha mahlweni ka Pi-Hahiroti, exikarhi ka Migidoli ni lwandle, mahlweni ka Baali-Sefoni; mi ta goha kusuhi na rona eribuweni ra lwandle.' },
    { n: 3, text: 'Hikuva Faro u ta ku eka vana va Israyele: \u2018Va lahlekile etikweni, mananga ya va pfelele.\u2019' },
    { n: 4, text: 'Kutani ndzi ta tiyisa mbilu ya Faro, u ta va landzelela; ndzi ta twarisiwa eka Faro ni le ka vandla ra yena hinkwaro, leswaku Vaegipta va tiva leswaku ndzi Yehovha. Hiloko va endla tano.' },
    { n: 5, text: 'Loko hosi ya Egipta yi byeriwile leswaku vanhu va tsutsumile, mbilu ya Faro ni ya malandza ya yena yi hundzuka eka vanhu, va ku: \u2018I yini leswi hi nga swi endla, hi pfumelela Israyele ku suka eku hi tirheleni ke?\u2019' },
    { n: 6, text: 'Hiloko a lunghiselela kalichi ya yena, a teka vanhu va yena na yena.' },
    { n: 7, text: 'A teka makalichi ya makhume-tsevu ya hlawuriweke, ni makalichi hinkwato ya Egipta, ni tindhuna ehenhla ka tona hinkwato.' },
    { n: 8, text: 'Yehovha a tiyisa mbilu ya Faro hosi ya Egipta, a landzelela vana va Israyele; kambe vana va Israyele a va humile hi voko ra le henhla.' },
    { n: 9, text: 'Vaegipta va va landzelela, tihanci hinkwato ni makalichi ya Faro, ni vagandli va yena, ni vandla ra yena, va va fanyela va gohile kusuhi ni lwandle, kusuhi na Pi-Hahiroti, mahlweni ka Baali-Sefoni.' },
    { n: 10, text: 'Loko Faro a tshinela, vana va Israyele va tlakusa mahlo ya vona, kutani vonani, Vaegipta va famba endzhaku ka vona; hiloko va chava swinene, vana va Israyele va rila eka Yehovha.' },
    { n: 11, text: 'Va ku eka Moxe: \u2018Xana i hikwalaho ka leswi ku nga riki na swilahlo eEgipta u nga hi tisa ku ta fela emananga leri ke? I yini leswi u nga hi endla swona, ku hi humesa eEgipta ke?\u2019' },
    { n: 12, text: '\u2018Xana a hi rito leri hi nga ku byela rona eEgipta, hi ku: \u201cHi tshike hi tirhela Vaegipta\u201d ke? Hikuva swi nga va swi ri swinene eka hina ku tirhela Vaegipta ku ri ni ku fela emananga.\u2019' },
    { n: 13, text: 'Moxe a ku eka vanhu: \u2018Mi nga chavi, yimani mi tiya, mi ta vona ku ponisa ka Yehovha, loku a nga ta mi endlela kona namuntlha; hikuva Vaegipta lava mi nga va vona namuntlha, a mi nga ha va voni nakambe ni siku ni rin\u2019we.\u2019' },
    { n: 14, text: '\u2018Yehovha u ta mi lwela, kutani n\u2019wina mi ta miyetela.\u2019' },
    { n: 15, text: 'Yehovha a ku eka Moxe: \u2018I yini leswi u rilaka eka mina ke? Byela vana va Israyele leswaku va famba.\u2019' },
    { n: 16, text: '\u2018Kambe wena, tlakusa nhonga ya wena, u navisa voko ra wena ehenhla ka lwandle, u ri avanyisa, leswaku vana va Israyele va hundza exikarhi ka lwandle hi ndlela yo oma.\u2019' },
    { n: 17, text: '\u2018Kutani mina, vona, ndzi ta tiyisa timbilu ta Vaegipta, va ta nghena endzhaku ka vona; ndzi ta twarisiwa eka Faro ni le ka vandla ra yena hinkwaro, eka makalichi ya yena, ni le ka vagandli ya yena.\u2019' },
    { n: 18, text: '\u2018Kutani Vaegipta va ta tiva leswaku ndzi Yehovha, loko ndzi twarisiwa eka Faro, eka makalichi ya yena, ni le ka vagandli ya yena.\u2019' },
    { n: 19, text: 'Ntsumi ya Xikwembu, leyi a yi famba mahlweni ka nxaxa wa Israyele, yi suka yi ya famba endzhaku ka vona; ni mupapa wa maru wu suka mahlweni ka vona wu ya yima endzhaku ka vona;' },
    { n: 20, text: 'wu nghena exikarhi ka nxaxa wa Egipta ni nxaxa wa Israyele; lowu a ku ri mupapa wa munyama eka van\u2019wana, kambe u nyika ku vonakala eka lavan\u2019wana hi vusiku; kutani va nga tshinelananga vusiku hinkwabyo.' },
    { n: 21, text: 'Moxe a navisa voko ra yena ehenhla ka lwandle; Yehovha a susa lwandle hi mheho ya matimba ya le vuxeni vusiku hinkwabyo, a endla lwandle ri va tiko ro oma, kutani mati ya avanyiseka.' },
    { n: 22, text: 'Vana va Israyele va nghena exikarhi ka lwandle hi ndlela yo oma; mati ya va rirangu ra xinene ni ra ximatsi eka vona.' },
    { n: 23, text: 'Vaegipta va va landzelela, va nghena endzhaku ka vona exikarhi ka lwandle, tihanci hinkwato ta Faro, makalichi ya yena, ni vagandli ya yena.' },
    { n: 24, text: 'Kutani hi nkarhi wa ku rindza ka ntshengula, Yehovha a languta nxaxa wa Vaegipta hi le mupapeni wa ndzilo ni wa maru, a pfilunganya nxaxa wa Vaegipta;' },
    { n: 25, text: 'a susa mavhilwa ya makalichi ya vona, va famba va tikeriwa swinene; hiloko Vaegipta va ku: \u2018A hi tsutsumeni mahlweni ka Israyele, hikuva Yehovha wa va lwela eka Vaegipta.\u2019' },
    { n: 26, text: 'Yehovha a ku eka Moxe: \u2018Navisa voko ra wena ehenhla ka lwandle, leswaku mati ya vuyela ehenhla ka Vaegipta, ehenhla ka makalichi ya vona, ni le henhla ka vagandli ya vona.\u2019' },
    { n: 27, text: 'Moxe a navisa voko ra yena ehenhla ka lwandle, kutani lwandle ri vuyela eka matimba ya rona ntshengula; Vaegipta va tsutsuma va hlangana na rona; Yehovha a hoxa Vaegipta exikarhi ka lwandle.' },
    { n: 28, text: 'Mati ya vuyela, ya funengeta makalichi ni vagandli, ni vandla hinkwaro ra Faro leri nga nghena endzhaku ka vona elwandle; a ku salanga na un\u2019wana wa vona.' },
    { n: 29, text: 'Kambe vana va Israyele va fambile hi ndlela yo oma exikarhi ka lwandle, mati ya va rirangu ra xinene ni ra ximatsi eka vona.' },
    { n: 30, text: 'Hi siku rero Yehovha a ponisa Israyele evokweni ra Vaegipta; kutani Israyele a vona Vaegipta va file eribuweni ra lwandle.' },
    { n: 31, text: 'Israyele a vona voko lera matimba leri Yehovha a nga ri tirhisa eka Vaegipta; kutani vanhu va chava Yehovha, va pfumela eka Yehovha ni le ka Moxe nandza wa yena.' },
  ],
  15: [
    { n: 1, text: 'Kutani Moxe ni vana va Israyele va yimbelela risimu leri eka Yehovha, va ku: Ndzi ta yimbelela eka Yehovha, hikuva u tlakukile swinene; hanci ni mugandli wa yona u va lahlele elwandle.' },
    { n: 2, text: 'Yehovha i matimba ya mina ni risimu ra mina, naswona u hundzukile ku ponisa ka mina; loyi i Xikwembu xa mina, ndzi ta n\u2019wi dzunisa; Xikwembu xa tatana, ndzi ta n\u2019wi tlakusa.' },
    { n: 3, text: 'Yehovha i wanuna wa nyimpi; vito ra yena i Yehovha.' },
    { n: 4, text: 'Makalichi ya Faro ni vandla ra yena u va lahlele elwandle; tindhuna ta yena ta ntsengo leti hlawuriweke ti mbombomele eLwandle ro Tshuka.' },
    { n: 5, text: 'Mati yo yeta ma va funengetile; va rhelele emadziveni tanihi ribye.' },
    { n: 6, text: 'Voko ra wena ra xinene, Yehovha, ri kombisile matimba lamakulu; voko ra wena ra xinene, Yehovha, ri fakamise mulala.' },
    { n: 7, text: 'Hi ku tlakuka ka wena lokukulu u tsemberile lava va ku pfukelaka; u rhumile ku hlundzuka ka wena, ku va herisa tanihi rinyasi.' },
    { n: 8, text: 'Hi ku fuzula ka tinhompfu ta wena mati ya hlengeletanile; mati lama khulukaka ya yimile tanihi mbuva, mati yo yeta ya timile exikarhi ka lwandle.' },
    { n: 9, text: 'Mulala u te: \u2018Ndzi ta landzelela, ndzi ta va fanyela, ndzi ta ava leswi phangiweke; moya wa mina wu ta xurha hi vona; ndzi ta humesa tiko ra mina ra nyimpi, voko ra mina ri ta va herisa.\u2019' },
    { n: 10, text: 'U hungile hi moya wa wena, lwandle ri va funengeta; va mbombomela tanihi ntsumbu ematini ya matimba swinene.' },
    { n: 11, text: 'I mani la fanaka na wena exikarhi ka swikwembu, Yehovha ke? I mani la fanaka na wena, la kwetsimaka hi ku saseka, la chavisaka hi ku dzunisiwa, la endlaka swihlamariso ke?' },
    { n: 12, text: 'U navisile voko ra wena ra xinene, misava yi va mita.' },
    { n: 13, text: 'Hi musa wa wena u rhangerile vanhu lava u nga va kutsula; u va fambisile hi matimba ya wena ku ya endhawini ya wena yo kwetsima.' },
    { n: 14, text: 'Tinxaka ti swi twile, ti rhendzeleka; ku rila ku khomile vaaki va tiko ra Filistiya.' },
    { n: 15, text: 'Kona tindhuna ta Edomu ti chavirile; vavanuna va matimba va Mowabu va khomiwa hi ku rhendzeleka; vaaki hinkvavo va Kanana va sungula ku n\u2019oka.' },
    { n: 16, text: 'Ku chava ni ku chavirika swi va wela henhla; hi vukulu va voko ra wena va miyetela tanihi ribye, ku fikela loko vanhu va wena va hundza, Yehovha, ku fikela loko vanhu lava u nga va xava va hundza.' },
    { n: 17, text: 'U ta va tisa, u va rhandzela entshaveni ya ndzhaka ya wena, endhawini leyi u nga yi endla leswaku u tshama eka yona, Yehovha, endhawini yo kwetsima, Yehovha, leyi mavoko ya wena ya yi tiyiseke.' },
    { n: 18, text: 'Yehovha u ta fuma hilaha ku nga heriki.' },
    { n: 19, text: 'Hikuva loko tihanci ta Faro ni makalichi ya yena ni vagandli va yena va nghene elwandle, Yehovha a vuyisela mati ya lwandle ehenhla ka vona; kambe vana va Israyele va fambile hi ndlela yo oma exikarhi ka lwandle.' },
    { n: 20, text: 'Kutani Miriyame muprofeta wa xisati, makwavo wa Aroni, a teka xingomana evokweni ra yena; vavasati hinkvavo va huma endzhaku ka yena va ri ni swingomana, va kina.' },
    { n: 21, text: 'Miriyame a va hlamula, a ku: Yimbelelani eka Yehovha, hikuva u tlakukile swinene; hanci ni mugandli wa yona u va lahlele elwandle.' },
    { n: 22, text: 'Moxe a fambisa Israyele ku suka eLwandle ro Tshuka, va humela emananga ya Xuri; va famba masiku manharhu emananga, va nga kumi mati.' },
    { n: 23, text: 'Loko va fika eMara, a va nga koti ku nwa mati ya Mara, hikuva a ma bava; hikwalaho vito ra kona ri nga thyiwa Mara.' },
    { n: 24, text: 'Vanhu va gungula eka Moxe, va ku: \u2018Hi ta nwa yini ke?\u2019' },
    { n: 25, text: 'Yena a rila eka Yehovha; kutani Yehovha a n\u2019wi komba mhandze; a yi hoxela ematini, hiloko mati ya nandziha. Laho Yehovha a nga va vekela nawu ni ku avanyisa, naswona laho a nga va ringa,' },
    { n: 26, text: 'a ku: \u2018Loko u yingisela rito ra Yehovha Xikwembu xa wena swinene, u endla leswi lulameke ematlhweni ka yena, u yingisela swileriso swa yena, u hlayisa milawu ya yena hinkwayo, a ndzi nga ka ndzi nga ku tisi na xin\u2019we xa mavabyi lawa ndzi nga ma tisa eka Vaegipta; hikuva ndzi Yehovha mutshunguli wa wena.\u2019' },
    { n: 27, text: 'Va fika eElimu, lomu a ku ri ni swihlovo swa khume-timbiri swa mati ni minkindzu ya makume-nkombo (70); va goha laho kusuhi ni mati.' },
  ],
  16: [
    { n: 1, text: 'Va suka eElimu, vandla hinkwaro ra vana va Israyele ri fika emananga ya Sini, leri nga exikarhi ka Elimu ni Sinayi, hi siku ra vukhume-mune ra n\u2019weti wa vumbirhi endzhaku ka loko va humile etikweni ra Egipta.' },
    { n: 2, text: 'Vandla hinkwaro ra vana va Israyele ri gungula eka Moxe ni ka Aroni emananga.' },
    { n: 3, text: 'Vana va Israyele va ku eka vona: \u2018Inge hi file hi voko ra Yehovha etikweni ra Egipta, loko hi tshamile kusuhi ni timbiza ta nyama, loko hi dya swinkwa hi xurha; hikuva mi hi humeserile emananga leri ku dlayisa hinkwaro vandla leri hi ndlala.\u2019' },
    { n: 4, text: 'Yehovha a ku eka Moxe: Vona, ndzi ta mi nisela swinkwa leswi humaka dzingwini ra matilo; vanhu va ta huma va hlengeleta mukavelo wa siku un\u2019wana ni un\u2019wana hi siku ra kona, leswaku ndzi va ringa loko va landzela nawu wa mina kumbe e-e.' },
    { n: 5, text: 'Kambe hi siku ra vutandzanu (6) va ta lunghiselela leswi va nga swi tisa, swi ta va swimbirhi ku tlula leswi va nga swi hlengeleta siku ni siku.' },
    { n: 6, text: 'Moxe na Aroni va ku eka vana va Israyele hinkvavo: Nimadyambu mi ta tiva leswaku i Yehovha loyi a nga mi humesa etikweni ra Egipta;' },
    { n: 7, text: 'nimixo mi ta vona ku dzunisa ka Yehovha, hikuva u twile ku gungula ka n\u2019wina eka Yehovha; kasi hina hi vamani leswaku mi nga gungula eka hina ke?' },
    { n: 8, text: 'Moxe a ku: Swi ta endleka loko Yehovha a mi nyika nyama yo dya nimadyambu, ni swinkwa nimixo ku xurha; hikuva Yehovha wa twa ku gungula ka n\u2019wina loku mi n\u2019wi gungulelaka kona; kasi hina hi vamani? Ku gungula ka n\u2019wina a ku ri eka hina, kambe ku le ka Yehovha.' },
    { n: 9, text: 'Moxe a ku eka Aroni: Byela vandla hinkwaro ra vana va Israyele, u ku: \u2018Tshinelani mahlweni ka Yehovha, hikuva u twile ku gungula ka n\u2019wina.\u2019' },
    { n: 10, text: 'Kutani loko Aroni a vulavula ni vandla hinkwaro ra vana va Israyele, va hundzuluxela langutelo ra vona emananga, kutani vonani, ku dzunisa ka Yehovha ku humelela emupapeni wa maru.' },
    { n: 11, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 12, text: 'Ndzi twile ku gungula ka vana va Israyele; vulavula na vona, u ku: \u2018Hi nkarhi wa madyambu mi ta dya nyama, naswona nimixo mi ta xurha hi swinkwa; kutani mi ta tiva leswaku ndzi Yehovha Xikwembu xa n\u2019wina.\u2019' },
    { n: 13, text: 'Kutani nimadyambu swikhorha swi tlhandluka, swi funengeta nxaxa; kasi nimixo mberha a yi ri kusuhi ni nxaxa.' },
    { n: 14, text: 'Loko mberha leyi yi herile, vonani, ehenhla ka misava ya mananga ku ri ni nchumu wa swiphembi-phembi, wa ntsandza lowutsongo, wa ntsandza lowu fanaka ni mberha yo tsemba emisaveni.' },
    { n: 15, text: 'Loko vana va Israyele va swi vona, va ku un\u2019wana ni un\u2019wana eka makwavo: \u2018I yini leswi ke?\u2019 Hikuva a va nga tivi leswaku i yini. Moxe a ku eka vona: \u2018Leri i xinkwa lexi Yehovha a nga mi nyika xona leswaku mi xi dya.\u2019' },
    { n: 16, text: '\u2018Hi leswi Yehovha a nga swi lerisa: Hlengeletani eka xona, un\u2019wana ni un\u2019wana hi ku ya hi ku dya kakwe, mpimo wa omeri (omer) hi nhloko, hi ku ya hi ntsengo wa mimoya ya n\u2019wina; un\u2019wana ni un\u2019wana a a hlengeletele lava va nga etendeni ra yena.\u2019' },
    { n: 17, text: 'Vana va Israyele va endla tano, va hlengeleta, un\u2019wana a hlengeleta swo tala, un\u2019wana switsongo.' },
    { n: 18, text: 'Loko va pima hi omeri, loyi a nga hlengeleta swo tala a nga saleriwanga hi nchumu, na loyi a nga hlengeleta switsongo a nga kayivelanga; un\u2019wana ni un\u2019wana a hlengeleta hi ku ya hi ku dya kakwe.' },
    { n: 19, text: 'Moxe a ku eka vona: Ku nga tshuki ku va ni loyi a siyelaka nchumu wa xona ku fikela nimixo.' },
    { n: 20, text: 'Kambe a va yingiselanga Moxe; un\u2019wana ni un\u2019wana a siyela xiphemu xa xona ku fikela nimixo, hiloko xi tswala swivungu, xi nuha; kutani Moxe a va hlundzukela.' },
    { n: 21, text: 'Va xi hlengeleta nimixo un\u2019wana ni un\u2019wana hi ku ya hi ku dya kakwe; loko dyambu ri hisa swinene, xi sungula ku n\u2019oka.' },
    { n: 22, text: 'Kutani hi siku ra vutandzanu (6) va hlengeleta swinkwa swimbirhi ku tlula ntolovelo, tiomeri timbirhi eka un\u2019wana ni un\u2019wana; tindhuna hinkwato ta vandla ti ta byela Moxe.' },
    { n: 23, text: 'Yena a ku eka vona: \u2018Hi leswi Yehovha a nga swi vula: Mundzuku i ku wisa loku kwetsimaka, Savata yo kwetsima eka Yehovha. Leswi mi rhandzaka ku swi baka, swi bakeni, ni leswi mi rhandzaka ku swi sweka, swi swekeni; kutani hinkwaswo leswi salaka, swi vekeni swi hlayiseka ku fikela nimixo.\u2019' },
    { n: 24, text: 'Va swi hlayisa ku fikela nimixo, hilaha Moxe a nga lerisa hakona; a swi nuhanga, naswona a ku nga ri na xivungu eka swona.' },
    { n: 25, text: 'Moxe a ku: \u2018Xi dyeni namuntlha, hikuva namuntlha i Savata ya Yehovha; namuntlha a mi nga ka mi nga xi kumi emasin\u2019wini.\u2019' },
    { n: 26, text: '\u2018Masiku ya tsevu mi ta xi hlengeleta, kambe hi siku ra vunkombo, leri nga Savata, a ku nga vi na nchumu eka rona.\u2019' },
    { n: 27, text: 'Kutani hi siku ra vunkombo un\u2019wana wa vanhu a huma ku ya hlengeleta, kambe a nga kumanga nchumu.' },
    { n: 28, text: 'Yehovha a ku eka Moxe: Ku fikela rini mi ala ku hlayisa swileriso swa mina ni milawu ya mina ke?' },
    { n: 29, text: 'Vonani, hikuva Yehovha u mi nyikile Savata; hikwalaho hi siku ra vutandzanu u mi nyika swinkwa swa masiku mambirhi; un\u2019wana ni un\u2019wana a a tshame endhawini ya yena, ku nga tshuki ku va ni loyi a humaka endhawini ya yena hi siku ra vunkombo.' },
    { n: 30, text: 'Kutani vanhu va wisa hi siku ra vunkombo.' },
    { n: 31, text: 'Yindlu ya Israyele yi thya vito ra xona Manna (Mana); a xi ri tanihi mbewu ya koriandere leyo basa, naswona ku nandziha ka xona a ku ri tanihi xinkwa xo lula lexi nga ni vulombe.' },
    { n: 32, text: 'Moxe a ku: \u2018Hi leswi Yehovha a nga swi lerisa: Tata omeri ya xona leswaku xi hlayisiwa emixakabyini ya n\u2019wina hinkwayo, leswaku va vona xinkwa lexi ndzi mi dyiseke xona emananga, loko ndzi mi humesa etikweni ra Egipta.\u2019' },
    { n: 33, text: 'Moxe a ku eka Aroni: \u2018Teka mbiza, u veka omeri yi tele hi Manna eka yona, u yi yimisa mahlweni ka Yehovha leswaku yi hlayisiwa emixakabyini ya n\u2019wina.\u2019' },
    { n: 34, text: 'Hilaha Yehovha a nga lerisa Moxe hakona, Aroni a yi yimisa mahlweni ka vumbhoni leswaku yi hlayisiwa.' },
    { n: 35, text: 'Vana va Israyele va dya Manna malembe ya makume-mune (40), ku fikela loko va fika etikweni leri ku tshamaka vanhu eka rona; va dya Manna ku fikela loko va fika emun\u2019wini wa tiko ra Kanana.' },
    { n: 36, text: 'Kasi omeri i xiphemu xa vukhume xa efa.' },
  ],
  17: [
    { n: 1, text: 'Vandla hinkwaro ra vana va Israyele ri suka emananga ya Sini, va famba hi ku landzela swiyimo swa vona hilaha Yehovha a nga lerisa hakona; va goha eRefidimi; kambe a ku nga ri na mati leswaku vanhu va nwa.' },
    { n: 2, text: 'Vanhu va holova na Moxe, va ku: \u2018Hi nyike mati leswaku hi nwa.\u2019 Moxe a ku eka vona: \u2018I yini leswi mi holovaka na mina ke? I yini leswi mi ringaka Yehovha ke?\u2019' },
    { n: 3, text: 'Vanhu va khomiwa hi torha ra mati laho, kutani vanhu va gungulela Moxe, va ku: \u2018I yini leswi u nga hi humesa ha swona eEgipta, ku hi dlayisa hi torha, hina ni vana va hina, ni swifuwo va hina ke?\u2019' },
    { n: 4, text: 'Moxe a rila eka Yehovha, a ku: \u2018Ndzi ta endla yini hi vanhu lava ke? Ku kusuhi leswaku va ndzi ganda hi maribye.\u2019' },
    { n: 5, text: 'Yehovha a ku eka Moxe: \u2018Hundza mahlweni ka vanhu, u teka van\u2019wana va vakulukumba va Israyele na wena; ni nhonga ya wena leyi u nga ba nambu ha yona, yi teke evokweni ra wena, u famba.\u2019' },
    { n: 6, text: '\u2018Vona, ndzi ta yima mahlweni ka wena laho ehenhla ka ribye eHorebe; u ta ba ribye lero, kutani mati ya ta huma eka rona leswaku vanhu va nwa.\u2019 Moxe a endla tano mahlweni ka vakulukumba va Israyele.' },
    { n: 7, text: 'A thya vito ra ndhawu yoleyo Masa na Meriba, hikwalaho ka ku holova ka vana va Israyele, ni hikwalaho ka ku ringa ka vona Yehovha, va ku: \u2018Xana Yehovha u exikarhi ka hina, kumbe e-e ke?\u2019' },
    { n: 8, text: 'Kutani vaAmaleke va ta, va lwa na Israyele eRefidimi.' },
    { n: 9, text: 'Moxe a ku eka Yoxuwa: \u2018Hi hlawulele vavanuna, u huma u ya lwa na vaAmaleke; mundzuku ndzi ta yima ehenhla ka xintshabyana, ndzi khome nhonga ya Xikwembu evokweni ra mina.\u2019' },
    { n: 10, text: 'Yoxuwa a endla hilaha Moxe a nga n\u2019wi byela hakona, a lwa na vaAmaleke; kambe Moxe, na Aroni, na Huru va tlhandluka ehenhla ka xintshabyana.' },
    { n: 11, text: 'Kutani loko Moxe a tlakusile voko ra yena, Israyele a a hlula; kambe loko a rhelerisa voko ra yena, Amaleke a a hlula.' },
    { n: 12, text: 'Kambe mavoko ya Moxe ya tikela; hiloko va teka ribye, va ri veka hansi ka yena, a tshama ehenhla ka rona; Aroni na Huru va seketela mavoko ya yena, un\u2019wana hi tlhelo leri, un\u2019wana hi tlhelo lera; kutani mavoko ya yena ya tiya ku fikela loko dyambu ri pela.' },
    { n: 13, text: 'Yoxuwa a hlula Amaleke ni vanhu va yena hi vukari bya banga.' },
    { n: 14, text: 'Yehovha a ku eka Moxe: Tsala mhaka leyi tanihi xitsundzuxo ebukwini, u yi tivisa etindleveleni ta Yoxuwa; hikuva ndzi ta herisa xitsundzuxo xa Amaleke hansi ka matilo hinkwako.' },
    { n: 15, text: 'Moxe a aka alitari, a thya vito ra yona Yehovha-Nisi (Yehovha i murendzo wa mina);' },
    { n: 16, text: 'a ku: \u2018Hikuva voko ri le henhla ka xiluvelo xa Yehovha; Yehovha u ta va ni nyimpi na Amaleke emixakabyini hinkwayo.\u2019' },
  ],
  18: [
    { n: 1, text: 'Yetro, muprista wa Midiyane, mukon\u2019wana wa Moxe, a twa hinkwaswo leswi Xikwembu xi nga swi endlela Moxe na Israyele vanhu va xona, leswaku Yehovha u humesile Israyele eEgipta.' },
    { n: 2, text: 'Yetro, mukon\u2019wana wa Moxe, a teka Sipora, nsati wa Moxe, endzhaku ka loko a nga n\u2019wi tlherisile,' },
    { n: 3, text: 'ni vana va yena vambirhi va majaha; loyi vito ra un\u2019wana a ku ri Gerixomu (hikuva u te: \u2018Ndzi vile muluveri etikweni ra vumbhoni\u2019);' },
    { n: 4, text: 'ni vito ra un\u2019wana a ku ri Eliyezere (hikuva u te: \u2018Xikwembu xa tatana xi vile mupfuni wa mina, xi ndzi ponisile eka banga ra Faro\u2019).' },
    { n: 5, text: 'Yetro, mukon\u2019wana wa Moxe, a ta ni vana va Moxe va majaha ni nsati wa yena eka Moxe emananga, lomu a a gohile kona kusuhi ni ntshava ya Xikwembu.' },
    { n: 6, text: 'A rhangela rito eka Moxe, a ku: \u2018Mina Yetro mukon\u2019wana wa wena, ndzi ta eka wena, ni nsati wa wena ni vana va wena vambirhi va majaha na yena.\u2019' },
    { n: 7, text: 'Moxe a huma ku ya hlangana ni mukon\u2019wana wa yena, a korhama, a n\u2019wi ntsuntsa; va vutisa un\u2019wana ni un\u2019wana hi ku hlayiseka ka yena, hiloko va nghena etendeni.' },
    { n: 8, text: 'Moxe a hlayisela mukon\u2019wana wa yena hinkwaswo leswi Yehovha a nga swi endla eka Faro ni le ka Vaegipta hikwalaho ka Israyele, ni hinkwako ku tikeriwa loku va nga hlangana na kona endleleni, ni leswaku Yehovha u va ponisile njhani.' },
    { n: 9, text: 'Yetro a tsaka hikwalaho ka hinkwako ku saseka loku Yehovha a nga ku endla eka Israyele, loyi a nga n\u2019wi ponisa evokweni ra Vaegipta.' },
    { n: 10, text: 'Yetro a ku: \u2018A ku dzunisiwe Yehovha, loyi a nga mi ponisa evokweni ra Vaegipta ni le vokweni ra Faro, loyi a nga ponisa vanhu hansi ka voko ra Vaegipta.\u2019' },
    { n: 11, text: '\u2018Sweswi ndzi tiva leswaku Yehovha u nkulu ku tlula swikwembu hinkwaswo; hikuva emhakeni leyi va nga va holovela ha yona, a a ri henhla ka vona.\u2019' },
    { n: 12, text: 'Kutani Yetro, mukon\u2019wana wa Moxe, a tisa xitlhabelo xo hisiwa ni switlhabelo swin\u2019wana eka Xikwembu; Aroni ni vakulukumba hinkvavo va Israyele va ta ku dya swakudya ni mukon\u2019wana wa Moxe mahlweni ka Xikwembu.' },
    { n: 13, text: 'Hi siku leri landzelaka Moxe a tshama ku avanyisela vanhu; kutani vanhu va yima mahlweni ka Moxe kusukela nimixo ku fikela nimadyambu.' },
    { n: 14, text: 'Loko mukon\u2019wana wa Moxe a vona hinkwaswo leswi a a swi endlela vanhu, a ku: \u2018I yini nchumu lowu u wu endlelaka vanhu ke? I yini leswi u tshamaka ntsena u ri wexe, kasi vanhu hinkvavo va yimile mahlweni ka wena kusukela nimixo ku fikela nimadyambu ke?\u2019' },
    { n: 15, text: 'Moxe a ku eka mukon\u2019wana wa yena: \u2018Hikuva vanhu va ta eka mina ku ta lava ku tsundzuxiwa hi Xikwembu;\u2019' },
    { n: 16, text: '\u2018loko va ri ni mhaka, va ta eka mina, kutani ndzi avanyisa exikarhi ka un\u2019wana ni un\u2019wana, ndzi va tivisa milawu ya Xikwembu ni swileriso xa xona.\u2019' },
    { n: 17, text: 'Mukon\u2019wana wa Moxe a ku eka yena: \u2018Nchumu lowu u wu endlaka a wu sasekanga.\u2019' },
    { n: 18, text: '\u2018Kunene u ta karhala swinene, wena ni vanhu lava va nga na wena; hikuva ntirho lowu wu ku tikela swinene, u nga ka u nga koti ku wu endla u ri wexe.\u2019' },
    { n: 19, text: '\u2018Yingisela sweswi rito ra mina; ndzi ta ku nyika xitsundzuxo, kutani Xikwembu a xi ve na wena: Vana muyimeri wa vanhu mahlweni ka Xikwembu, u tisa timhaka eka Xikwembu;' },
    { n: 20, text: '\u2018u va dyondzisa milawu ni swileriso, u va komba ndlela leyi va faneleke ku famba ha yona, ni ntirho lowu va faneleke ku wu endla.\u2019' },
    { n: 21, text: '\u2018Kambe wena, hlawula exikarhi ka vanhu hinkvavo vavanuna va matimba, lava chavaka Xikwembu, vavanuna va ntiyiso, lava nyenyetsaka vukanganyisi, u va veka henhla ka vona ku va tindhuna ta gidi (1,000), tindhuna ta dzana (100), tindhuna ta ntsengo wa makume-ntlhanu (50), ni tindhuna ta ntsengo wa khume (10);\u2019' },
    { n: 22, text: '\u2018va ta avanyisela vanhu hi mikarhi hinkwayo; kutani mhaka hinkwayo leyikulu va ta yi tisa eka wena, kambe mhaka hinkwayo leyitsongo va ta yi avanyisa hi voxe; swi ta ku olovela, hikuva va ta rwala rhendzo leri na wena.\u2019' },
    { n: 23, text: '\u2018Loko u endla nchumu lowu, naswona Xikwembu xi ku lerisa tano, u ta koti ku tiya, ni hinkwavo vanhu lava va ta fika endhawini ya vona hi ku rhula.\u2019' },
    { n: 24, text: 'Moxe a yingisela rito ra mukon\u2019wana wa yena, a endla hinkwaswo leswi a nga swi vula.' },
    { n: 25, text: 'Moxe a hlawula vavanuna va matimba exikarhi ka Israyele hinkwayo, a va veka henhla ka vanhu, va va tindhuna ta gidi (1,000), tindhuna ta dzana (100), tindhuna ta makume-ntlhanu (50), ni tindhuna ta khume (10).' },
    { n: 26, text: 'Va avanyisela vanhu hi mikarhi hinkwayo; timhaka to tikela va ti tisa eka Moxe, kambe timhaka hinkwato to olova va ti avanyisela hi voxe.' },
    { n: 27, text: 'Moxe a tlherisa mukon\u2019wana wa yena, hiloko a tifambela ku ya etikweni ra yena.' },
  ],
  19: [
    { n: 1, text: 'Hi n\u2019weti wa vunharhu, endzhaku ka loko vana va Israyele va humile etikweni ra Egipta, hi siku rero va fika emananga ya Sinayi.' },
    { n: 2, text: 'Va suka eRefidimi, va fika emananga ya Sinayi, va goha emananga; Israyele a goha kwalaho mahlweni ka ntshava.' },
    { n: 3, text: 'Moxe a tlhandlukela eka Xikwembu; Yehovha a vitana yena entshaveni, a ku: \u2018Byela yindlu ya Yakobo, u tivisa vana va Israyele, u ku:\u2019' },
    { n: 4, text: '\u2018Mi vonile leswi ndzi swi endleke eka Vaegipta, ni leswi ndzi mi rhwaleke ha swona ehenhla ka timpapa ta maxalati, ndzi mi tisa eka mina.\u2019' },
    { n: 5, text: '\u2018Sweswi ke, loko mi yingisela rito ra mina swinene, mi hlayisa ntwanano wa mina, mi ta va xuma xa mina eka matiko hinkwawo; hikuva misava hinkwayo i ya mina.\u2019' },
    { n: 6, text: '\u2018Mi ta va mfumo wa vaprista eka mina, ni tiko ro kwetsima. Lawa i marito lawa u nga ta ma byela vana va Israyele.\u2019' },
    { n: 7, text: 'Moxe a ta, a vitana vakulukumba va vanhu, a va tivisa marito lawa hinkwawo lawa Yehovha a nga n\u2019wi lerisa wona.' },
    { n: 8, text: 'Vanhu hinkwavo va hlamula hi rito rin\u2019we, va ku: \u2018Hinkwaswo leswi Yehovha a swi vuleke, hi ta swi endla.\u2019 Moxe a tlherisela marito ya vanhu eka Yehovha.' },
    { n: 9, text: 'Yehovha a ku eka Moxe: \u2018Vona, ndzi ta ta eka wena hi mupapa wa maru, leswaku vanhu va twa loko ndzi vulavula na wena, va ta ku pfumela hilaha ku nga heriki.\u2019 Moxe a tivisa marito ya vanhu eka Yehovha.' },
    { n: 10, text: 'Yehovha a ku eka Moxe: \u2018Famba eka vanhu, u va kwetsimisa namuntlha ni mundzuku, va hlantswa tinguvu ta vona.\u2019' },
    { n: 11, text: '\u2018Va nenele hi siku ra vunharhu; hikuva hi siku ra vunharhu Yehovha u ta rhelela entshaveni ya Sinayi mahlweni ka vanhu hinkwavo.\u2019' },
    { n: 12, text: '\u2018Teka ndzilakano wa vanhu ku rhendzela, u ku: \u201cTivonelani ku tlhandlukela entshaveni kumbe ku khumba nkuma wa yona; un\u2019wana ni un\u2019wana loyi a khumbaka ntshava u ta dlayiwa.\u201d\u2019' },
    { n: 13, text: '\u2018Ku nga tshuki ku va ni voko leri khumbaka yona, hikuva u ta gandiwa hi maribye kumbe ku tsuviwa hi miseve; hambi a ri xifuwo hambi a ri munhu, a nga ka a nga pfumeleriwi ku hanya; loko mpongolo wu rila, va ta tlhandlukela entshaveni.\u2019' },
    { n: 14, text: 'Moxe a rhelela entshaveni eka vanhu, a kwetsimisa vanhu, va hlantswa tinguvu ta vona.' },
    { n: 15, text: 'A ku eka vanhu: \u2018Lunghekani hi siku ra vunharhu; mi nga tshineli ka vavasati.\u2019' },
    { n: 16, text: 'Hi siku ra vunharhu, loko ku ri mixo, ku va ni ku dzindza ka tulu ni mpama, ni mupapa wa maru entshaveni, ni rito ra mpongolo ra matimba swinene; vanhu hinkwavo lava a va ri enkambeni va rhurhumela.' },
    { n: 17, text: 'Moxe a humesa vanhu enkambeni ku ya hlangana ni Xikwembu, va yima ehansi ka ntshava.' },
    { n: 18, text: 'Ntshava ya Sinayi a yi ri ni musi hinkwayo, hikuva Yehovha a a rhelele ehenhla ka yona hi ndzilo; musi wa yona a wu tlhandluka tanihi musi wa xitofu, ntshava hinkwayo yi tsekatseka swinene.' },
    { n: 19, text: 'Loko rito ra mpongolo ri ya ri kurisa swinene, Moxe a vulavula, kutani Xikwembu xi n\u2019wi hlamula hi rito.' },
    { n: 20, text: 'Yehovha a rhelela entshaveni ya Sinayi, ehenhla ka nhloko ya ntshava; Yehovha a vitana Moxe entshaveni, Moxe a tlhandluka.' },
    { n: 21, text: 'Yehovha a ku eka Moxe: \u2018Rhelela, u tivisa vanhu, leswaku va nga tshuki va tshinela eka Yehovha ku ya vona, hikuva va ta fa hi ku tala.\u2019' },
    { n: 22, text: '\u2018Ni vaprista lava va tshinelelaka Yehovha va fanele va ti-kwetsimisa, leswaku Yehovha a nga va tsuvi.\u2019' },
    { n: 23, text: 'Moxe a ku eka Yehovha: \u2018Vanhu va nga ka va nga tlhandlukeli entshaveni ya Sinayi, hikuva wena u hi lerisile, u ku: \u201cCeka ndzilakano entshaveni, u yi kwetsimisa.\u201d\u2019' },
    { n: 24, text: 'Yehovha a ku eka yena: \u2018Famba, u rhelela, u tlhela u vuya na Aroni; kambe vaprista ni vanhu va nga tshuki va tlhandluka ku ya eka Yehovha, leswaku a nga va tsuvi.\u2019' },
    { n: 25, text: 'Moxe a rhelela eka vanhu, a va byela tano.' },
  ],
  20: [
    { n: 1, text: 'Xikwembu xi vula marito lawa hinkwawo, xi ku:' },
    { n: 2, text: '\u2018Ndzi Yehovha Xikwembu xa wena, loyi a ku humeseke etikweni ra Egipta, endlwini ya vuhlonga.\u2019' },
    { n: 3, text: '\u2018U nga tshuki u va ni swikwembu swin\u2019wana mahlweni ka mina.\u2019' },
    { n: 4, text: '\u2018U nga tshuki u tiendlela xifaniso lexi vatliweke, kumbe xifaniso xa nchumu lowu nga ematilweni ehenhla, kumbe lowu nga emisaveni ehansi, kumbe lowu nga ematini ehansi ka misava.\u2019' },
    { n: 5, text: '\u2018U nga tshuki u va nkhinsamela hambi ku va va tirhela; hikuva mina Yehovha Xikwembu xa wena, ndzi Xikwembu lexi nga ni titshembela, ndzi ba xidyoho xa vatatana ehenhla ka vana, ku fikela eka xitukulwana xa vunharhu ni xa mune xa lava va ndzi vengaka;\u2019' },
    { n: 6, text: '\u2018naswona ndzi komba musa eka madzana ya switukulwana ya lava va ndzi rhandzaka, lava hlayisaka milawu ya mina.\u2019' },
    { n: 7, text: '\u2018U nga tshuki u tirhisa vito ra Yehovha Xikwembu xa wena hi ndlela leyi nga riki ya nkoka; hikuva Yehovha a nga ka a nga n\u2019wi teki loyi a tirhisaka vito ra yena hi ndlela leyi nga riki ya nkoka a ri la nga riki na nandzu.\u2019' },
    { n: 8, text: '\u2018Tsundzuka siku ra Savata leswaku u ri kwetsimisa.\u2019' },
    { n: 9, text: '\u2018Masiku ya tsevu u ta tirha, u endla ntirho wa wena hinkwawo;\u2019' },
    { n: 10, text: '\u2018kambe siku ra vunkombo i Savata ya Yehovha Xikwembu xa wena; u nga tshuki u endla ntirho na wun\u2019we, wena, hambi i n\u2019wana wa wena wa jaha, hambi i n\u2019wana wa wena wa xisati, hambi i nandza wa wena, hambi i nandza wa wena wa xisati, hambi i xifuwo xa wena, hambi i muluveri loyi a nga ndzeni ka tinyangwa ta wena.\u2019' },
    { n: 11, text: '\u2018Hikuva hi masiku ya tsevu Yehovha u endle matilo ni misava, ni lwandle, ni hinkwaswo leswi nga eka swona, kutani a wisa hi siku ra vunkombo; hikwalaho Yehovha u katekise siku ra Savata, a ri kwetsimisa.\u2019' },
    { n: 12, text: '\u2018Xixima tatana wa wena ni manana wa wena, leswaku masiku ya wena ma leha etikweni leri Yehovha Xikwembu xa wena a ku nyikaka rona.\u2019' },
    { n: 13, text: '\u2018U nga tshuki u dlaya.\u2019' },
    { n: 14, text: '\u2018U nga tshuki u endla vuoswi.\u2019' },
    { n: 15, text: '\u2018U nga tshuki u yiva.\u2019' },
    { n: 16, text: '\u2018U nga tshuki u hemba eka muakelani wa wena.\u2019' },
    { n: 17, text: '\u2018U nga tshuki u navela yindlu ya muakelani wa wena; u nga tshuki u navela nsati wa muakelani wa wena, hambi i nandza wa yena, hambi i nandza wa yena wa xisati, hambi i homu ya yena, hambi i mbongolo ya yena, hambi i nchumu wa muakelani wa wena.\u2019' },
    { n: 18, text: 'Vanhu hinkwavo va twa ku dzindza ka tulu, ni mpama, ni rito ra mpongolo, ni ntshava leyi nga ni musi; loko vanhu va swi vona, va rhendzeleka, va yima ekule.' },
    { n: 19, text: 'Va ku eka Moxe: \u2018Vulavula wena na hina, kutani hi ta yingisela; kambe u nga tshuki u vula leswaku Xikwembu xi vulavula na hina, leswaku hi nga fi.\u2019' },
    { n: 20, text: 'Moxe a ku eka vanhu: \u2018Mi nga chavi; hikuva Xikwembu xi tele ku mi ringa, leswaku ku chava ka xona ku va mahlweni ka n\u2019wina, leswaku mi nga dyohi.\u2019' },
    { n: 21, text: 'Vanhu va yima ekule, kambe Moxe a tshinela eka musi wa xivindzi lomu Xikwembu a xi ri kona.' },
    { n: 22, text: 'Yehovha a ku eka Moxe: \u2018Byela vana va Israyele: \u201cMi vonile leswaku ndzi vulavule na n\u2019wina ndzi ri ematilweni.\u201d\u2019' },
  ],
  21: [
    { n: 1, text: 'Lawa i milawu leyi u nga ta yi veka mahlweni ka vona.' },
    { n: 2, text: '\u2018Loko u xava nandza wa Xiheveru, u ta ku tirhela malembe ya tsevu; hi lembe ra vunkombo a ta huma a ntshunxekile, a nga hlawanga nchumu.\u2019' },
    { n: 3, text: '\u2018Loko a te a ri un\u2019we, u ta huma a ri un\u2019we; loko a ri na nsati, nsati wa yena u ta huma na yena.\u2019' },
    { n: 4, text: '\u2018Loko n\u2019wini wa yena a n\u2019wi nyikile nsati, kutani a tswala vana va majaha kumbe va xisati, nsati ni vana va yena va ta va va n\u2019wini wa yena, kutani yena u ta huma a ri un\u2019we.\u2019' },
    { n: 5, text: '\u2018Kambe loko nandza a ku: \u201cNdzi rhandza n\u2019wini wa mina, ni nsati wa mina, ni vana va mina; a ndzi lavi ku huma ndzi ntshunxekile\u201d;\u2019' },
    { n: 6, text: '\u2018kutani n\u2019wini wa yena a a n\u2019wi tise mahlweni ka Xikwembu, a n\u2019wi tise emimbiteni kumbe etimhandzeni ta timbanti, kutani n\u2019wini wa yena a n\u2019wi ba ndleve hi xitirho; kutani a ta n\u2019wi tirhela hilaha ku nga heriki.\u2019' },
    { n: 7, text: '\u2018Loko wanuna a xavisa n\u2019wana wa yena wa xisati ku va nandza, a nga ka a nga humi hilaha nandza wa xinuna a humaka hakona.\u2019' },
    { n: 8, text: '\u2018Loko a nga n\u2019wi tsakeli mahlweni ka n\u2019wini wa yena, loyi a nga n\u2019wi hlawulaka eka yena, u ta pfumelela leswaku a kutsuriwa; a nga ka a nga na matimba ya ku n\u2019wi xavisa eka vanhu vambe, hikuva u n\u2019wi kanganyisile.\u2019' },
    { n: 9, text: '\u2018Loko a n\u2019wi hlawulela n\u2019wana wa yena wa jaha, u ta n\u2019wi endla hilaha ku fanaka ni vana va xisati.\u2019' },
    { n: 10, text: '\u2018Loko a teka un\u2019wana, a nga tshiki swakudya swa yena, ni tinguvu ta yena, ni nawu wa vukati wa yena.\u2019' },
    { n: 11, text: '\u2018Loko a nga n\u2019wi endleli swilo leswi swinharhu, u ta huma a nga hakelanga mali.\u2019' },
    { n: 12, text: '\u2018Loyi a baka munhu, leswaku a fa, u ta dlayiwa.\u2019' },
    { n: 13, text: '\u2018Kambe loyi a nga n\u2019wi pfukelanga, kambe Xikwembu xi n\u2019wi humesela evokweni ra yena, ndzi ta ku hlawulela ndhawu leyi a nga ta balekela eka yona.\u2019' },
    { n: 14, text: '\u2018Loko munhu a lwa ni muakelani wa yena hi vukari, a n\u2019wi dlaya hi vuxisi, hambi a ri eka alitari ya mina, u ta n\u2019wi teka leswaku a fa.\u2019' },
    { n: 15, text: '\u2018Loyi a baka tatana wa yena kumbe manana wa yena u ta dlayiwa.\u2019' },
    { n: 16, text: '\u2018Loyi a yivaka munhu, hambi a n\u2019wi xavisile, hambi a kumiwe a ri evokweni ra yena, u ta dlayiwa.\u2019' },
    { n: 17, text: '\u2018Loyi a tlhukanaka tatana wa yena kumbe manana wa yena u ta dlayiwa.\u2019' },
    { n: 18, text: '\u2018Loko vavanuna va holova, un\u2019wana a ba un\u2019wana hi ribye kumbe hi xintshabyana, a nga fi, kambe a tlhela a etlela ehansi;\u2019' },
    { n: 19, text: '\u2018loko a pfuka a famba ehandle hi nhonga ya yena, loyi a n\u2019wi ba a ta va a nga ri na nandzu, ntsena a a hakela nkarhi wa yena ni ku n\u2019wi horisa swinene.\u2019' },
    { n: 20, text: '\u2018Loko wanuna a ba nandza wa yena kumbe nandza wa yena wa xisati hi nhonga, a fa evokweni ra yena, u ta xupuriwa.\u2019' },
    { n: 21, text: '\u2018Kambe loko a hanya siku rin\u2019we kumbe mambirhi, a nga xupuriwi, hikuva i mali ya yena.\u2019' },
    { n: 22, text: '\u2018Loko vavanuna va holova, va ba wansati la nga ni khwiri, kutani vana va yena va huma, kambe ku nga ri na mhaka ya rifu, u ta hakela hilaha n\u2019wini wa wansati a nga ta n\u2019wi kombisa hakona; u ta hakela hi ku avanyisiwa.\u2019' },
    { n: 23, text: '\u2018Kambe loko ku ri ni mhaka ya rifu, u ta nyikela moya hi moya,\u2019' },
    { n: 24, text: '\u2018tihlo hi tihlo, meno hi meno, voko hi voko, milenge hi milenge,\u2019' },
    { n: 25, text: '\u2018ku hisiwa hi ku hisiwa, xilondzo hi xilondzo, ku biwa hi ku biwa.\u2019' },
    { n: 26, text: '\u2018Loko wanuna a ba tihlo ra nandza wa yena, kumbe tihlo ra nandza wa yena wa xisati, a ri onha, u ta n\u2019wi tshunxa leswaku a ya hlayiseka hikwalaho ka tihlo ra yena.\u2019' },
    { n: 27, text: '\u2018Loko a gongonyola meno ra nandza wa yena, kumbe meno ra nandza wa yena wa xisati, u ta n\u2019wi tshunxa leswaku a ya hlayiseka hikwalaho ka meno ra yena.\u2019' },
    { n: 28, text: '\u2018Loko homu yi ba wanuna kumbe wansati, a fa, homu yi ta gandiwa hi maribye, a yi nga dyiwi nyama ya yona; kambe n\u2019wini wa homu a a nga ri na nandzu.\u2019' },
    { n: 29, text: '\u2018Kambe loko homu a yi ri leyi ba-baka khale, naswona n\u2019wini wa yona a byeriwile, kambe a nga yi hlayisanga, kutani yi dlaya wanuna kumbe wansati, homu yi ta gandiwa hi maribye, naswona n\u2019wini wa yona u ta dlayiwa.\u2019' },
    { n: 30, text: '\u2018Loko a kombiwa ntsengo, u ta nyikela hinkwaswo leswi a nga ta n\u2019wi kombisa swona leswaku a kutsula moya wa yena.\u2019' },
    { n: 31, text: '\u2018Loko yi ba n\u2019wana wa jaha kumbe n\u2019wana wa xisati, va ta endla eka yena hilaha nawu lowu wu vulaka hakona.\u2019' },
    { n: 32, text: '\u2018Loko homu yi ba nandza wa xinuna kumbe nandza wa xisati, n\u2019wini wa yona u ta nyikela ntsengo wa xitsheke xa makume-manharhu (30) eka n\u2019wini wa nandza, kutani homu yi ta gandiwa hi maribye.\u2019' },
    { n: 33, text: '\u2018Loko wanuna a pfula xihlovo, kumbe a tsemba xihlovo, a nga xi funengeti, kutani homu kumbe mbongolo yi wela eka xona,\u2019' },
    { n: 34, text: '\u2018n\u2019wini wa xihlovo u ta hakela, u ta hakela ntsengo eka n\u2019wini wa xona, kutani xifuwo lexi feke xi ta va xa yena.\u2019' },
    { n: 35, text: '\u2018Loko homu ya wanuna yi ba homu ya muakelani wa yena, kutani yi fa, va ta xavisa homu leyi hanyaka, va avelana mali ya yona, va avelana ni leyi feke.\u2019' },
    { n: 36, text: '\u2018Kumbe loko swi tiviwile leswaku homu a yi ba-baka khale, naswona n\u2019wini wa yona a nga yi hlayisanga, u ta hakela homu hi homu, kutani leyi feke yi ta va ya yena.\u2019' },
  ],
  22: [
    { n: 1, text: '\u2018Loko wanuna a yiva homu kumbe nyimpfu, a yi tlhava kumbe a yi xavisa, u ta hakela homu hi tihomu ta ntlhanu, ni nyimpfu hi tinyimpfu ta mune.\u2019' },
    { n: 2, text: '\u2018Loko muyivi a kumiwa a fela etindlwini, a nga ri na nandzu wa ngati.\u2019' },
    { n: 3, text: '\u2018Loko dyambu ri humile ehenhla ka yena, ku ta va ni nandzu wa ngati; u ta hakela swinene; loko a nga na nchumu, u ta xavisiwa hikwalaho ka swilo leswi a nga swi yiva.\u2019' },
    { n: 4, text: '\u2018Loko a kumiwa a ha ri na nchumu lowu a nga wu yiva, hambi i homu, hambi i mbongolo, hambi i nyimpfu, a a hakela swimbirhi.\u2019' },
    { n: 5, text: '\u2018Loko wanuna a dyisa xifuwo xa yena ensin\u2019wini kumbe ensin\u2019wini ya vhinya, a xi tshika xi dyisa ensin\u2019wini ya munhu un\u2019wana, u ta hakela hi leswinene swa nsimu ya yena ni leswinene swa nsimu ya yena ya vhinya.\u2019' },
    { n: 6, text: '\u2018Loko ndzilo wu huma, wu tshwuka emimingwen, kutani miwiti ya koriandere kumbe nsimu ya koriandere kumbe nsimu yi hisiwa, loyi a nga tshwukisa ndzilo u ta hakela hinkwaswo.\u2019' },
    { n: 7, text: '\u2018Loko wanuna a nyika muakelani wa yena mali kumbe swilo leswaku a swi hlayisa, kutani swi yiviwa endlwini ya wanuna yoloye, loko muyivi a kumiwa, u ta hakela swimbirhi.\u2019' },
    { n: 8, text: '\u2018Loko muyivi a nga kumiwanga, n\u2019wini wa yindlu u ta tisiwa mahlweni ka Xikwembu, ku tiva loko a nga tshambulanga voko ra yena ehenhla ka swilo swa muakelani wa yena.\u2019' },
    { n: 9, text: '\u2018Ehenhla ka mhaka hinkwayo ya xidyoho, ehenhla ka homu, ehenhla ka mbongolo, ehenhla ka nyimpfu, ehenhla ka tinguvu, ehenhla ka nchumu wun\u2019wana lowu lahlekeke, loyi a nge: \u201cHi lowu\u201d, mhaka ya vona hinkwavo yi ta fika mahlweni ka Xikwembu; loyi Xikwembu xi nga ta n\u2019wi avanyisa, u ta hakela swimbirhi eka muakelani wa yena.\u2019' },
    { n: 10, text: '\u2018Loko wanuna a nyika muakelani wa yena mbongolo, kumbe homu, kumbe nyimpfu, kumbe xifuwo xin\u2019wana, leswaku a xi hlayisa, kutani xi fa, kumbe xi vaviseka, kumbe xi tekiwa hi nsele, ku nga ri na loyi a xi vonaka;\u2019' },
    { n: 11, text: '\u2018xihlambanyo xa Yehovha xi ta va exikarhi ka vona vambirhi, leswaku a nga tshambulanga voko ra yena ehenhla ka swilo swa muakelani wa yena; n\u2019wini wa xona u ta xi amukela, kutani a nga hakeli.\u2019' },
    { n: 12, text: '\u2018Kambe loko xi yiviwile eka yena, u ta xi hakela eka n\u2019wini wa xona.\u2019' },
    { n: 13, text: '\u2018Loko xi dlayiwile hi swiharhi, a a xi tise tanihi vumbhoni; a nga hakeli xifuwo lexi dlayiweke hi swiharhi.\u2019' },
    { n: 14, text: '\u2018Loko wanuna a lomba nchumu eka muakelani wa yena, kutani xi vaviseka kumbe xi fa, n\u2019wini wa xona a nga ri kona, u ta hakela swinene.\u2019' },
    { n: 15, text: '\u2018Loko n\u2019wini wa xona a ri kona, a nga hakeli; loko xi ri xilombi, xi ta ta hi ntsengo wa xona.\u2019' },
    { n: 16, text: '\u2018Loko wanuna a kanganyisa nhwana loyi a nga si tivisiwaka, a etlela na yena, u ta n\u2019wi teka a va nsati wa yena hi ku n\u2019wi hakela.\u2019' },
    { n: 17, text: '\u2018Loko tatana wa yena a ala ku n\u2019wi nyika yena, u ta hakela mali hi ku ya hi ntsengo wa vavasati lava nga vhanhwana.\u2019' },
    { n: 18, text: '\u2018U nga tshuki u pfumelela mulozi wansati ku hanya.\u2019' },
    { n: 19, text: '\u2018Loyi a etlelaka na xiharhi u ta dlayiwa.\u2019' },
    { n: 20, text: '\u2018Loyi a gandzelaka swikwembu swin\u2019wana, handle ka Yehovha ntsena, u ta dlayiwa.\u2019' },
    { n: 21, text: '\u2018U nga tshuki u xanisa muluveri hambi ku n\u2019wi tikela, hikuva mi vile valuveri etikweni ra Egipta.\u2019' },
    { n: 22, text: '\u2018U nga tshuki u xanisa mufelani hambi a ri n\u2019wana la nga riki na tatana.\u2019' },
    { n: 23, text: '\u2018Loko u va xanisa, va ta rila eka mina, ndzi ta twa rito ra vona;\u2019' },
    { n: 24, text: '\u2018kutani ku hlundzuka ka mina ku ta pfuka, ndzi ta mi dlaya hi banga; vana va n\u2019wina va ta va vafelani, ni vasati va n\u2019wina va ta va vafelani.\u2019' },
    { n: 25, text: '\u2018Loko u lomba vanhu va mina mali, lava va tshamaka na wena va ri swisiwana, u nga tshuki u va tanihi munhu loyi a lerisaka mali, mi nga tshuki mi va vekela ntsengo wa mali.\u2019' },
    { n: 26, text: '\u2018Loko u teka tinguvu ta muakelani wa wena tanihi nchumu wa vumbhoni, u ta n\u2019wi tlherisela tona loko dyambu ri nga si pela;\u2019' },
    { n: 27, text: '\u2018hikuva i nchumu wa yena ntsena, i tinguvu ta nhlonge ya yena, u ta etlela ha yoni; u ta etlela ha yini ke? Loko a rila eka mina, ndzi ta twa, hikuva ndzi ni musa.\u2019' },
    { n: 28, text: '\u2018U nga tshuki u rhukana Xikwembu, naswona u nga tshuki u rhukana khamba ra vanhu va wena.\u2019' },
    { n: 29, text: '\u2018U nga tshuki u hlwela ku nyikela ntsengo wa titsheke ta wena, ni ntsengo wa swilo swa wena; u ta nyikela mativula ya vana va wena va majaha eka mina.\u2019' },
    { n: 30, text: '\u2018U ta endla tano hi homu ya wena, ni hi tinyimpfu ta wena; masiku ya nkombo yi ta va na manana wa yona, hi siku ra vunkombo u ta yi nyikela eka mina.\u2019' },
    { n: 31, text: '\u2018Mi ta va vanhu va mina vo kwetsima; hikwalaho mi nga tshuki mi dya nyama leyi dlayiweke hi swiharhi, mi yi hoxela timbyana.\u2019' },
  ],
  23: [
    { n: 1, text: '\u2018U nga tshuki u hangalasa mahungu ya mavunwa; u nga tshuki u pfuna munhu wo homboloka hi ku va mbhoni ya mavunwa.\u2019' },
    { n: 2, text: '\u2018U nga tshuki u landza ntshungu wa vanhu leswaku u endla swo biha; naswona u nga tshuki u hlamula eka mhaka ya vuavanyisi hi ku landza ntshungu, leswaku u soholota nawu.\u2019' },
    { n: 3, text: '\u2018U nga tshuki u tsanwela xisiwana eka mhaka ya vuavanyisi.\u2019' },
    { n: 4, text: '\u2018Loko u kuma homu ya nala wa wena kumbe mbongolo ya yena yi lahlekile, u fanele u yi tlherisela eka yena.\u2019' },
    { n: 5, text: '\u2018Loko u vona mbongolo ya munhu loyi a ku vengaka yi wile ehansi ya ndzhwalo wa yona, u nga tshuki u n\u2019wi tshika; u fanele u n\u2019wi pfuna ku yi humesa.\u2019' },
    { n: 6, text: '\u2018U nga tshuki u soholota vuavanyisi bya xisiwana xa wena eka mhaka ya xona.\u2019' },
    { n: 7, text: '\u2018Tshika mhaka ya mavunwa, naswona u nga tshuki u dlaya munhu loyi a nga riki na nandzu, hikuva a ndzi nge n\u2019wi lweli loyi a endlaka swilo swo biha.\u2019' },
    { n: 8, text: '\u2018U nga tshuki u amukela ntsengo, hikuva ntsengo wu ba mahlo ya lava vonaka, wu soholota marito ya lava lulameke.\u2019' },
    { n: 9, text: '\u2018U nga tshuki u xanisa muluveri; hikuva mi tiva moya wa muluveri, tanihi leswi mi vileke valuveri etikweni ra Egipta.\u2019' },
    { n: 10, text: '\u2018Lembe ra tsevu u ta byala tiko ra wena, u hlengeleta mihandzu ya rona;\u2019' },
    { n: 11, text: '\u2018kambe hi lembe ra vunkombo u ta ri tshika, ri wisa, leswaku swisiwana swa vanhu va wena swi dya; naswona leswi va swi siyaka, swiharhi swa nhova swi ta swi dya. U ta endla tano hi nsimu ya wena ya vhinya ni hi nsimu ya wena ya olive.\u2019' },
    { n: 12, text: '\u2018Masiku ya tsevu u ta endla ntirho wa wena, kambe hi siku ra vunkombo u ta wisa, leswaku homu ya wena ni mbongolo ya wena swi wisa, naswona n\u2019wana wa nandza wa wena wa xisati ni muluveri va ta humesiwa va wisa.\u2019' },
    { n: 13, text: '\u2018Hinkwaswo leswi ndzi mi byeleke swona, hlayisani leswaku mi swi endla; mi nga tshuki mi vitana mavito ya swikwembu swin\u2019wana, naswona ma nga tshuki ma twala enon\u2019wini wa n\u2019wina.\u2019' },
    { n: 14, text: '\u2018Ku rhangeriwa kanharhu hi lembe mi ta ndzi khomela nkhuvo.\u2019' },
    { n: 15, text: '\u2018Mi ta hlayisa nkhuvo wa xinkwa lexi nga riki na comela; masiku ya nkombo mi ta dya xinkwa lexi nga riki na comela, hilaha ndzi mi leriseke hakona, hi nkarhi lowu vekiweke wa n\u2019weti wa Abibi, hikuva mi hume etikweni ra Egipta hi n\u2019weti wolowo; kambe a ku na munhu loyi a nga ta humelela mahlweni ka mina a ri loyi a nga riki na nchumu.\u2019' },
    { n: 16, text: '\u2018Ni nkhuvo wa ku tswariwa ka swilo, wa mintirho yo sungula ya swakudya swa n\u2019wina leswi mi swi byaleke ensin\u2019wini; ni nkhuvo wa ku hlengeleta hi ku hela ka lembe, loko mi hlengeleta mintirho ya n\u2019wina ensin\u2019wini.\u2019' },
    { n: 17, text: '\u2018Kanharhu hi lembe, vaxinuna hinkwavo va n\u2019wina va ta humelela mahlweni ka Yehovha Xikwembu.\u2019' },
    { n: 18, text: '\u2018U nga tshuki u nyikela ngati ya xitlhavelo xa mina xikan\u2019we ni xinkwa lexi nga na comela; naswona mafurha ya nkhuvo wa mina ma nga tshuki ma sala ku fikela nimixo.\u2019' },
    { n: 19, text: '\u2018Mintirho yo sungula ya mihandzu ya misava ya wena, u ta yi tisa endlwini ya Yehovha Xikwembu xa wena. U nga tshuki u sweka ximbutana hi ntswamba wa manana wa xona.\u2019' },
    { n: 20, text: '\u2018Vona, ndzi rhumela ntsumi mahlweni ka wena, leswaku yi ku hlayisa endleleni, yi ku yisa endhawini leyi ndzi yi lunghiseleke.\u2019' },
    { n: 21, text: '\u2018Tivonela mahlweni ka yona, u yingisela rito ra yona; u nga tshuki u yi hlundzukisa, hikuva a yi nge rivaleli ku tlula ka n\u2019wina; hikuva vito ra mina ri le ndzeni ka yona.\u2019' },
    { n: 22, text: '\u2018Kambe loko u yingisela rito ra yona swinene, u endla hinkwaswo leswi ndzi swi vulaka, ndzi ta va nala wa valala va wena, ndzi lwa ni lava va lwelaka na wena.\u2019' },
    { n: 23, text: '\u2018Hikuva ntsumi ya mina yi ta famba mahlweni ka wena, yi ku yisa eka Vaamori, ni Vahiti, ni Vaperizi, ni Vakanana, ni Vahevi, ni Vayebusi; kutani ndzi ta va lovisa.\u2019' },
    { n: 24, text: '\u2018U nga tshuki u nkhinsamela swikwembu swa vona, hambi ku va u swi tirhela, kumbe u landza mintirho ya vona; kambe u fanele u swi mbumbuluxa swinene, u fayetela swifaniso swa vona swa maribye.\u2019' },
    { n: 25, text: '\u2018Mi fanele mi tirhela Yehovha Xikwembu xa n\u2019wina, kutani a ta katekisa swakudya swa n\u2019wina ni mati ya n\u2019wina; naswona ndzi ta susa vuvabyi exikarhi ka n\u2019wina.\u2019' },
    { n: 26, text: '\u2018A ku nge vi na wansati loyi a nga ta huma vana hinkwavo, hambi ku va a nga tswali, etikweni ra wena; ndzi ta endla leswaku masiku ya vutomi bya wena ma tala.\u2019' },
    { n: 27, text: '\u2018Ndzi ta rhumela ku chava ka mina mahlweni ka wena, ndzi hlamarisa vanhu hinkwavo lava u nga ta hlangana na vona, ndzi ta endla leswaku valala hinkwavo va wena va ku fularhela hi nhlana.\u2019' },
    { n: 28, text: '\u2018Ndzi ta rhumela mimpfapfarhuti mahlweni ka wena, leti nga ta hlongola Vahevi, ni Vakanana, ni Vahiti mahlweni ka wena.\u2019' },
    { n: 29, text: '\u2018A ndzi nge va hlongoli mahlweni ka wena hi lembe rin\u2019we, leswaku tiko ri nga vi ri rhumbi, ni swiharhi swa nhova swi nga mi telela.\u2019' },
    { n: 30, text: '\u2018Ndzi ta va hlongola mahlweni ka wena hi katsongo-katsongo, ku fikela loko u tala, u teka tiko rolero.\u2019' },
    { n: 31, text: '\u2018Ndzi ta veka ndzilakano wa wena kusukela elwandle ra Xitswonga ku ya fika elwandle ra Vafilista, ni kusukela emananga ku ya fika enambyeni; hikuva ndzi ta nyikela vaaki va tiko evokweni ra wena, kutani u ta va hlongola mahlweni ka wena.\u2019' },
    { n: 32, text: '\u2018U nga tshuki u endla ntwanano na vona, kumbe ni swikwembu swa vona.\u2019' },
    { n: 33, text: '\u2018Va nga tshuki va tshama etikweni ra wena, leswaku va nga ku endli u dyoha eka mina; hikuva loko u tirhela swikwembu swa vona, swi ta va ntlhamu eka wena.\u2019' },
  ],
  24: [
    { n: 1, text: 'Kutani a ku eka Moxe: \u2018Tlhandluka eka Yehovha, wena, na Aroni, na Nadaba, na Abihu, ni vakulukumba va va-Israyele va makume-nkombo, mi nkhinsamela ekule.\u2019' },
    { n: 2, text: '\u2018Moxe ntsena u ta tshinela eka Yehovha; kambe vona va nga tshuki va tshinela, ni vanhu va nga tshuki va tlhandluka na yena.\u2019' },
    { n: 3, text: 'Moxe a ta, a byela vanhu marito hinkwavo ya Yehovha ni milawu hinkwayo; vanhu hinkwavo va hlamula hi rito rin\u2019we, va ku: \u2018Hinkwaswo leswi Yehovha a swi vuleke, hi ta swi endla.\u2019' },
    { n: 4, text: 'Moxe a tsala marito hinkwavo ya Yehovha, a pfuka hi mixo, a aka alitari ehansi ka ntshava, ni mhandzi ya maribye ya khume-mbirhi, hi ku ya hi tinxaka ta khume-mbirhi ta Israyele.' },
    { n: 5, text: 'A rhuma majaha ya vana va Israyele, va nyikela magandzelo ya ku hisiwa, ni magandzelo ya ku rhula, ya tihomu eka Yehovha.' },
    { n: 6, text: 'Moxe a teka hafu ya ngati, a yi chela emakwetsini, hafu yin\u2019wana ya ngati a yi fafata ehenhla ka alitari.' },
    { n: 7, text: 'A teka buku ya ntwanano, a yi hlaya mahlweni ka vanhu; va ku: \u2018Hinkwaswo leswi Yehovha a swi vuleke, hi ta swi endla, hi ta yingisela.\u2019' },
    { n: 8, text: 'Moxe a teka ngati, a yi fafata ehenhla ka vanhu, a ku: \u2018Vona, i ngati ya ntwanano lowu Yehovha a wu endleke na n\u2019wina hi ku ya hi marito lawa hinkwawo.\u2019' },
    { n: 9, text: 'Moxe a tlhandluka, na Aroni, na Nadaba, na Abihu, ni vakulukumba va va-Israyele va makume-nkombo;' },
    { n: 10, text: 'va vona Xikwembu xa Israyele; ehansi ka milenge ya xona a ku ri tanihi xitirho xa safiro, ni tanihi ntumbuluko wa matilo hi ku kwetsima ka wona.' },
    { n: 11, text: 'A nga tshambulanga voko ra yena ehenhla ka vakulukumba va vana va Israyele; va vona Xikwembu, kutani va dya ni ku nwa.' },
    { n: 12, text: 'Yehovha a ku eka Moxe: \u2018Tlhandlukela eka mina entshaveni, u va kona; ndzi ta ku nyika maribye ya milawu, ni milawu leyi ndzi yi tsaleke, leswaku u ta dyondzisa vona.\u2019' },
    { n: 13, text: 'Moxe a pfuka, na Yoxuwa mutirheli wa yena, Moxe a tlhandlukela entshaveni ya Xikwembu.' },
    { n: 14, text: 'A ku eka vakulukumba: \u2018Mi hi rindzela laha, ku fikela loko hi vuya eka n\u2019wina; vonani, Aroni na Huri va na n\u2019wina; loyi a nga ni mhaka, a a famba eka vona.\u2019' },
    { n: 15, text: 'Moxe a tlhandlukela entshaveni, mupapa wa maru wu funengeta ntshava.' },
    { n: 16, text: 'Kwetsima ka Yehovha ku tshama entshaveni ya Sinayi, mupapa wa maru wu yi funengeta hi masiku ya tsevu; hi siku ra vunkombo a vitana Moxe exikarhi ka mupapa wa maru.' },
    { n: 17, text: 'Ku vonakala ka kwetsima ka Yehovha a ku ri tanihi ndzilo lowu hisaka, enhlokweni ya ntshava, mahlweni ka vana va Israyele.' },
    { n: 18, text: 'Moxe a nghena exikarhi ka mupapa wa maru, a tlhandlukela entshaveni; Moxe a va entshaveni hi masiku ya mune-ntlhanu ni mune-vusiku.' },
  ],
  25: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '\u2018Byela vana va Israyele leswaku va ndzi tisa minyikelo; un\u2019wana ni un\u2019wana loyi mbilu ya yena yi n\u2019wi susumetaka ku nyika, mi ta amukela minyikelo ya mina.\u2019' },
    { n: 3, text: '\u2018Lawa i minyikelo leyi mi nga ta yi amukela eka vona: nsuku, ni silivhere, ni koporo,\u2019' },
    { n: 4, text: '\u2018ni ntsemba wa vumfumi, ni ntsemba wa ntswamba, ni ntsemba wa xichave, ni ntsalu wa rila, ni nhlonge ya mbuti,\u2019' },
    { n: 5, text: '\u2018ni nhlonge ya tihomu ta ntswamba leti khavisiweke, ni nhlonge ya tibadger, ni timhandzi ta xitachi,\u2019' },
    { n: 6, text: '\u2018ni mafurha ya rivoningo, ni swirungo swa mafurha yo kwetsima ni swirungo swa nun\u2019hwelo,\u2019' },
    { n: 7, text: '\u2018ni maribye ya onyx, ni maribye yo khavisa ehenhla ka ephod, ni ehenhla ka xifuva.\u2019' },
    { n: 8, text: '\u2018Naswona va ta ndzi akela ndhawu yo kwetsima, leswaku ndzi ta tshama exikarhi ka vona.\u2019' },
    { n: 9, text: '\u2018Hi ku ya hi hinkwaswo leswi ndzi ku kombaka, xifaniso xa tabernakela, ni xifaniso xa hinkwaswo leswi nga eka swona, mi ta endla tano.\u2019' },
    { n: 10, text: '\u2018Va ta endla areka ya mhandzi ya xitachi; ku leha ka yona i tinyanya timbirhi ni hafu, ni ku anama ka yona i tinyanya ta n\u2019we ni hafu, ni ku tlakuka ka yona i tinyanya ta n\u2019we ni hafu.\u2019' },
    { n: 11, text: '\u2018U ta yi ambexa hi nsuku lowo tengamela, endzeni ni le handle u ta yi ambexa, u ta endla nkhombolo wa nsuku ku rhendzela.\u2019' },
    { n: 12, text: '\u2018U ta yi endlela switirho swa nsuku swa mune, u swi veka emakumu ya yona ya mune; switirho swimbirhi hi tlhelo rin\u2019we, ni switirho swimbirhi hi tlhelo rin\u2019we.\u2019' },
    { n: 13, text: '\u2018U ta endla timhandzi ta mhandzi ya xitachi, u ti ambexa hi nsuku.\u2019' },
    { n: 14, text: '\u2018U ta nghenisa timhandzi eswitirhweni, ematlhelo ya areka, leswaku areka yi rhwaliwa ha tona.\u2019' },
    { n: 15, text: '\u2018Timhandzi ti ta tshama eswitirhweni swa areka; a ti nge humi eka yona.\u2019' },
    { n: 16, text: '\u2018U ta veka endzeni ka areka vumbhoni lebyi ndzi nga ta ku nyika byona.\u2019' },
    { n: 17, text: '\u2018U ta endla xifunengeto xa nsuku lowo tengamela; ku leha ka xona i tinyanya timbirhi ni hafu, ni ku anama ka xona i tinyanya ta n\u2019we ni hafu.\u2019' },
    { n: 18, text: '\u2018U ta endla makerubi mambirhi ya nsuku, hi ku ma fula u ta ma endla emakumu mambirhi ya xifunengeto.\u2019' },
    { n: 19, text: '\u2018Makerubi man\u2019we emakumu lawa, ni kerubi rin\u2019we emakumu lawa; hi ku ya hi xifunengeto, mi ta endla makerubi emakumu ya yona mambirhi.\u2019' },
    { n: 20, text: '\u2018Makerubi ma ta andlala timpapa ta wona ehenhla, ma funengeta xifunengeto hi timpapa ta wona, ma langutana; mahlo ya makerubi ma ta languta ehenhla ka xifunengeto.\u2019' },
    { n: 21, text: '\u2018U ta veka xifunengeto ehenhla ka areka; endzeni ka areka u ta veka vumbhoni lebyi ndzi nga ta ku nyika byona.\u2019' },
    { n: 22, text: '\u2018Kwalaho ndzi ta hlangana na wena, ndzi ta vulavula na wena ndzi ri ehenhla ka xifunengeto, exikarhi ka makerubi mambirhi, lawa ma nga ehenhla ka areka ya vumbhoni, hinkwaswo leswi ndzi nga ta ku lerisa swona eka vana va Israyele.\u2019' },
    { n: 23, text: '\u2018U ta endla tafula ra mhandzi ya xitachi; ku leha ka rona i tinyanya timbirhi, ku anama ka rona i tinyanya ta n\u2019we, ni ku tlakuka ka rona i tinyanya ta n\u2019we ni hafu.\u2019' },
    { n: 24, text: '\u2018U ta ri ambexa hi nsuku lowo tengamela, u ta ri endlela nkhombolo wa nsuku ku rhendzela.\u2019' },
    { n: 25, text: '\u2018U ta ri endlela nkombiso wa xirhendzevutana, wa tinyanya ta mune, u ta ri endlela nkhombolo wa nsuku ku rhendzela nkombiso wa wona.\u2019' },
    { n: 26, text: '\u2018U ta ri endlela switirho swa nsuku swa mune, u swi veka emakumu ya yona ya mune, emakumu ya milenge ya mune.\u2019' },
    { n: 27, text: '\u2018Switirho swi ta va ekusuhi ni nkombiso, ku va swiyindlu swa timhandzi to rhwala tafula.\u2019' },
    { n: 28, text: '\u2018U ta endla timhandzi hi mhandzi ya xitachi, u ti ambexa hi nsuku, leswaku tafula ri rhwaliwa ha tona.\u2019' },
    { n: 29, text: '\u2018U ta endla swibye swa rona, ni swikhavu swa rona, ni swikho swa rona, ni swibye swa swinwelo swa matumbuluko; hi nsuku lowo tengamela u ta swi endla.\u2019' },
    { n: 30, text: '\u2018U ta veka ehenhla ka tafula xinkwa xa ku kombisiwa mahlweni ka mina hi minkarhi hinkwayo.\u2019' },
    { n: 31, text: '\u2018U ta endla xitirho xa rivoningo xa nsuku lowo tengamela; hi ku fula u ta endla xitirho xa rivoningo; xirhundzu xa xona, ni miri wa xona, ni swibye swa xona, ni swirhundzu swa xona, ni swiluva swa xona, swi ta va xikan\u2019we na xona.\u2019' },
    { n: 32, text: '\u2018Timitsu ta tsevu ti ta huma ematlhelo ya xona; timitsu tinharhu ta xitirho xa rivoningo ti ta huma etlhelweni rin\u2019we, ni timitsu tinharhu ta xitirho xa rivoningo ti ta huma etlhelweni rin\u2019we.\u2019' },
    { n: 33, text: '\u2018Timitsu tinharhu ti ta va tanihi swiluva swa miluva ya almond, xirhundzu ni xiluva etlhelweni rin\u2019we, ni timitsu tinharhu tanihi swiluva swa miluva ya almond, xirhundzu ni xiluva etlhelweni rin\u2019we; tano ti ta va timitsu ta tsevu leti humaka exitaleni xa xitirho xa rivoningo.\u2019' },
    { n: 34, text: '\u2018Exitaleni xa xitirho xa rivoningo ku ta va ni swirhundzu swa mune tanihi swiluva swa miluva ya almond, ni swirhundzu swa swona ni swiluva swa swona.\u2019' },
    { n: 35, text: '\u2018Ku ta va ni xirhundzu ehansi ka timitsu timbirhi ta xitirho, xirhundzu ehansi ka timitsu timbirhi ta xitirho, xirhundzu ehansi ka timitsu timbirhi ta xitirho, hi ku ya hi timitsu ta tsevu leti humaka exitaleni xa xitirho xa rivoningo.\u2019' },
    { n: 36, text: '\u2018Swirhundzu swa swona ni timitsu ta swona swi ta va xikan\u2019we na xona; hinkwaswo swi ta va xikan\u2019we, i nsuku lowo tengamela lowu furiweke.\u2019' },
    { n: 37, text: '\u2018U ta endla rivoningo ra xona ra nkombo; va ta veka rivoningo ra xona, leswaku ri voninga emahlweni ka xona.\u2019' },
    { n: 38, text: '\u2018Swikhomo swa xona ni swibye swa xona swa tshevhu, swi ta va hi nsuku lowo tengamela.\u2019' },
    { n: 39, text: '\u2018Hi talenta ya nsuku lowo tengamela u ta endla xitirho xa rivoningo ni swibye swa xona hinkwaswo.\u2019' },
    { n: 40, text: '\u2018Vona, u swi endla hi ku ya hi xifaniso lexi u xi kombiweke entshaveni.\u2019' },
  ],
  26: [
    { n: 1, text: '\u2018Tabernakela u ta yi endla hi malapi ya khume ya ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave; u ta endla makerubi hi ku ma fula, hi ntirho wa ntlhandlhi.\u2019' },
    { n: 2, text: '\u2018Ku leha ka lapi rin\u2019we i tinyanya ta makume-mbirhi ni nhungu, ni ku anama ka lapi rin\u2019we i tinyanya ta mune; malapi hinkwawo ma ta va ni mpimo wun\u2019we.\u2019' },
    { n: 3, text: '\u2018Malapi ya ntlhanu ma ta va lama hlanganisiweke, ni malapi man\u2019wana ya ntlhanu ma ta va lama hlanganisiweke.\u2019' },
    { n: 4, text: '\u2018U ta endla mahlwa ya ntsemba wa vumfumi ematlhelo ya lapi rin\u2019we, exihlameni xa nhlanganiso; u ta endla tano hi lapi ro hetelela erivaleni ra ntlhanu wa malapi.\u2019' },
    { n: 5, text: '\u2018U ta endla mahlwa ya makume-ntlhanu elapi rin\u2019we, u ta endla mahlwa ya makume-ntlhanu emakumu ya lapi leri nga erivaleni ra ntlhanu wa malapi; mahlwa ma ta langutana.\u2019' },
    { n: 6, text: '\u2018U ta endla swikhomo swa nsuku swa makume-ntlhanu, u hlanganisa malapi hi swikhomo, leswaku tabernakela yi va yin\u2019we.\u2019' },
    { n: 7, text: '\u2018U ta endla malapi ya nhlonge ya mbuti ku va ntsimba ehenhla ka tabernakela; u ta endla malapi ya khume-n\u2019we.\u2019' },
    { n: 8, text: '\u2018Ku leha ka lapi rin\u2019we i tinyanya ta makume-ntlhanu, ni ku anama ka lapi rin\u2019we i tinyanya ta mune; malapi ya khume-n\u2019we ma ta va ni mpimo wun\u2019we.\u2019' },
    { n: 9, text: '\u2018U ta hlanganisa malapi ya ntlhanu hi voxe, ni malapi ya tsevu hi voxe, u ta petsa lapi ra vutsevu mahlweni ka tabernakela.\u2019' },
    { n: 10, text: '\u2018U ta endla mahlwa ya makume-ntlhanu elapi rin\u2019we ra nhlanganiso, ni mahlwa ya makume-ntlhanu elapi rin\u2019we ra nhlanganiso.\u2019' },
    { n: 11, text: '\u2018U ta endla swikhomo swa koporo swa makume-ntlhanu, u nghenisa swikhomo mahlweni, u hlanganisa ntsimba leswaku yi va yin\u2019we.\u2019' },
    { n: 12, text: '\u2018Loku ku salaka ehenhla ka malapi ya ntsimba, hafu ya lapi leri salaka yi ta va ehenhla ka tabernakela.\u2019' },
    { n: 13, text: '\u2018Nhlonge ya lapi leri salaka, tinyanya ta mune etlhelweni rin\u2019we ni tinyanya ta mune etlhelweni rin\u2019we, yi ta funengeta tabernakela.\u2019' },
    { n: 14, text: '\u2018U ta endla xifunengeto xa nhlonge ya tihomu ta ntswamba leti khavisiweke, ni xifunengeto xa nhlonge ya tibadger ehenhla.\u2019' },
    { n: 15, text: '\u2018U ta endla makhumbi ya tabernakela hi mhandzi ya xitachi, ya yima.\u2019' },
    { n: 16, text: '\u2018Ku leha ka mhandzi i tinyanya ta khume, ni ku anama ka mhandzi i tinyanya ta n\u2019we ni hafu.\u2019' },
    { n: 17, text: '\u2018Mhandzi yin\u2019we ni yin\u2019we yi ta va ni swikhomo swimbirhi, swi hlanganisiweke; u ta endla tano hi makhumbi hinkwawo ya tabernakela.\u2019' },
    { n: 18, text: '\u2018U ta endla makhumbi ya tabernakela, makhumbi ya makume-mbirhi etlhelweni ra dzonga.\u2019' },
    { n: 19, text: '\u2018U ta endla swisekelo swa silivhere swa makume-mune ehansi ka makhumbi ya makume-mbirhi, swisekelo swimbirhi ehansi ka mhandzi yin\u2019we, ni swisekelo swimbirhi ehansi ka mhandzi yin\u2019we.\u2019' },
    { n: 20, text: '\u2018Etlhelweni ra n\u2019walungu ra tabernakela, makhumbi ya makume-mbirhi;\u2019' },
    { n: 21, text: '\u2018ni swisekelo swa silivhere swa makume-mune, swisekelo swimbirhi ehansi ka mhandzi yin\u2019we.\u2019' },
    { n: 22, text: '\u2018Emakumu ya tabernakela etlhelweni ra vupela-dyambu u ta endla makhumbi ya ntlhanu.\u2019' },
    { n: 23, text: '\u2018U ta endla makhumbi mambirhi emakumu ya tabernakela.\u2019' },
    { n: 24, text: '\u2018Ma ta va ma hlanganisiweke ehansi, ma ta va ma hlanganisiweke ehenhla hi xikhomo xin\u2019we; ma ta va tano hi mambirhi ya wona.\u2019' },
    { n: 25, text: '\u2018Ma ta va makhumbi ya nhungu, ni swisekelo swa silivhere swa khume-mune, swisekelo swimbirhi ehansi ka mhandzi yin\u2019we.\u2019' },
    { n: 26, text: '\u2018U ta endla timhandzi ta mhandzi ya xitachi, ya ntlhanu emakhumbini ya tlhelo rin\u2019we ra tabernakela,\u2019' },
    { n: 27, text: '\u2018ni timhandzi ta ntlhanu emakhumbini ya tlhelo rin\u2019we ra tabernakela, ni timhandzi ta ntlhanu emakhumbini ya tlhelo ra vupela-dyambu.\u2019' },
    { n: 28, text: '\u2018Mhandzi ya le xikarhi yi ta hundza emakhumbini, yi suka etlhelweni rin\u2019we ku ya eka rin\u2019we.\u2019' },
    { n: 29, text: '\u2018U ta ambexa makhumbi hi nsuku, u ta endla swikhomo swa nsuku swa timhandzi, u ta ambexa timhandzi hi nsuku.\u2019' },
    { n: 30, text: '\u2018U ta yimisa tabernakela hi xifaniso lexi u xi kombiweke entshaveni.\u2019' },
    { n: 31, text: '\u2018U ta endla nkhombolo hi ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave, u endla makerubi hi ntirho wa ntlhandlhi.\u2019' },
    { n: 32, text: '\u2018U ta wu hayeka ehenhla ka timhandzi ta mhandzi ya xitachi, ti ambexiweke hi nsuku, ni swikhomo swa nsuku, ehenhla ka swisekelo swa silivhere swa mune.\u2019' },
    { n: 33, text: '\u2018U ta hayeka nkhombolo ehansi ka swikhomo, u nghenisa areka ya vumbhoni endzeni ka nkhombolo; nkhombolo wu ta mi hambanisela ndhawu yo kwetsima ni ya kwetsima swinene.\u2019' },
    { n: 34, text: '\u2018U ta veka xifunengeto ehenhla ka areka ya vumbhoni endhawini yo kwetsima swinene.\u2019' },
    { n: 35, text: '\u2018U ta veka tafula ehandle ka nkhombolo, ni rivoningo etlhelweni ra dzonga ra tabernakela.\u2019' },
    { n: 36, text: '\u2018U ta endla nkhombolo emunyangweni wa ntsimba hi ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave, hi ku rhunga.\u2019' },
    { n: 37, text: '\u2018U ta endla timhandzi ta mhandzi ya xitachi, u ti ambexa hi nsuku, ni swikhomo swa nsuku swa ntlhanu.\u2019' },
  ],
  27: [
    { n: 1, text: '\u2018U ta endla alitari ya mhandzi ya xitachi, ya tinyanya ta ntlhanu, ya tinyanya ta ntlhanu, yi ta va ya xirhendzevutana, ni ku tlakuka ka yona i tinyanya ta nhungu.\u2019' },
    { n: 2, text: '\u2018U ta endla timhondzo ta yona emakumu ya yona ya mune, timhondzo ta yona ti ta va xikan\u2019we na yona, u ta yi ambexa hi koporo.\u2019' },
    { n: 3, text: '\u2018U ta endla swibye swa yona, ni swikhavu swa yona, ni swikho swa yona, ni swibye swa yona swa ndzilo; swibye hinkwaswo u ta swi endla hi koporo.\u2019' },
    { n: 4, text: '\u2018U ta yi endlela xikhomo xa koporo, hi ntirho wa mhandzi, ni swikhomo swa koporo swa mune emakumu ya yona ya mune.\u2019' },
    { n: 5, text: '\u2018U ta yi veka ehansi ka nkhombolo wa alitari, leswaku xikhomo xi va exikarhi ka alitari.\u2019' },
    { n: 6, text: '\u2018U ta endla timhandzi ta alitari, timhandzi ta mhandzi ya xitachi, u ti ambexa hi koporo.\u2019' },
    { n: 7, text: '\u2018Timhandzi ti ta nghenisiwa eswikhomweni, leswaku ti va etlhelweni ra alitari loko yi rhwaliwa.\u2019' },
    { n: 8, text: '\u2018U ta endla alitari ya mapuranka, ya mune wa matlhelo, hi ku ya hi xifaniso lexi u xi kombiweke entshaveni.\u2019' },
    { n: 9, text: '\u2018U ta endla rivale ra tabernakela, etlhelweni ra dzonga, hi malapi ya ntsemba wa vumfumi, ya tinyanya ta dzana.\u2019' },
    { n: 10, text: '\u2018Ni mhandzi ya makume-mbirhi, ni swisekelo swa koporo swa makume-mbirhi, ni swikhomo swa silivhere swa timhandzi.\u2019' },
    { n: 11, text: '\u2018Hi tlhelo ra n\u2019walungu hi ku ya hi ku leha ka rona, malapi ya tinyanya ta dzana, ni timhandzi ta makume-mbirhi, ni swisekelo swa koporo swa makume-mbirhi.\u2019' },
    { n: 12, text: '\u2018Ni rivale etlhelweni ra vupela-dyambu, malapi ya tinyanya ta ntlhanu, ni timhandzi ta ntlhanu, ni swisekelo swa ntlhanu.\u2019' },
    { n: 13, text: '\u2018Ni tlhelo ra vuxa hi ku anama ka rona, malapi ya tinyanya ta ntlhanu.\u2019' },
    { n: 14, text: '\u2018Malapi ya tinyanya ta ntlhanu etlhelweni rin\u2019we, ni timhandzi ta nhungu, ni swisekelo swa nhungu.\u2019' },
    { n: 15, text: '\u2018Ni etlhelweni rin\u2019we malapi ya tinyanya ta ntlhanu, ni timhandzi ta nhungu, ni swisekelo swa nhungu.\u2019' },
    { n: 16, text: '\u2018Ni emunyangweni wa rivale nkhombolo wa tinyanya ta ntlhanu, hi ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave, hi ku rhunga; ni timhandzi ta mune, ni swisekelo swa mune.\u2019' },
    { n: 17, text: '\u2018Timhandzi hinkwato ta rivale ti ta va ni swikhomo swa silivhere, ni swisekelo swa koporo.\u2019' },
    { n: 18, text: '\u2018Ku leha ka rivale tinyanya ta dzana, ni ku anama ka rona tinyanya ta ntlhanu, ni ku tlakuka ka rona tinyanya ta ntlhanu, hi ntsemba wa vumfumi, ni swisekelo swa koporo.\u2019' },
    { n: 19, text: '\u2018Switirho hinkwaswo swa tabernakela hi ntirho wa yona, ni swikhomo swa rivale hinkwaswo, swi ta va hi koporo.\u2019' },
    { n: 20, text: '\u2018U ta lerisa vana va Israyele leswaku va ku tisele mafurha ya olive yo kwetsima, leswaku rivoningo ri tshama ri ri kusuhi.\u2019' },
    { n: 21, text: '\u2018Etabernakela ya nhlanganiso, ehandle ka nkhombolo wa vumbhoni, Aroni ni vana va yena va ta ri hlayisa kusukela nimixo ku fikela nimadyambu mahlweni ka Yehovha; nawu lowu wu ta va hilaha ku nga heriki eka vana va Israyele.\u2019' },
  ],
  28: [
    { n: 1, text: '\u2018U ta tisa Aroni makwavo, ni vana va yena exikarhi ka vana va Israyele, leswaku va va vaprista eka mina; Aroni, na Nadaba, na Abihu, na Eliyezere, na Itamari, vana va Aroni.\u2019' },
    { n: 2, text: '\u2018U ta endla tinguvu to kwetsima eka Aroni makwavo, to dzunisa ni to sasekisa.\u2019' },
    { n: 3, text: '\u2018U ta vulavula ni hinkwavo lava va tlhariheke, lava ndzi va tateke hi moya wa vutlhari, leswaku va endla tinguvu ta Aroni, leswaku a va muprista eka mina.\u2019' },
    { n: 4, text: '\u2018Lawa i tinguvu leti va nga ta ti endla: xifuva, ni ephod, ni nkhombolo, ni nkhombolo wa ntlhandlhi, ni xihuku, ni bhande; va ta endla tinguvu to kwetsima eka Aroni makwavo, ni vana va yena, leswaku a va muprista eka mina.\u2019' },
    { n: 5, text: '\u2018Va ta teka nsuku, ni ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave.\u2019' },
    { n: 6, text: '\u2018Va ta endla ephod hi nsuku, ni ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave, hi ntirho wa ntlhandlhi.\u2019' },
    { n: 7, text: '\u2018Yi ta va ni swikhomo swimbirhi, swi hlanganisiweke emakumu ya yona mambirhi.\u2019' },
    { n: 8, text: '\u2018Ni bhande ra ephod, leri nga ehenhla ka yona, ri ta va hi ntirho wun\u2019we, hi nsuku, ni ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave.\u2019' },
    { n: 9, text: '\u2018U ta teka maribye mambirhi ya onyx, u tsalela eka wona mavito ya vana va Israyele:\u2019' },
    { n: 10, text: '\u2018mavito ya ntlhanu hi ribye rin\u2019we, ni mavito ya ntlhanu hi ribye rin\u2019we, hi ku landzelana ka ku tswariwa ka vona.\u2019' },
    { n: 11, text: '\u2018Hi ntirho wa muvuli wa maribye, tanihi ku tsala ka mfungho, u ta tsala mavito ya vana va Israyele ehenhla ka maribye mambirhi, u ma veka eswikhomweni swa nsuku.\u2019' },
    { n: 12, text: '\u2018U ta veka maribye mambirhi ehenhla ka swikhomo swa ephod, maribye ya vutsundzuxo eka vana va Israyele; Aroni u ta rhwala mavito ya vona mahlweni ka Yehovha ehenhla ka mabye mambirhi ya vutsundzuxo.\u2019' },
    { n: 13, text: '\u2018U ta endla swikhomo swa nsuku,\u2019' },
    { n: 14, text: '\u2018ni swikhomo swimbirhi swa nsuku lowu tengamela, swi fana ni ntsimbirhi hi ntirho wa ku rhunga, u veka swikhomo swa ku rhunga ehenhla ka swikhomo.\u2019' },
    { n: 15, text: '\u2018U ta endla xifuva xa vuavanyisi hi ntirho wa ntlhandlhi; u ta xi endla hi nsuku, ni ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave.\u2019' },
    { n: 16, text: '\u2018Xi ta va xa mune wa matlhelo, xi phutsiwile; tinyanya ta n\u2019we ku leha ka xona, ni tinyanya ta n\u2019we ku anama ka xona.\u2019' },
    { n: 17, text: '\u2018U ta veka ehenhla ka xona swiphemu swa maribye swa mune: ribye ra sardius, ni topaz, ni emerald, i swiphemu swa mune.\u2019' },
    { n: 18, text: '\u2018Ni xiphemu xa vumbirhi: turquoise, ni sapphire, ni diamond.\u2019' },
    { n: 19, text: '\u2018Ni xiphemu xa vunharhu: jacinth, ni agate, ni amethyst.\u2019' },
    { n: 20, text: '\u2018Ni xiphemu xa mune: beryl, ni onyx, ni jasper; swi ta va swi vekiwe swikhomweni swa nsuku.\u2019' },
    { n: 21, text: '\u2018Maribye ma ta va hi mavito ya vana va Israyele, khume-mbirhi hi mavito ya vona, hi ku tsala ka mfungho; rin\u2019we ni rin\u2019we ri ta va ni vito ra wona eka tinxaka ta khume-mbirhi.\u2019' },
    { n: 22, text: '\u2018U ta endla ehenhla ka xifuva swikhomo swa ku rhunga, swa nsuku lowu tengamela.\u2019' },
    { n: 23, text: '\u2018U ta endla ehenhla ka xifuva swikhomo swimbirhi swa nsuku, u veka swikhomo swimbirhi emakumu mambirhi ya xifuva.\u2019' },
    { n: 24, text: '\u2018U ta veka swikhomo swimbirhi swa nsuku emakumu mambirhi ya xifuva.\u2019' },
    { n: 25, text: '\u2018Swikhomo swimbirhi u ta swi veka ehenhla ka swikhomo swimbirhi, u swi veka emakumu ya ephod.\u2019' },
    { n: 26, text: '\u2018U ta endla swikhomo swimbirhi swa nsuku, u swi veka emakumu mambirhi ya xifuva, etlhelweni ra ephod.\u2019' },
    { n: 27, text: '\u2018U ta endla swikhomo swimbirhi swa nsuku, u swi veka emakumu mambirhi ya ephod, etlhelweni ra bhande.\u2019' },
    { n: 28, text: '\u2018Va ta hlanganisa xifuva ni swikhomo swa ephod hi ntsemba wa ntswamba, leswaku xi va ehenhla ka bhande ra ephod.\u2019' },
    { n: 29, text: '\u2018Aroni u ta rhwala mavito ya vana va Israyele exifubeni xa vuavanyisi mahlweni ka Yehovha, tanihi vutsundzuxo hi minkarhi hinkwayo.\u2019' },
    { n: 30, text: '\u2018U ta veka Urim ni Tummim exifubeni xa vuavanyisi, leswaku swi va ehenhla ka mbilu ya Aroni, loko a tshinela mahlweni ka Yehovha; Aroni u ta rhwala vuavanyisi bya vana va Israyele ehenhla ka mbilu ya yena mahlweni ka Yehovha hi minkarhi hinkwayo.\u2019' },
    { n: 31, text: '\u2018U ta endla nkhombolo wa ephod hi ntsemba wa ntswamba ntsena.\u2019' },
    { n: 32, text: '\u2018Yi ta va ni mbilu ehenhla, ni nkhombolo wu ta va wa ku rhunga, tanihi mbilu ya xihuku, leswaku yi nga handzuki.\u2019' },
    { n: 33, text: '\u2018Ehenhla ka xifuva u ta endla timagranata ta ntsemba wa ntswamba, ni ntsemba wa vumfumi, ni ntsalu wa rila, ku rhendzela; ni tinsimbiri ta nsuku exikarhi ka tona.\u2019' },
    { n: 34, text: '\u2018Ntsimbiri wa nsuku ni timagranata, ntsimbiri wa nsuku ni timagranata, ehenhla ka xifuva ku rhendzela.\u2019' },
    { n: 35, text: '\u2018Aroni u ta yi ambara loko a tirha, rito ra ntsimbiri ri ta twala loko a nghena endhawini yo kwetsima mahlweni ka Yehovha, ni loko a huma, leswaku a nga fi.\u2019' },
    { n: 36, text: '\u2018U ta endla xifuwu xa nsuku lowo tengamela, u tsala ehenhla ka xona: \u201cKu Kwetsima ka Yehovha.\u201d\u2019' },
    { n: 37, text: '\u2018U ta xi veka hi ntsemba wa ntswamba ehenhla ka xihuku.\u2019' },
    { n: 38, text: '\u2018Xi ta va ehenhla ka mbilu ya Aroni, Aroni u ta rhwala nandzu wa swilo leswi kwetsimaka leswi vana va Israyele va nga ta swi nyikela; xi ta va ehenhla ka mbilu ya yena hi minkarhi hinkwayo, leswaku va amukeleka mahlweni ka Yehovha.\u2019' },
    { n: 39, text: '\u2018U ta rhunga nkhombolo hi ntsemba wa vumfumi, u ta endla xihuku hi ntsemba wa vumfumi, u ta endla bhande hi ntirho wa ku rhunga.\u2019' },
    { n: 40, text: '\u2018U ta endla nkhombolo eka vana va Aroni, u ta va endlela mabhante, u ta va endlela swihuku, swa ku dzunisa ni ku sasekisa.\u2019' },
    { n: 41, text: '\u2018U ta ambexa Aroni makwavo, ni vana va yena, u ta va tota, u ta va kwetsimisa, leswaku va va vaprista eka mina.\u2019' },
    { n: 42, text: '\u2018U ta va endlela mabhulukwe ya nhlonge, leswaku va funengeta mbilu ya vona; ma ta va kusukela elun\u2019wini ku ya fika emilengeni.\u2019' },
    { n: 43, text: '\u2018Ma ta va ehenhla ka Aroni ni vana va yena, loko va nghena etabernakela ya nhlanganiso, kumbe loko va tshinela ealitari, leswaku va tirha endhawini yo kwetsima, leswaku va nga vi na nandzu, va fa; nawu lowu wu ta va hilaha ku nga heriki eka yena ni vana va yena endzhaku ka yena.\u2019' },
  ],
  29: [
    { n: 1, text: '\u2018Leri i rito leri u nga ta va endla ha rona, leswaku va va vaprista eka mina: teka homu yin\u2019we, ni tinyimpfu timbirhi leti nga riki na xilondzo.\u2019' },
    { n: 2, text: '\u2018Ni xinkwa lexi nga riki na comela, ni mikate leyi nga riki na comela, leyi hlanganisiweke hi mafurha, ni swinkwa leswi nga riki na comela, leswi totiweke hi mafurha; u ta swi endla hi mapa ya koriandere.\u2019' },
    { n: 3, text: '\u2018U ta swi veka exirhundzwini xin\u2019we, u swi tisa exirhundzwini, ni homu ni tinyimpfu timbirhi.\u2019' },
    { n: 4, text: '\u2018U ta tisa Aroni ni vana va yena emunyangweni wa tabernakela ya nhlanganiso, u va hlantswa hi mati.\u2019' },
    { n: 5, text: '\u2018U ta teka tinguvu, u ambexa Aroni nkhombolo, ni ephod, ni xifuva, u n\u2019wi boha hi bhande ra ephod.\u2019' },
    { n: 6, text: '\u2018U ta veka xihuku enhlokweni ya yena, u veka xifuwu xo kwetsima ehenhla ka xihuku.\u2019' },
    { n: 7, text: '\u2018U ta teka mafurha ya ku tota, u ma chela enhlokweni ya yena, u n\u2019wi tota.\u2019' },
    { n: 8, text: '\u2018U ta tisa vana va yena, u va ambexa makhombolo.\u2019' },
    { n: 9, text: '\u2018U ta va boha hi mabhante, Aroni ni vana va yena, u va veka swihuku, naswona vaprista va ta va vona hi nawu lowu nga heriki; u ta kwetsimisa Aroni ni vana va yena.\u2019' },
    { n: 10, text: '\u2018U ta tisa homu mahlweni ka tabernakela ya nhlanganiso, Aroni ni vana va yena va ta veka mavoko ya vona ehenhla ka nhloko ya homu.\u2019' },
    { n: 11, text: '\u2018U ta tlhava homu mahlweni ka Yehovha, emunyangweni wa tabernakela ya nhlanganiso.\u2019' },
    { n: 12, text: '\u2018U ta teka ngati ya homu, u yi chela hi ritiho ra wena ehenhla ka timhondzo ta alitari, u chela ngati hinkwayo ehansi ka alitari.\u2019' },
    { n: 13, text: '\u2018U ta teka mafurha hinkwawo lama funengetaka mbilu, ni xiphemu xa xivindzi, ni titsheke timbirhi, ni mafurha lama nga ehenhla ka tona, u swi hisa ealitari.\u2019' },
    { n: 14, text: '\u2018Kambe nyama ya homu, ni nhlonge ya yona, ni thyaka ra yona, u ta swi hisa hi ndzilo ekheleni ra n\u2019wina; i xitlhavelo xa xidyoho.\u2019' },
    { n: 15, text: '\u2018U ta teka nyimpfu yin\u2019we, Aroni ni vana va yena va ta veka mavoko ya vona ehenhla ka nhloko ya nyimpfu.\u2019' },
    { n: 16, text: '\u2018U ta tlhava nyimpfu, u teka ngati ya yona, u yi fafata ehenhla ka alitari ku rhendzela.\u2019' },
    { n: 17, text: '\u2018U ta tsemba nyimpfu hi swiphemu, u hlantswa swiphemu swa yona ni milenge ya yona, u swi veka ehenhla ka swiphemu swa yona.\u2019' },
    { n: 18, text: '\u2018U ta hisa nyimpfu hinkwayo ealitari; i xitlhavelo xo hisiwa eka Yehovha; i swakudya swa nun\u2019hwelo eka Yehovha.\u2019' },
    { n: 19, text: '\u2018U ta teka nyimpfu yin\u2019we, Aroni ni vana va yena va ta veka mavoko ya vona ehenhla ka nhloko ya nyimpfu.\u2019' },
    { n: 20, text: '\u2018U ta tlhava nyimpfu, u teka ngati ya yona, u yi chela ehenhla ka nhloko ya Aroni, ni vana va yena, ni ehenhla ka mavoko ya vona ya xinene, ni milenge ya vona ya xinene, u fafata ngati ehenhla ka alitari ku rhendzela.\u2019' },
    { n: 21, text: '\u2018U ta teka ngati leyi nga ealitari, ni mafurha ya ku tota, u yi fafata ehenhla ka Aroni, ni tinguvu ta yena, ni vana va yena, ni tinguvu ta vana va yena; u ta kwetsima yena ni tinguvu ta yena.\u2019' },
    { n: 22, text: '\u2018U ta teka mafurha ya nyimpfu, ni ntsendze, ni mafurha lama funengetaka mbilu, ni xiphemu xa xivindzi, ni titsheke timbirhi, ni mafurha lama nga ehenhla ka tona, ni ntsu wa xinene, hikuva i nyimpfu ya ku kwetsima.\u2019' },
    { n: 23, text: '\u2018Ni xinkwa xin\u2019we, ni mikate ya xinkwa leyi hlanganisiweke hi mafurha, ni xinkwa xin\u2019we exirhundzwini xa xinkwa lexi nga riki na comela mahlweni ka Yehovha.\u2019' },
    { n: 24, text: '\u2018U ta swi veka hinkwaswo emavokweni ya Aroni, ni vana va yena, u swi phaphazela mahlweni ka Yehovha.\u2019' },
    { n: 25, text: '\u2018U ta swi teka emavokweni ya vona, u swi hisa ealitari ehenhla ka xitlhavelo xo hisiwa, swi va swakudya swa nun\u2019hwelo mahlweni ka Yehovha.\u2019' },
    { n: 26, text: '\u2018U ta teka ntsu wa nyimpfu ya ku kwetsima, u wu phaphazela mahlweni ka Yehovha; wu ta va xiphemu xa wena.\u2019' },
    { n: 27, text: '\u2018U ta kwetsimisa ntsu wa ku phaphazela, ni xiphemu xa ntsu lexi phaphazeriweke, lexi phaphazeriweke eka nyimpfu ya Aroni ni vana va yena.\u2019' },
    { n: 28, text: '\u2018Xi ta va xiphemu xa Aroni ni vana va yena hi nawu lowu nga heriki eka vana va Israyele; hikuva i xiphemu xa ku kwetsima.\u2019' },
    { n: 29, text: '\u2018Tinguvu to kwetsima ta Aroni ti ta va ta vana va yena endzhaku ka yena, leswaku va totiwa hi tona, va kwetsimisiwa hi tona.\u2019' },
    { n: 30, text: '\u2018Muprista loyi a nga ta va endzhaku ka yena eka vana va yena, u ta ti ambara masiku ya mune, loko a nghena etabernakela ya nhlanganiso leswaku a tirha endhawini yo kwetsima.\u2019' },
    { n: 31, text: '\u2018U ta teka nyimpfu ya ku kwetsima, u sweka nyama ya yona endhawini yo kwetsima.\u2019' },
    { n: 32, text: '\u2018Aroni ni vana va yena va ta dya nyama ya nyimpfu, ni xinkwa lexi nga exirhundzwini, emunyangweni wa tabernakela ya nhlanganiso.\u2019' },
    { n: 33, text: '\u2018Va ta dya swilo leswi va kutsuriweke ha swona, leswaku va kwetsimisiwa; kambe munhu loyi a nga riki muprista a nga ka a nga swi dyi, hikuva i swilo swo kwetsima.\u2019' },
    { n: 34, text: '\u2018Loko nyama ya xitlhavelo xo kwetsima kumbe xinkwa xi sala ku fikela nimixo, u ta hisa lexi saleke hi ndzilo; a xi nge dyiwi, hikuva i swo kwetsima.\u2019' },
    { n: 35, text: '\u2018U ta endla tano hi Aroni ni vana va yena, hi hinkwaswo leswi ndzi ku leriseke swona; u ta va kwetsimisa masiku ya mune.\u2019' },
    { n: 36, text: '\u2018U ta nyikela homu ya xidyoho siku ni siku, u ta kwetsimisa alitari hi ku endla xitlhavelo xa ku kwetsimisa; u ta yi tota leswaku yi kwetsima.\u2019' },
    { n: 37, text: '\u2018U ta kwetsimisa alitari masiku ya mune, u ta yi kwetsimisa; alitari yi ta va yo kwetsima swinene; hinkwaswo leswi khumbaka alitari swi ta kwetsima.\u2019' },
    { n: 38, text: '\u2018Leri i rito leri u nga ta nyikela ealitari: tihomu timbirhi leti nga ni lembe rin\u2019we, siku ni siku, hi minkarhi hinkwayo.\u2019' },
    { n: 39, text: '\u2018Homu yin\u2019we u ta nyikela nimixo, ni homu ya vumbirhi u ta nyikela nimadyambu.\u2019' },
    { n: 40, text: '\u2018Ni xinkwa lexi nga riki na comela, ni mikate ya xinkwa leyi hlanganisiweke hi mafurha, ni xinkwa xin\u2019we, ni xinkwa xin\u2019we; ni xinkwa xa ntswamba, hi mapa ya koriandere.\u2019' },
    { n: 41, text: '\u2018Homu ya vumbirhi u ta nyikela nimadyambu, ni xitlhavelo xa nimixo, ni nun\u2019hwelo wa nun\u2019hwelo eka Yehovha.\u2019' },
    { n: 42, text: '\u2018Xi ta va xitlhavelo xo hisiwa hi minkarhi hinkwayo eka vana va Israyele, emunyangweni wa tabernakela ya nhlanganiso mahlweni ka Yehovha; kwalaho ndzi ta hlangana na wena, ndzi ta vulavula na wena.\u2019' },
    { n: 43, text: '\u2018Kwalaho ndzi ta hlangana na vana va Israyele, yi ta kwetsimisiwa hi ku dzunisa ka mina.\u2019' },
    { n: 44, text: '\u2018Ndzi ta kwetsimisa tabernakela ya nhlanganiso ni alitari; ndzi ta kwetsimisa Aroni ni vana va yena, leswaku va va vaprista eka mina.\u2019' },
    { n: 45, text: '\u2018Ndzi ta tshama exikarhi ka vana va Israyele, ndzi ta va Xikwembu xa vona.\u2019' },
    { n: 46, text: '\u2018Va ta tiva leswaku ndzi Yehovha Xikwembu xa vona, loyi a va humeseke etikweni ra Egipta, leswaku ndzi ta tshama exikarhi ka vona; ndzi Yehovha Xikwembu xa vona.\u2019' },
  ],
  30: [
    { n: 1, text: '\u2018U ta endla alitari ya ku hisa nun\u2019hwelo hi mhandzi ya xitachi.\u2019' },
    { n: 2, text: '\u2018Ku leha ka yona i tinyanya ta n\u2019we, ni ku anama ka yona i tinyanya ta n\u2019we, yi ta va ya xirhendzevutana, ni ku tlakuka ka yona i tinyanya ta mbirhi; timhondzo ta yona ti ta va xikan\u2019we na yona.\u2019' },
    { n: 3, text: '\u2018U ta yi ambexa hi nsuku lowo tengamela, enhlohlo ya yona, ni matlhelo ya yona ku rhendzela, ni timhondzo ta yona; u ta yi endlela nkhombolo wa nsuku ku rhendzela.\u2019' },
    { n: 4, text: '\u2018U ta yi endlela swikhomo swimbirhi swa nsuku ehansi ka nkhombolo wa yona, ematlhelweni ya yona mambirhi, ku va switirho swa timhandzi to yi rhwala.\u2019' },
    { n: 5, text: '\u2018U ta endla timhandzi hi mhandzi ya xitachi, u ti ambexa hi nsuku.\u2019' },
    { n: 6, text: '\u2018U ta yi veka mahlweni ka nkhombolo lowu nga mahlweni ka areka ya vumbhoni, mahlweni ka xifunengeto lexi nga ehenhla ka vumbhoni, laha ndzi nga ta hlangana na wena.\u2019' },
    { n: 7, text: '\u2018Aroni u ta hisa nun\u2019hwelo wa swirungo ehenhla ka yona nimixo ni nimixo, loko a tengisa swirhundzu.\u2019' },
    { n: 8, text: '\u2018Loko Aroni a veka rivoningo nimadyambu, u ta hisa nun\u2019hwelo, i nun\u2019hwelo wa minkarhi hinkwayo mahlweni ka Yehovha eka tinxaka ta n\u2019wina.\u2019' },
    { n: 9, text: '\u2018Mi nga tshuki mi hisa nun\u2019hwelo wun\u2019wana ehenhla ka yona, hambi ku va xitlhavelo xo hisiwa, hambi ku va xinkwa, hambi ku va swakunwa.\u2019' },
    { n: 10, text: '\u2018Aroni u ta endla xitlhavelo xa ku kwetsimisa ehenhla ka timhondzo ta yona kan\u2019we hi lembe hi ngati ya xitlhavelo xa xidyoho; kan\u2019we hi lembe u ta endla tano hi ngati ya xitlhavelo xa xidyoho eka tinxaka ta n\u2019wina; i yo kwetsima swinene eka Yehovha.\u2019' },
    { n: 11, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 12, text: '\u2018Loko u hlaya vana va Israyele, un\u2019wana ni un\u2019wana u ta nyikela nkutsulo wa vutomi bya yena eka Yehovha, leswaku ku nga vi na ntungu exikarhi ka vona loko va hlaya.\u2019' },
    { n: 13, text: '\u2018Hinkwavo lava nga exikarhi ka lava hlayiweke, va ta nyikela hafu ya xikhele hi mpimo wa vutomi bya vutomi; xikhele xi ta va xa makume-mbirhi ya gerah; hafu ya xikhele i munyikelo eka Yehovha.\u2019' },
    { n: 14, text: '\u2018Hinkwavo lava humaka eka lava hlayiweke, va makume-mbirhi ya malembe ku ya ehenhla, va ta nyikela munyikelo eka Yehovha.\u2019' },
    { n: 15, text: '\u2018Loyi a fuweke a nga ka a nga nyikeli ku tlula hafu ya xikhele, ni xisiwana a nga ka a nga nyikeli ku tlula hafu ya xikhele, hi ku nyikela munyikelo eka Yehovha, leswaku ku kutsuriwa vutomi bya n\u2019wina.\u2019' },
    { n: 16, text: '\u2018U ta teka mali ya nkutsulo eka vana va Israyele, u ta yi nyikela eka ntirho wa tabernakela ya nhlanganiso, leswaku yi va vutsundzuxo eka vana va Israyele mahlweni ka Yehovha, ku kutsula vutomi bya n\u2019wina.\u2019' },
    { n: 17, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 18, text: '\u2018U ta endla xibye xa koporo, ni xisekelo xa xona xa koporo, xo hlantswela; u ta xi veka exikarhi ka tabernakela ya nhlanganiso ni alitari, u chela mati endzeni.\u2019' },
    { n: 19, text: '\u2018Aroni ni vana va yena va ta hlantswa mavoko ya vona ni milenge ya vona eka xona.\u2019' },
    { n: 20, text: '\u2018Loko va nghena etabernakela ya nhlanganiso, va ta hlantswa hi mati, leswaku va nga fi; kumbe loko va tshinela ealitari leswaku va tirha, va hisa swakudya swa nun\u2019hwelo eka Yehovha.\u2019' },
    { n: 21, text: '\u2018Va ta hlantswa mavoko ya vona ni milenge ya vona, leswaku va nga fi; nawu lowu wu ta va hilaha ku nga heriki eka yena ni vana va yena eka tinxaka ta vona.\u2019' },
    { n: 22, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 23, text: '\u2018Teka swirungo leswinene: mirra ya ntswamba, timbirhi ta magidi, ni sinamoni wa ntswamba, wa hafu ya yona, ni ndzalo wa ndzilo, timbirhi ta magidi,\u2019' },
    { n: 24, text: '\u2018ni kasiya, timbirhi ta magidi, hi mpimo wa vutomi bya vutomi, ni mafurha ya olive, hi hin.\u2019' },
    { n: 25, text: '\u2018U ta endla mafurha ya ku tota yo kwetsima, ntirho wa muvumbi wa swirungo; i mafurha ya ku tota yo kwetsima.\u2019' },
    { n: 26, text: '\u2018U ta tota tabernakela ya nhlanganiso, ni areka ya vumbhoni,\u2019' },
    { n: 27, text: '\u2018ni tafula ni swibye swa rona hinkwaswo, ni xitirho xa rivoningo ni swibye swa xona, ni alitari ya nun\u2019hwelo,\u2019' },
    { n: 28, text: '\u2018ni alitari ya xitlhavelo xo hisiwa ni swibye swa yona hinkwaswo, ni xibye xa mati ni xisekelo xa xona.\u2019' },
    { n: 29, text: '\u2018U ta swi kwetsimisa leswaku swi va swo kwetsima swinene; hinkwaswo leswi swi nga ta swi khumba swi ta kwetsima.\u2019' },
    { n: 30, text: '\u2018U ta tota Aroni ni vana va yena, u va kwetsimisa leswaku va va vaprista eka mina.\u2019' },
    { n: 31, text: '\u2018U ta vulavula ni vana va Israyele, u ku: Leri i mafurha ya ku tota yo kwetsima eka mina eka tinxaka ta n\u2019wina.\u2019' },
    { n: 32, text: '\u2018Ma nga tshuki ma cheriwa ehenhla ka miri wa munhu, naswona mi nga tshuki mi endla man\u2019wana hi mpimo wa wona; i yo kwetsima, ma ta va yo kwetsima eka n\u2019wina.\u2019' },
    { n: 33, text: '\u2018Munhu loyi a endlaka man\u2019wana, kumbe loyi a ma cheriwaka, u ta susiwa exikarhi ka vanhu va yena.\u2019' },
    { n: 34, text: '\u2018Yehovha a ku eka Moxe: Teka swirungo, ni onycha, ni galbanum, ni nun\u2019hwelo, ni mirra ya ntswamba; swi va swa mpimo wun\u2019we.\u2019' },
    { n: 35, text: '\u2018U ta endla nun\u2019hwelo hi ntirho wa muvumbi wa swirungo, wu khavisiwe, wu kwetsime, wu tengile.\u2019' },
    { n: 36, text: '\u2018U ta wu kandziya wu va mpfhura, u wu veka mahlweni ka vumbhoni etabernakela ya nhlanganiso, laha ndzi nga ta hlangana na wena; wu ta va wo kwetsima swinene eka n\u2019wina.\u2019' },
    { n: 37, text: '\u2018Nun\u2019hwelo lowu u nga ta wu endla, mi nga tshuki mi tiendlela wona hi mpimo wa wona; u ta va wo kwetsima eka Yehovha.\u2019' },
    { n: 38, text: '\u2018Munhu loyi a endlaka nun\u2019hwelo wo fana na wona leswaku a nuhela, u ta susiwa exikarhi ka vanhu va yena.\u2019' },
  ],
  31: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '\u2018Vona, ndzi vitane Bezalele, n\u2019wana wa Uri, n\u2019wana wa Huri, wa ntsawa wa Yuda;\u2019' },
    { n: 3, text: '\u2018ndzi n\u2019wi tate hi moya wa Xikwembu, hi vutlhari, ni hi ku twisisa, ni hi vutivi, ni hi mintirho hinkwayo,\u2019' },
    { n: 4, text: '\u2018ku endla mintirho ya nsuku, ni silivhere, ni koporo,\u2019' },
    { n: 5, text: '\u2018ni ku tsema maribye, ni ku rhunga, ni mintirho hinkwayo ya mhandzi.\u2019' },
    { n: 6, text: '\u2018Ndzi nyike na Oholiabe, n\u2019wana wa Ahisamake, wa ntsawa wa Dani, leswaku a va na yena; ndzi tate mbilu ya hinkwavo lava va tlhariheke vutlhari, leswaku va endla hinkwaswo leswi ndzi ku leriseke swona.\u2019' },
    { n: 7, text: '\u2018Tabernakela ya nhlanganiso, ni areka ya vumbhoni, ni xifunengeto lexi nga ehenhla ka yona, ni swibye hinkwaswo swa tabernakela,\u2019' },
    { n: 8, text: '\u2018ni tafula ni swibye swa rona, ni xitirho xa rivoningo ni swibye swa xona, ni alitari ya nun\u2019hwelo,\u2019' },
    { n: 9, text: '\u2018ni alitari ya xitlhavelo xo hisiwa ni swibye swa yona hinkwaswo, ni xibye xa mati ni xisekelo xa xona,\u2019' },
    { n: 10, text: '\u2018ni tinguvu to kwetsima, tinguvu to kwetsima ta Aroni muprista, ni tinguvu ta vana va yena leswaku va va vaprista,\u2019' },
    { n: 11, text: '\u2018ni mafurha ya ku tota, ni nun\u2019hwelo wa swirungo endhawini yo kwetsima; va ta endla hinkwaswo hi ku ya hi hinkwaswo leswi ndzi ku leriseke swona.\u2019' },
    { n: 12, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 13, text: '\u2018Vulavula ni vana va Israyele, u ku: Mi ta hlayisa masabata ya mina, hikuva i mfungho exikarhi ka mina na n\u2019wina eka tinxaka ta n\u2019wina, leswaku mi tiva leswaku ndzi Yehovha loyi a mi kwetsimisaka.\u2019' },
    { n: 14, text: '\u2018Mi ta hlayisa masabata, hikuva i yo kwetsima eka n\u2019wina; loyi a ma thyakisa u ta fa; munhu loyi a endlaka ntirho ha wona, u ta susiwa exikarhi ka vanhu va yena.\u2019' },
    { n: 15, text: '\u2018Masiku ya tsevu ku ta endliwa ntirho, kambe hi siku ra vunkombo i masabata ya ku wisa, ya ku kwetsima eka Yehovha; loyi a endlaka ntirho hi siku ra masabata u ta fa.\u2019' },
    { n: 16, text: '\u2018Vana va Israyele va ta hlayisa masabata, va ma endla eka tinxaka ta vona, i ntwanano lowu nga heriki.\u2019' },
    { n: 17, text: '\u2018I mfungho exikarhi ka mina na vana va Israyele hilaha ku nga heriki, hikuva Yehovha u endle matilo ni misava hi masiku ya tsevu, kutani hi siku ra vunkombo a wisa, a titwisa ku antswa.\u2019' },
    { n: 18, text: 'Loko a heta ku vulavula na yena entshaveni ya Sinayi, a nyika Moxe maribye mambirhi ya vumbhoni, maribye ya ribye, lama tsaleriweke hi rintiho ra Xikwembu.' },
  ],
  32: [
    { n: 1, text: 'Loko vanhu va vona leswaku Moxe u hlwela ku rhela entshaveni, vanhu va hlengeletana eka Aroni, va ku eka yena: \u2018Pfuka, u hi endlela swikwembu leswi nga ta famba mahlweni ka hina; hikuva Moxe loyi a hi humeseke etikweni ra Egipta, a hi tivi leswi n\u2019wi humeleleke.\u2019' },
    { n: 2, text: 'Aroni a ku eka vona: \u2018Haxani swiambalo swa nsuku leswi nga etindleveni ta vavasati va n\u2019wina, ni vana va n\u2019wina va majaha, ni vana va n\u2019wina va vaxisati, mi ndzi tisa.\u2019' },
    { n: 3, text: 'Vanhu hinkwavo va haxa swiambalo swa nsuku leswi nga etindleveni ta vona, va tisa eka Aroni.' },
    { n: 4, text: 'A swi amukela evokweni ra vona, a swi fayetela, a swi endla xinkonyana hi xitirho xa xifaniso; va ku: \u2018Leswi i swikwembu swa n\u2019wina, Israyele, leswi mi humeseke etikweni ra Egipta.\u2019' },
    { n: 5, text: 'Aroni a swi vona, a aka alitari mahlweni ka xona; Aroni a huwelela, a ku: \u2018Kusasa i nkhuvo eka Yehovha.\u2019' },
    { n: 6, text: 'Va pfuka hi mixo, va nyikela magandzelo ya ku hisiwa, ni magandzelo ya ku rhula; vanhu va tshama ku dya ni ku nwa, va pfuka ku tlanga.' },
    { n: 7, text: 'Yehovha a ku eka Moxe: \u2018Rhela, hikuva vanhu va wena lava u va humeseke etikweni ra Egipta, va dyohile.\u2019' },
    { n: 8, text: '\u2018Va hambukile hi ku hatlisa endleleni leyi ndzi va leriseke yona; va tiendlele xinkonyana xa nsuku, va nkhinsamela mahlweni ka xona, va nyikela magandzelo eka xona, va ku: Leswi i swikwembu swa n\u2019wina, Israyele, leswi mi humeseke etikweni ra Egipta.\u2019' },
    { n: 9, text: 'Yehovha a ku eka Moxe: \u2018Ndzi vonile vanhu lava, vonani, i vanhu va nhloko yo nona.\u2019' },
    { n: 10, text: '\u2018Kutani ndzi tshike, leswaku vukari bya mina byi va pfukela, ndzi va lovisa, ndzi ta endla wena u va tiko lerikulu.\u2019' },
    { n: 11, text: 'Moxe a khongela mahlweni ka Yehovha Xikwembu xa yena, a ku: \u2018Yehovha, ha yini vukari bya wena byi pfukela vanhu va wena, lava u va humeseke etikweni ra Egipta hi matimba lamakulu ni hi voko leri tlakukeke?\u2019' },
    { n: 12, text: '\u2018Ha yini va-Egipta va fanele ku vula, va ku: A a va humese hi ku biha, leswaku a va dlaya entshaveni, a va lovisa ehenhla ka misava? Tlherisa vukari bya wena, u rivalela vanhu va wena.\u2019' },
    { n: 13, text: '\u2018Tsundzuka Abraham, na Isaka, na Israyele, malandza ya wena, lawa u ma hlambanyeleke hi wena, u ku eka wona: Ndzi ta andzisa vana va n\u2019wina tanihi tinyeleti ta le matilweni, ni tiko leri hinkwaro leri ndzi ri tshembiseke, ndzi ta ri nyika vana va n\u2019wina, va ta ri dya hilaha ku nga heriki.\u2019' },
    { n: 14, text: 'Yehovha a tshika ku endla swo biha leswi a a vule leswaku u ta swi endla eka vanhu va yena.' },
    { n: 15, text: 'Moxe a hundzuluka, a rhela entshaveni, a ri ni maribye mambirhi ya vumbhoni evokweni ra yena, maribye lama tsaleriweke etlhelo rin\u2019we ni rin\u2019wana; a tsaleriwile etlhelo rin\u2019we ni rin\u2019wana.' },
    { n: 16, text: 'Maribye a ku ri ntirho wa Xikwembu, ni ku tsala a ku ri ku tsala ka Xikwembu, ku tsaleriwile ehenhla ka maribye.' },
    { n: 17, text: 'Yoxuwa a twa rito ra vanhu loko va huwelela, a ku eka Moxe: \u2018Ku ni rito ra nyimpi ekheleni.\u2019' },
    { n: 18, text: 'Moxe a ku: \u2018A hi rito ra ku hlula, ni rito ra ku hluliwa; kambe i rito ra lava yimbelaka leri ndzi ri twaka.\u2019' },
    { n: 19, text: 'Loko a tshinela ekheleni, a vona xinkonyana ni ku tlanga, vukari bya Moxe byi pfuka, a cukumeta maribye evokweni ra yena, a ma fayetela ehansi ka ntshava.' },
    { n: 20, text: 'A teka xinkonyana lexi va xi endleke, a xi hisa hi ndzilo, a xi kandziya xi va mpfhura, a xi chela ematini, a nyika vana va Israyele va nwa.' },
    { n: 21, text: 'Moxe a ku eka Aroni: \u2018Vanhu lava va ku endle yini, leswi u va tiseke xidyoho lexikulu?\u2019' },
    { n: 22, text: 'Aroni a ku: \u2018Vukari bya n\u2019wini wanga byi nga pfuki; u va tiva vanhu lava, leswaku va rhandza swo biha.\u2019' },
    { n: 23, text: '\u2018Va ku eka mina: Hi endlele swikwembu leswi nga ta famba mahlweni ka hina; hikuva Moxe loyi a hi humeseke etikweni ra Egipta, a hi tivi leswi n\u2019wi humeleleke.\u2019' },
    { n: 24, text: '\u2018Ndzi ku eka vona: Un\u2019wana ni un\u2019wana la nga ni nsuku, a a wu haxe; va wu nyika eka mina, ndzi wu cukumeta endzilweni, kutani ku huma xinkonyana lexi.\u2019' },
    { n: 25, text: 'Moxe a vona leswaku vanhu va tixaxile, hikuva Aroni a a va tshike va tixaxa eka valala va vona.' },
    { n: 26, text: 'Moxe a yima emunyangweni wa nkhele, a ku: \u2018Loyi a nga na Yehovha, a a te eka mina!\u2019 Vana hinkwavo va Levi va hlengeletana eka yena.' },
    { n: 27, text: 'A ku eka vona: \u2018Yehovha Xikwembu xa Israyele u vula tano: Un\u2019wana ni un\u2019wana a a bohe banga ra yena erivaleni, a famba exikarhi ka nkhele, a dlaya makwavo, ni munghana wa yena, ni muakelani wa yena.\u2019' },
    { n: 28, text: 'Vana va Levi va endla hilaha Moxe a va byeleke hakona; hi siku rero ku fa vanhu va kwalomu ka madzana manharhu.' },
    { n: 29, text: 'Moxe a ku: \u2018Tivoni, mi titshikile namuntlha eka Yehovha, hikuva un\u2019wana ni un\u2019wana u lwe ni n\u2019wana wa yena ni makwavo, leswaku a mi nyika nkateko namuntlha.\u2019' },
    { n: 30, text: 'Hi siku leri landzelaka, Moxe a ku eka vanhu: \u2018Mi endle xidyoho lexikulu; kambe ndzi ta tlhandlukela eka Yehovha, kumbexana ndzi ta kuma ku rivaleriwa xidyoho xa n\u2019wina.\u2019' },
    { n: 31, text: 'Moxe a tlhelela eka Yehovha, a ku: \u2018Vanhu lava va endle xidyoho lexikulu, va tiendlele swikwembu swa nsuku.\u2019' },
    { n: 32, text: '\u2018Kutani sweswi, u rivalela xidyoho xa vona; loko a hi tano, ndzi hlapise ebukwini ya wena leyi u yi tsaleke.\u2019' },
    { n: 33, text: 'Yehovha a ku eka Moxe: \u2018Loyi a ndzi dyoheleke, hi yena ndzi nga ta n\u2019wi hlapisa ebukwini ya mina.\u2019' },
    { n: 34, text: '\u2018Kutani famba, u rhungela vanhu endhawini leyi ndzi ku byeleke yona; vona, ntsumi ya mina yi ta famba mahlweni ka wena; kambe hi siku ra ku avanyisa, ndzi ta va ba hi xidyoho xa vona.\u2019' },
    { n: 35, text: 'Yehovha a ba vanhu, hikuva va endlile xinkonyana lexi Aroni a xi endleke.' },
  ],
  33: [
    { n: 1, text: 'Yehovha a ku eka Moxe: \u2018Famba, u tlhandluka laha, wena ni vanhu lava u va humeseke etikweni ra Egipta, u ya etikweni leri ndzi ri hlambanyeleke Abraham, na Isaka, na Yakobo, ndzi ku: Ndzi ta ri nyika vana va wena.\u2019' },
    { n: 2, text: '\u2018Ndzi ta rhumela ntsumi mahlweni ka wena, ndzi ta hlongola Vakanana, ni Vaamori, ni Vahiti, ni Vaperizi, ni Vahevi, ni Vayebusi.\u2019' },
    { n: 3, text: '\u2018Etikweni leri humaka mafurha ni vusi; hikuva a ndzi nge fambi na n\u2019wina, hikuva mi vanhu va nhloko yo nona, leswaku ndzi nga mi lovisi endleleni.\u2019' },
    { n: 4, text: 'Vanhu va twa marito lawa yo biha, va rila; a ku na munhu loyi a ambareke swiambalo swa yena.' },
    { n: 5, text: 'Yehovha a ku eka Moxe: \u2018Byela vana va Israyele: Mi vanhu va nhloko yo nona; loko ndzi ta famba na n\u2019wina hi nkarhi wun\u2019we, ndzi ta mi lovisa; kutani sweswi, hluvani swiambalo swa n\u2019wina, ndzi ta tiva leswi ndzi nga ta mi endla swona.\u2019' },
    { n: 6, text: 'Vana va Israyele va hluva swiambalo swa vona kusukela entshaveni ya Horebe.' },
    { n: 7, text: 'Moxe a teka tabernakela, a yi yimisa ekheleni, ekule ni nkhele, a yi vitana Tabernakela ya Nhlanganiso; hinkwavo lava va lavaka Yehovha va ya etabernakela ya nhlanganiso, leyi nga ekhandle ni nkhele.' },
    { n: 8, text: 'Loko Moxe a huma ku ya etabernakela, vanhu hinkwavo va pfuka, un\u2019wana ni un\u2019wana a yima emunyangweni wa tende ra yena, a languta Moxe, ku fikela loko a nghena etabernakela.' },
    { n: 9, text: 'Loko Moxe a nghena etabernakela, mupapa wa maru a wu rhela, wu yima emunyangweni wa tabernakela, kutani Yehovha a vulavula na Moxe.' },
    { n: 10, text: 'Vanhu hinkwavo va vona mupapa wa maru wu yimile emunyangweni wa tabernakela; vanhu hinkwavo va pfuka, va nkhinsamela un\u2019wana ni un\u2019wana emunyangweni wa tende ra yena.' },
    { n: 11, text: 'Yehovha a vulavula na Moxe hi xikandza ni xikandza, tanihi leswi munhu a vulavulaka ni munghana wa yena. A tlhelela ekheleni, kambe Yoxuwa n\u2019wana wa Nuni, mutirheli wa yena, a nga humanga etabernakela.' },
    { n: 12, text: 'Moxe a ku eka Yehovha: \u2018Vona, u ku eka mina: Rhungela vanhu lava; kambe a wu ndzi byelanga loyi u nga ta famba na yena; naswona u ku: Ndzi ku tivile hi vito, naswona u kumile tintswalo mahlweni ka mina.\u2019' },
    { n: 13, text: '\u2018Kutani sweswi, loko ndzi kumile tintswalo mahlweni ka wena, ndzi kombe ndlela ya wena, leswaku ndzi ku tiva, ndzi kuma tintswalo mahlweni ka wena; tsundzuka leswaku tiko leri i vanhu va wena.\u2019' },
    { n: 14, text: 'A ku: \u2018Moya wa mina wu ta famba na wena, ndzi ta ku wisisa.\u2019' },
    { n: 15, text: 'A ku eka yena: \u2018Loko moya wa wena wu nga fambi na hina, u nga hi humesi laha.\u2019' },
    { n: 16, text: '\u2018Hikuva ha yini swi ta tiviwa leswaku ndzi kumile tintswalo mahlweni ka wena, mina ni vanhu va wena? Xana a hi hi ku famba ka wena na hina, leswaku hi hambana ni vanhu hinkwavo lava nga ehenhla ka misava?\u2019' },
    { n: 17, text: 'Yehovha a ku eka Moxe: \u2018Ndzi ta endla hinkwaswo leswi u vuleke, hikuva u kumile tintswalo mahlweni ka mina, ndzi ku tivile hi vito.\u2019' },
    { n: 18, text: 'A ku: \u2018Ndzi kombe kwetsima ka wena.\u2019' },
    { n: 19, text: 'A ku: \u2018Ndzi ta hundzisa ku saseka ka mina hinkwako mahlweni ka wena, ndzi ta huwelela vito ra Yehovha mahlweni ka wena; ndzi ta twela vusiwana loyi ndzi nga ta n\u2019wi twela vusiwana, ndzi ta nkhensa loyi ndzi nga ta n\u2019wi nkhensa.\u2019' },
    { n: 20, text: 'A ku: \u2018A wu nge vi na matimba yo vona xikandza xa mina, hikuva a ku na munhu loyi a nga ta ndzi vona a hanya.\u2019' },
    { n: 21, text: 'Yehovha a ku: \u2018Vona, ku na ndhawu ekusuhi na mina, u ta yima ehenhla ka ribye.\u2019' },
    { n: 22, text: '\u2018Loko kwetsima ka mina ku hundza, ndzi ta ku veka ehenhla ka ribye, ndzi ku funengeta hi voko ra mina ku fikela loko ndzi hundza.\u2019' },
    { n: 23, text: '\u2018Ndzi ta suka voko ra mina, u ta vona hlanu ra mina; kambe xikandza xa mina a xi nge voniwi.\u2019' },
  ],
  34: [
    { n: 1, text: 'Yehovha a ku eka Moxe: \u2018Tiyimela maribye mambirhi ya ribye ku fana ni yo sungula, ndzi ta tsala ehenhla ka maribye marito lama a ma ri ehenhla ka maribye yo sungula, lawa u ma fayeteleke.\u2019' },
    { n: 2, text: '\u2018Tlhandluka hi mixo, u ta tlhandlukela entshaveni ya Sinayi, u yima mahlweni ka mina enhlokweni ya ntshava.\u2019' },
    { n: 3, text: '\u2018A ku na munhu loyi a nga ta tlhandluka na wena, hambi ku va munhu loyi a nga ta voniwa entshaveni hinkwayo; hambi ku va tihomu kumbe tinyimpfu, ti nga tshuki ti dyela kusuhi ni ntshava leyi.\u2019' },
    { n: 4, text: 'Moxe a tiyima maribye mambirhi ya ribye ku fana ni yo sungula; a pfuka hi mixo, a tlhandlukela entshaveni ya Sinayi, hi leswi Yehovha a n\u2019wi leriseke swona, a ri ni maribye mambirhi evokweni ra yena.' },
    { n: 5, text: 'Yehovha a rhela emupapeni, a yima na yena kwalaho, a huwelela vito ra Yehovha.' },
    { n: 6, text: 'Yehovha a hundza mahlweni ka yena, a huwelela: \u2018Yehovha, Yehovha, Xikwembu xa vusiwana ni xa tintswalo, lexi hlwelaka ku hlundzuka, lexi teleke hi musa ni hi ntiyiso,\u2019' },
    { n: 7, text: '\u2018lexi hlayisaka musa eka madzana, lexi rivalelaka xidyoho, ni ku tlula, ni xidyoho, lexi nga ka xi nga rivaleli, lexi tiselaka vana va vana nandzu wa vatatana va vona eka tinxaka ta nhungu.\u2019' },
    { n: 8, text: 'Moxe a hatlisa, a korhamela hansi, a nkhinsamela.' },
    { n: 9, text: 'A ku: \u2018Loko ndzi kumile tintswalo mahlweni ka wena, Yehovha, a a fambe na hina, hikuva i vanhu va nhloko yo nona; rivalela xidyoho xa hina ni ku tlula ka hina, u hi teka hi va ndzhaka ya wena.\u2019' },
    { n: 10, text: 'A ku: \u2018Vona, ndzi endla ntwanano mahlweni ka vanhu va wena hinkwavo, ndzi ta endla swihlamariso leswi nga si tiviwaka emisaveni hinkwayo, ni exikarhi ka tinxaka hinkwato; vanhu hinkwavo lava u nga exikarhi ka vona va ta vona ntirho wa Yehovha, hikuva i ntirho wo chavisa lowu ndzi nga ta wu endla na wena.\u2019' },
    { n: 11, text: '\u2018Hlayisa leswi ndzi ku leriseke swona namuntlha; vona, ndzi hlongola mahlweni ka wena Vaamori, ni Vakanana, ni Vahiti, ni Vaperizi, ni Vahevi, ni Vayebusi.\u2019' },
    { n: 12, text: '\u2018Tivonela leswaku u nga endli ntwanano na vaaki va tiko leri u yaka eka rona, leswaku ri nga vi ntlhamu exikarhi ka n\u2019wina.\u2019' },
    { n: 13, text: '\u2018Kambe mi ta fayetela alitari ya vona, mi fayetela swifaniso swa vona swa maribye, mi tsemakanya mitsimba ya vona ya swikwembu.\u2019' },
    { n: 14, text: '\u2018Hikuva u nga tshuki u nkhinsamela xikwembu xin\u2019wana, hikuva Yehovha, loyi vito ra yena ri nga wa ku rhandza, i Xikwembu xa ku rhandza.\u2019' },
    { n: 15, text: '\u2018U nga tshuki u endla ntwanano na vaaki va tiko, hikuva va ta hambukela swikwembu swa vona, va ku mema, kutani u ta dya xitlhavelo xa vona;\u2019' },
    { n: 16, text: '\u2018naswona u ta teka vana va vona va vaxisati u va nyika vana va wena va majaha, vana va vona va vaxisati va ta hambukela swikwembu swa vona, va endla leswaku vana va wena va majaha va hambukela swikwembu swa vona.\u2019' },
    { n: 17, text: '\u2018U nga tshuki u tiendlela swikwembu swa ku fayetela.\u2019' },
    { n: 18, text: '\u2018U ta hlayisa nkhuvo wa xinkwa lexi nga riki na comela; masiku ya nkombo mi ta dya xinkwa lexi nga riki na comela, hilaha ndzi mi leriseke hakona, hi nkarhi lowu vekiweke wa n\u2019weti wa Abibi, hikuva mi hume etikweni ra Egipta hi n\u2019weti wolowo.\u2019' },
    { n: 19, text: '\u2018Hinkwaswo leswi pfulaka nkolo i swa mina, ni swiharhi hinkwaswo swa n\u2019wina, swinkonyana kumbe swimbutana.\u2019' },
    { n: 20, text: '\u2018Kambe ntlhanu wa mbongolo u ta wu kutsula hi nyimpfu; loko u nga wu kutsuli, u ta wu fayetela khosi ya wona; u ta kutsula vana va wena va majaha hinkwavo, naswona a ku na munhu loyi a nga ta humelela mahlweni ka mina a ri loyi a nga riki na nchumu.\u2019' },
    { n: 21, text: '\u2018Masiku ya tsevu mi ta endla ntirho, kambe hi siku ra vunkombo mi ta wisa, hambi ku va hi nkarhi wa ku byala kumbe hi nkarhi wa ku hlengeleta.\u2019' },
    { n: 22, text: '\u2018U ta endla nkhuvo wa mavhiki, wa mintirho yo sungula ya ku hlengeleta koroni, ni nkhuvo wa ku hlengeleta hi ku hela ka lembe.\u2019' },
    { n: 23, text: '\u2018Kanharhu hi lembe, vaxinuna hinkwavo va n\u2019wina va ta humelela mahlweni ka Yehovha Xikwembu, Xikwembu xa Israyele.\u2019' },
    { n: 24, text: '\u2018Hikuva ndzi ta hlongola vamatiko mahlweni ka n\u2019wina, ndzi ta andzisa ndzilakano wa n\u2019wina; a ku na munhu loyi a nga ta navela tiko ra n\u2019wina loko mi tlhandlukela ku humelela mahlweni ka Yehovha Xikwembu xa n\u2019wina, kanharhu hi lembe.\u2019' },
    { n: 25, text: '\u2018U nga tshuki u nyikela ngati ya xitlhavelo xa mina xikan\u2019we ni xinkwa lexi nga na comela; naswona xitlhavelo xa nkhuvo wa ku tswariwa ka swilo a xi nga tshikiwi ku fikela nimixo.\u2019' },
    { n: 26, text: '\u2018Mintirho yo sungula ya mihandzu ya misava ya wena, u ta yi tisa endlwini ya Yehovha Xikwembu xa wena. U nga tshuki u sweka ximbutana hi ntswamba wa manana wa xona.\u2019' },
    { n: 27, text: 'Yehovha a ku eka Moxe: \u2018Tsala marito lawa, hikuva hi marito lawa ndzi endle ntwanano na wena ni na Israyele.\u2019' },
    { n: 28, text: 'A va entshaveni hi masiku ya mune-ntlhanu ni mune-vusiku; a nga dyanga xinkwa, a nga nwanganga mati. A tsala ehenhla ka maribye marito ya ntwanano, marito ya khume.' },
    { n: 29, text: 'Loko Moxe a rhela entshaveni ya Sinayi, Moxe a ri ni maribye mambirhi ya vumbhoni evokweni ra yena, loko a rhela entshaveni, Moxe a a nga tivi leswaku xikandza xa yena xi voningile hi ku vulavula na Yehovha.' },
    { n: 30, text: 'Aroni ni vana va Israyele hinkwavo va vona Moxe, vonani, xikandza xa yena xi voningile; va chava ku tshinela ekusuhi na yena.' },
    { n: 31, text: 'Moxe a va vitana, Aroni ni varhangeli hinkwavo va ntshungu va tlhelela eka yena, Moxe a vulavula na vona.' },
    { n: 32, text: 'Endzhaku ka swona vana va Israyele hinkwavo va tshinela, a va lerisa hinkwaswo leswi Yehovha a n\u2019wi byeleke swona entshaveni ya Sinayi.' },
    { n: 33, text: 'Moxe a heta ku vulavula na vona, a funengeta xikandza xa yena hi xifunengeto.' },
    { n: 34, text: 'Loko Moxe a nghena mahlweni ka Yehovha leswaku a vulavula na yena, a hluva xifunengeto, ku fikela loko a huma; a huma, a byela vana va Israyele hinkwaswo leswi a lerisiweke swona.' },
    { n: 35, text: 'Vana va Israyele va vona xikandza xa Moxe, leswaku xikandza xa Moxe xi voningile, kutani Moxe a tlhela a funengeta xikandza xa yena hi xifunengeto, ku fikela loko a nghena a ya vulavula na Yehovha.' },
  ],
  35: [
    { n: 1, text: 'Moxe a hlengeleta vana va Israyele hinkwavo, a ku eka vona: \u201cLeswi i swilo leswi Yehovha a leriseke leswaku mi swi endla.\u201d' },
    { n: 2, text: '\u201cMasiku ya tsevu mi ta endla ntirho, kambe hi siku ra vunkombo mi ta va ni masabata ya ku wisa, ya ku kwetsima eka Yehovha; loyi a endlaka ntirho ha wona u ta fa.\u201d' },
    { n: 3, text: '\u201cMi nga tshuki mi tshivela ndzilo etendeni ra n\u2019wina hi siku ra masabata.\u201d' },
    { n: 4, text: 'Moxe a vulavula ni vana va Israyele hinkwavo, a ku: \u201cLeswi i rito leri Yehovha a leriseke rona:\u201d' },
    { n: 5, text: '\u201cTekani exikarhi ka n\u2019wina munyikelo eka Yehovha; un\u2019wana ni un\u2019wana loyi a nga ni mbilu ya ku rhandza, a a tise munyikelo wa Yehovha: nsuku, ni silivhere, ni koporo,\u201d' },
    { n: 6, text: '\u201cntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave, ni voya bya mbuti,\u201d' },
    { n: 7, text: '\u201cni nhlonge ya tihomu ta ntswamba leti khavisiweke, ni nhlonge ya tibadger, ni mhandzi ya xitachi,\u201d' },
    { n: 8, text: '\u201cni mafurha ya rivoningo, ni swirungo swa mafurha ya ku tota, ni swirungo swa nun\u2019hwelo,\u201d' },
    { n: 9, text: '\u201cni maribye ya onyx, ni maribye ya ku vekiwa ehenhla ka ephod, ni xifuva.\u201d' },
    { n: 10, text: '\u201cHinkwavo lava tlhariheke exikarhi ka n\u2019wina, va ta ta, va endla hinkwaswo leswi Yehovha a leriseke swona:\u201d' },
    { n: 11, text: '\u201ctabernakela, ni tende ra yona, ni xifunengeto xa yona, ni swikhomo swa yona, ni timhandzi ta yona, ni swisekelo swa yona,\u201d' },
    { n: 12, text: '\u201careka ni timhandzi ta yona, ni xifunengeto, ni nkhombolo wa ndhawu yo kwetsima,\u201d' },
    { n: 13, text: '\u201ctafula ni timhandzi ta rona, ni swibye swa rona, ni xinkwa xa vumbhoni,\u201d' },
    { n: 14, text: '\u201cxitirho xa rivoningo, ni swibye swa xona, ni rivoningo, ni mafurha ya rivoningo,\u201d' },
    { n: 15, text: '\u201calitari ya nun\u2019hwelo ni timhandzi ta yona, ni mafurha ya ku tota, ni nun\u2019hwelo wa swirungo, ni nkhombolo wa munyangweni wa tabernakela,\u201d' },
    { n: 16, text: '\u201calitari ya xitlhavelo xo hisiwa ni xikhomo xa koporo, ni timhandzi ta yona, ni swibye swa yona hinkwaswo, ni xibye xa mati ni xisekelo xa xona,\u201d' },
    { n: 17, text: '\u201cmakhumbi ya rivale, ni timhandzi ta rona, ni swisekelo swa rona, ni nkhombolo wa munyangweni wa rivale,\u201d' },
    { n: 18, text: '\u201cswikhomo swa tabernakela, ni swikhomo swa rivale, ni tinguvu ta tona,\u201d' },
    { n: 19, text: '\u201ctinguvu to kwetsima eka Aroni muprista, ni tinguvu ta vana va yena leswaku va va vaprista.\u201d' },
    { n: 20, text: 'Vana hinkwavo va Israyele va huma mahlweni ka Moxe.' },
    { n: 21, text: 'Un\u2019wana ni un\u2019wana loyi mbilu ya yena yi n\u2019wi susumeteke, loyi moya wa yena wu n\u2019wi nyikeleke, va tisa munyikelo wa Yehovha wa tabernakela ya nhlanganiso, ni wa swilo hinkwaswo swa ntirho wa yona, ni wa tinguvu to kwetsima.' },
    { n: 22, text: 'Va tisa vaxinuna ni vaxisati; hinkwavo lava va ri ni mbilu ya ku rhandza, va tisa swiambalo, ni swikhomo, ni swihlampfi, ni swilo swa nsuku; un\u2019wana ni un\u2019wana u tisa munyikelo wa nsuku eka Yehovha.' },
    { n: 23, text: 'Hinkwavo lava va ri ni ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave, ni voya bya mbuti, ni nhlonge ya tihomu ta ntswamba, ni nhlonge ya tibadger, va tisa.' },
    { n: 24, text: 'Hinkwavo lava tiseke munyikelo wa silivhere ni koporo, va tisa munyikelo eka Yehovha; hinkwavo lava va ri ni mhandzi ya xitachi ya ntirho hinkwawo, va tisa.' },
    { n: 25, text: 'Vaxisati hinkwavo lava tlhariheke va rhunga hi mavoko ya vona, va tisa leswi va swi rhungiseke, ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave.' },
    { n: 26, text: 'Vaxisati hinkwavo lava mbilu ya vona yi va susumeteke hi vutlhari, va rhunga voya bya mbuti.' },
    { n: 27, text: 'Varhangeli va tisa maribye ya onyx, ni maribye ya ku vekiwa ehenhla ka ephod, ni xifuva,' },
    { n: 28, text: 'ni swirungo, ni mafurha ya rivoningo, ni mafurha ya ku tota, ni nun\u2019hwelo wa swirungo.' },
    { n: 29, text: 'Vana va Israyele va tisa munyikelo wa ku rhandza eka Yehovha, vaxinuna ni vaxisati, hinkwavo lava mbilu ya vona yi va susumeteke ku endla ntirho hinkwawo lowu Yehovha a leriseke Moxe.' },
    { n: 30, text: 'Moxe a ku eka vana va Israyele: \u201cVona, Yehovha u vitane Bezalele, n\u2019wana wa Uri, n\u2019wana wa Huri, wa ntsawa wa Yuda,\u201d' },
    { n: 31, text: '\u201cndzi n\u2019wi tate hi moya wa Xikwembu, hi vutlhari, ni ku twisisa, ni vutivi, ni mintirho hinkwayo,\u201d' },
    { n: 32, text: '\u201cku endla mintirho ya nsuku, ni silivhere, ni koporo,\u201d' },
    { n: 33, text: '\u201cku tsema maribye, ni ku rhunga, ni mintirho hinkwayo ya mhandzi.\u201d' },
    { n: 34, text: '\u201cU n\u2019wi nyike vutlhari bya ku dyondzisa, yena ni Oholiabe, n\u2019wana wa Ahisamake, wa ntsawa wa Dani.\u201d' },
    { n: 35, text: '\u201cU va tate hi vutlhari bya ku endla ntirho hinkwawo wa muvumbi, ni wa ku rhunga, ni wa ku rhunga hi ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave, ni ku rhunga; va endla mintirho hinkwayo.\u201d' },
  ],
  36: [
    { n: 1, text: 'Bezalele, ni Oholiabe, ni hinkwavo lava va tlhariheke, lava Yehovha a va nyikeke vutlhari, va endla ntirho hinkwawo wa ndhawu yo kwetsima.' },
    { n: 2, text: 'Moxe a vitana Bezalele, ni Oholiabe, ni hinkwavo lava va tlhariheke, lava Yehovha a va nyikeke vutlhari, hinkwavo lava mbilu ya vona yi va susumeteke ku ta endloni.' },
    { n: 3, text: 'Va teka munyikelo hinkwawo lowu vana va Israyele va wu tiseke; va hambeta va tisa munyikelo wa ku rhandza nimixo ni nimixo.' },
    { n: 4, text: 'Hinkwavo lava va tlhariheke lava a va endla ntirho wa ndhawu yo kwetsima, va huma eka ntirho lowu a va wu endla,' },
    { n: 5, text: 'va ku eka Moxe: \u201cVanhu va tisa ku tlula leswi nga lavekaka eka ntirho wa ndhawu leyi Yehovha a leriseke ku yi endla.\u201d' },
    { n: 6, text: 'Moxe a lerisa leswaku ku huweleliwa etindhawini hinkwato, a ku: \u201cVaxinuna ni vaxisati, mi nga ha endli munyikelo wa ndhawu yo kwetsima.\u201d Vanhu va yima ku tisa.' },
    { n: 7, text: 'Hikuva swilo leswi va swi tiseke a swi ringene eka ntirho hinkwawo, swi tlula.' },
    { n: 8, text: 'Hinkwavo lava va tlhariheke va endla tabernakela hi malapi ya khume ya ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave; va endla makerubi hi ku ma fula, hi ntirho wa ntlhandlhi.' },
    { n: 9, text: 'Ku leha ka lapi rin\u2019we i tinyanya ta makume-mbirhi ni nhungu, ni ku anama ka lapi rin\u2019we i tinyanya ta mune; malapi hinkwawo ma ta va ni mpimo wun\u2019we.' },
    { n: 10, text: 'Va hlanganisa malapi ya ntlhanu, ni malapi man\u2019wana ya ntlhanu ma hlanganisiweke.' },
    { n: 11, text: 'Va endla mahlwa ya ntsemba wa vumfumi etlhelo ra lapi rin\u2019we, exihlameni xa nhlanganiso; va endla tano hi lapi ro hetelela erivaleni ra ntlhanu wa malapi.' },
    { n: 12, text: 'Va endla mahlwa ya makume-ntlhanu elapi rin\u2019we, va endla mahlwa ya makume-ntlhanu emakumu ya lapi leri nga erivaleni ra ntlhanu wa malapi; mahlwa ma langutana.' },
    { n: 13, text: 'Va endla swikhomo swa nsuku swa makume-ntlhanu, va hlanganisa malapi hi swikhomo, leswaku tabernakela yi va yin\u2019we.' },
    { n: 14, text: 'Va endla malapi ya nhlonge ya mbuti ku va ntsimba ehenhla ka tabernakela; va endla malapi ya khume-n\u2019we.' },
    { n: 15, text: 'Ku leha ka lapi rin\u2019we i tinyanya ta makume-ntlhanu, ni ku anama ka lapi rin\u2019we i tinyanya ta mune; malapi ya khume-n\u2019we ma ta va ni mpimo wun\u2019we.' },
    { n: 16, text: 'Va hlanganisa malapi ya ntlhanu hi voxe, ni malapi ya tsevu hi voxe.' },
    { n: 17, text: 'Va endla mahlwa ya makume-ntlhanu elapi rin\u2019we ra nhlanganiso, ni mahlwa ya makume-ntlhanu elapi rin\u2019we ra nhlanganiso.' },
    { n: 18, text: 'Va endla swikhomo swa koporo swa makume-ntlhanu, va hlanganisa ntsimba leswaku yi va yin\u2019we.' },
    { n: 19, text: 'Va endla xifunengeto xa nhlonge ya tihomu ta ntswamba leti khavisiweke, ni xifunengeto xa nhlonge ya tibadger ehenhla.' },
    { n: 20, text: 'Va endla makhumbi ya tabernakela hi mhandzi ya xitachi, ya yima.' },
    { n: 21, text: 'Ku leha ka mhandzi i tinyanya ta khume, ni ku anama ka mhandzi i tinyanya ta n\u2019we ni hafu.' },
    { n: 22, text: 'Mhandzi yin\u2019we ni yin\u2019we yi ta va ni swikhomo swimbirhi, swi hlanganisiweke; va endla tano hi makhumbi hinkwawo ya tabernakela.' },
    { n: 23, text: 'Va endla makhumbi ya tabernakela, makhumbi ya makume-mbirhi etlhelweni ra dzonga.' },
    { n: 24, text: 'Va endla swisekelo swa silivhere swa makume-mune ehansi ka makhumbi ya makume-mbirhi, swisekelo swimbirhi ehansi ka mhandzi yin\u2019we, ni swisekelo swimbirhi ehansi ka mhandzi yin\u2019we.' },
    { n: 25, text: 'Etlhelweni ra n\u2019walungu ra tabernakela, makhumbi ya makume-mbirhi,' },
    { n: 26, text: 'ni swisekelo swa silivhere swa makume-mune, swisekelo swimbirhi ehansi ka mhandzi yin\u2019we.' },
    { n: 27, text: 'Emakumu ya tabernakela etlhelweni ra vupela-dyambu va endla makhumbi ya ntlhanu.' },
    { n: 28, text: 'Va endla makhumbi mambirhi emakumu ya tabernakela.' },
    { n: 29, text: 'Ma va ma hlanganisiweke ehansi, ma va ma hlanganisiweke ehenhla hi xikhomo xin\u2019we; va endla tano hi mambirhi ya wona.' },
    { n: 30, text: 'Ma va makhumbi ya nhungu, ni swisekelo swa silivhere swa khume-mune, swisekelo swimbirhi ehansi ka mhandzi yin\u2019we.' },
    { n: 31, text: 'Va endla timhandzi ta mhandzi ya xitachi, ya ntlhanu emakhumbini ya tlhelo rin\u2019we ra tabernakela,' },
    { n: 32, text: 'ni timhandzi ta ntlhanu emakhumbini ya tlhelo ra vupela-dyambu.' },
    { n: 33, text: 'Mhandzi ya le xikarhi yi hundza emakhumbini, yi suka etlhelweni rin\u2019we ku ya eka rin\u2019we.' },
    { n: 34, text: 'Va ambexa makhumbi hi nsuku, va endla swikhomo swa nsuku swa timhandzi, va ambexa timhandzi hi nsuku.' },
    { n: 35, text: 'Va endla nkhombolo hi ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave, va endla makerubi hi ntirho wa ntlhandlhi.' },
    { n: 36, text: 'Va endla timhandzi ta mhandzi ya xitachi, va ti ambexa hi nsuku, ni swikhomo swa nsuku, va swi yimisa ehenhla ka swisekelo swa silivhere swa mune.' },
    { n: 37, text: 'Va endla nkhombolo emunyangweni wa ntsimba hi ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave, hi ku rhunga;' },
    { n: 38, text: 'ni timhandzi ta ntlhanu ni swikhomo swa tona, va ambexa timhandzi hi nsuku, ni swikhomo swa nsuku swa ntlhanu.' },
  ],
  37: [
    { n: 1, text: 'Bezalele a endla areka hi mhandzi ya xitachi; ku leha ka yona i tinyanya ta mbirhi ni hafu, ni ku anama ka yona i tinyanya ta n\u2019we ni hafu, ni ku tlakuka ka yona i tinyanya ta n\u2019we ni hafu.' },
    { n: 2, text: 'A yi ambexa hi nsuku lowo tengamela endzeni ni handle, a yi endlela nkhombolo wa nsuku ku rhendzela.' },
    { n: 3, text: 'A yi endlela swikhomo swa nsuku swa mune emakumu ya yona ya mune, swikhomo swimbirhi etlhelweni rin\u2019we, ni swikhomo swimbirhi etlhelweni rin\u2019we.' },
    { n: 4, text: 'A endla timhandzi ta mhandzi ya xitachi, a ti ambexa hi nsuku.' },
    { n: 5, text: 'A nghenisa timhandzi eswikhomweni ematlhelweni ya areka, to rhwala areka.' },
    { n: 6, text: 'A endla xifunengeto hi nsuku lowo tengamela; ku leha ka xona i tinyanya ta mbirhi ni hafu, ni ku anama ka xona i tinyanya ta n\u2019we ni hafu.' },
    { n: 7, text: 'A endla makerubi mambirhi hi nsuku, a ma endla hi ku ma fula, emakumu mambirhi ya xifunengeto.' },
    { n: 8, text: 'Kerubi rin\u2019we emakumu ya n\u2019we, ni kerubi rin\u2019we emakumu ya n\u2019wana, emakumu ya xifunengeto.' },
    { n: 9, text: 'Makerubi ma angarha hi timpapa ta wona ehenhla, ma funengeta xifunengeto hi timpapa ta wona, ma langutana; mahlweni ka xifunengeto makerubi ma langutana.' },
    { n: 10, text: 'A endla tafula hi mhandzi ya xitachi; ku leha ka rona i tinyanya ta mbirhi, ni ku anama ka rona i tinyanya ta n\u2019we, ni ku tlakuka ka rona i tinyanya ta n\u2019we ni hafu.' },
    { n: 11, text: 'A ri ambexa hi nsuku lowo tengamela, a ri endlela nkhombolo wa nsuku ku rhendzela.' },
    { n: 12, text: 'A ri endlela nkolo wa vutlhari, ni nkhombolo wa nsuku ku rhendzela nkolo.' },
    { n: 13, text: 'A ri endlela swikhomo swa nsuku swa mune, a swi veka emakumu mambirhi ya milenge ya rona.' },
    { n: 14, text: 'Swikhomo a swi ri kusuhi ni nkolo, ku va switirho swa timhandzi to rhwala tafula.' },
    { n: 15, text: 'A endla timhandzi ta mhandzi ya xitachi to rhwala tafula, a ti ambexa hi nsuku.' },
    { n: 16, text: 'A endla swibye leswi nga ehenhla ka tafula, swibye swa rona, ni swikhavu swa rona, ni swikho swa rona, ni swibye swa rona swa ku chela, hi nsuku lowo tengamela.' },
    { n: 17, text: 'A endla xitirho xa rivoningo hi nsuku lowo tengamela; a endla xitirho hi ku xi fula, ni xitirho xa xona, ni swikhomo swa xona, ni makerubi ya xona, ni swimaluva swa xona, hi nsuku wun\u2019we.' },
    { n: 18, text: 'Timpapa ta tsevu ti huma ematlhelweni ya xona, timpapa ta nharhu ta xitirho xa rivoningo etlhelweni rin\u2019we, ni timpapa ta nharhu ta xitirho xa rivoningo etlhelweni rin\u2019we.' },
    { n: 19, text: 'Timpapa ta nharhu ti fana ni swimaluva hi ximfuno xa alimondi, ni swikhomo swa xona, ni swimaluva swa xona; hi tano eka timpapa ta tsevu leti humaka exitalweni.' },
    { n: 20, text: 'Ehenhla ka xitirho xa rivoningo a ku ri ni swimaluva swa mune hi ximfuno xa alimondi, ni swikhomo swa xona, ni swimaluva swa xona.' },
    { n: 21, text: 'Swikhomo swimbirhi swi huma ehansi ka timpapa ta timbirhi, swikhomo swimbirhi swi huma ehansi ka timpapa ta timbirhi, swikhomo swimbirhi swi huma ehansi ka timpapa ta timbirhi, hi tano eka timpapa ta tsevu leti humaka eka xona.' },
    { n: 22, text: 'Swikhomo swa tona ni timpapa ta tona a ti huma eka xona; hinkwaswo a ku ri ntirho wun\u2019we wa nsuku lowo tengamela.' },
    { n: 23, text: 'A endla rivoningo ra yona ra ntlhanu ni n\u2019we, ni swikhavu swa rona, ni swibye swa rona swa ndzilo, hi nsuku lowo tengamela.' },
    { n: 24, text: 'A endla xitirho ni swibye swa xona hinkwaswo hi nsuku lowo tengamela wa talente yin\u2019we.' },
    { n: 25, text: 'A endla alitari ya nun\u2019hwelo hi mhandzi ya xitachi; ku leha ka yona i tinyanya ta n\u2019we, ni ku anama ka yona i tinyanya ta n\u2019we, ni ku tlakuka ka yona i tinyanya ta mbirhi; timhondzo ta yona ti ta va xikan\u2019we na yona.' },
    { n: 26, text: 'A yi ambexa hi nsuku lowo tengamela, enhlohlo ya yona, ni matlhelo ya yona ku rhendzela, ni timhondzo ta yona; a yi endlela nkhombolo wa nsuku ku rhendzela.' },
    { n: 27, text: 'A yi endlela swikhomo swa nsuku swa mune, swikhomo swimbirhi etlhelweni rin\u2019we, ni swikhomo swimbirhi etlhelweni rin\u2019we, to rhwala timhandzi.' },
    { n: 28, text: 'A endla timhandzi hi mhandzi ya xitachi, a ti ambexa hi nsuku.' },
    { n: 29, text: 'A endla mafurha ya ku tota yo kwetsima, ni nun\u2019hwelo wa swirungo wa ku tengisa, hi ntirho wa muvumbi wa swirungo.' },
  ],
  38: [
    { n: 1, text: 'A endla alitari ya xitlhavelo xo hisiwa hi mhandzi ya xitachi; ku leha ka yona i tinyanya ta nhungu, ni ku anama ka yona i tinyanya ta nhungu, ni ku tlakuka ka yona i tinyanya ta mune.' },
    { n: 2, text: 'A endla timhondzo ta yona emakumu ya yona ya mune, timhondzo ta yona ti va xikan\u2019we na yona, a yi ambexa hi koporo.' },
    { n: 3, text: 'A endla swibye swa yona hinkwaswo, swikhavu, ni swikho, ni swibye swa ndzilo, swibye hinkwaswo swa yona a swi endla hi koporo.' },
    { n: 4, text: 'A yi endlela xikhomo xa koporo, hi ntirho wa mhandzi, ni swikhomo swa koporo swa mune emakumu ya yona ya mune.' },
    { n: 5, text: 'A yi veka ehansi ka nkhombolo wa alitari, leswaku xikhomo xi va exikarhi ka alitari.' },
    { n: 6, text: 'A endla timhandzi ta mhandzi ya xitachi, a ti ambexa hi koporo.' },
    { n: 7, text: 'A nghenisa timhandzi eswikhomweni, leswaku ti va etlhelweni ra alitari loko yi rhwaliwa; a endla alitari hi mapuranka, ya mune wa matlhelo.' },
    { n: 8, text: 'A endla xibye xa mati hi koporo, ni xisekelo xa xona xa koporo, hi swikho swa vaxisati lava a va tirha emunyangen wa tabernakela ya nhlanganiso.' },
    { n: 9, text: 'A endla rivale; etlhelweni ra dzonga, malapi ya rivale ma va hi ntsemba wa vumfumi, ya tinyanya ta dzana.' },
    { n: 10, text: 'Ni mhandzi ya makume-mbirhi, ni swisekelo swa koporo swa makume-mbirhi, ni swikhomo swa silivhere swa timhandzi.' },
    { n: 11, text: 'Hi tlhelo ra n\u2019walungu malapi ma va ya tinyanya ta dzana, ni timhandzi ta makume-mbirhi, ni swisekelo swa koporo swa makume-mbirhi.' },
    { n: 12, text: 'Etlhelweni ra vupela-dyambu malapi ya va ya tinyanya ta ntlhanu, ni timhandzi ta ntlhanu, ni swisekelo swa ntlhanu.' },
    { n: 13, text: 'Etlhelweni ra vuxa, hi ku anama, malapi ya va ya tinyanya ta ntlhanu.' },
    { n: 14, text: 'Malapi ya tinyanya ta ntlhanu etlhelweni rin\u2019we, ni timhandzi ta nhungu, ni swisekelo swa nhungu.' },
    { n: 15, text: 'Etlhelweni rin\u2019we, malapi ya va ya tinyanya ta ntlhanu, ni timhandzi ta nhungu, ni swisekelo swa nhungu.' },
    { n: 16, text: 'Hinkwaswo swiambalo swa rivale ku rhendzela a swi va hi ntsemba wa vumfumi.' },
    { n: 17, text: 'Swisekelo swa timhandzi a swi va hi koporo, swikhomo swa timhandzi a swi va hi silivhere, ni swikhomo swa timhandzi hinkwato ta rivale a swi va hi silivhere.' },
    { n: 18, text: 'Nkhombolo wa munyangweni wa rivale a wu va hi ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave, hi ku rhunga; ku leha ka wona tinyanya ta makume-mbirhi, ni ku tlakuka ka wona hi ku anama tinyanya ta ntlhanu.' },
    { n: 19, text: 'Timhandzi ta mune ni swisekelo swa koporo swa mune, swikhomo swa silivhere, ni swikhomo swa timhandzi a swi va hi silivhere.' },
    { n: 20, text: 'Swikhomo hinkwaswo swa tabernakela ni rivale a swi va hi koporo.' },
    { n: 21, text: 'Lawa i matimu ya tabernakela, tabernakela ya vumbhoni, lawa ma hlayiweke hi ku lerisa ka Moxe, ntirho wa Valevi, hi Bezalele, n\u2019wana wa Uri, n\u2019wana wa Huri, wa ntsawa wa Yuda.' },
    { n: 22, text: 'Oholiabe, n\u2019wana wa Ahisamake, wa ntsawa wa Dani, a a ri na yena, muvumbi ni muendli wa mintirho, ni murohi hi ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave.' },
    { n: 23, text: 'Nsuku hinkwawo lowu tirhisiweke, hi nsuku wa munyikelo, a wu va wa talente ta makume-mbirhi-tsevu ni makume-mbirhi ya xikhele.' },
    { n: 24, text: 'Silivhere ya lava hlayiweke hi nkutsulo a yi va ya talente ta dzana, ni makume-mbirhi-tsevu ni nhungu ya xikhele.' },
    { n: 25, text: 'Hafu ya xikhele hi munhu, hi mpimo wa vutomi bya vutomi, eka hinkwavo lava hlayiweke, va makume-mbirhi ya malembe ku ya ehenhla, va va madzana-madzana ya magidi ni makume-mbirhi-ntsevu ni ntlhanu wa madzana ya magidi.' },
    { n: 26, text: 'Talente ta dzana ta silivhere a ti tirhisiwa ku endla swisekelo swa ndhawu yo kwetsima ni swisekelo swa nkhombolo; swisekelo swa dzana, talente ta dzana, talente yin\u2019we hi xisekelo.' },
    { n: 27, text: 'Eka makume-mbirhi-ntsevu na nhungu ya xikhele, a endla swikhomo swa timhandzi, a ambexa timhandzi.' },
    { n: 28, text: 'Koporo ya munyikelo a yi va ya talente ta makume-mune-ntsevu, ni dzana-ntsevu ya xikhele.' },
    { n: 29, text: 'Hi yona a endla swisekelo swa munyangweni wa tabernakela ya nhlanganiso, ni alitari ya koporo ni xikhomo xa koporo, ni swibye swa alitari.' },
    { n: 30, text: 'Ni swisekelo swa rivale ku rhendzela, ni swisekelo swa nkhombolo wa munyangweni wa rivale, ni swikhomo hinkwaswo swa tabernakela, ni swikhomo hinkwaswo swa rivale ku rhendzela.' },
  ],
  39: [
    { n: 1, text: 'Hi ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave, va endla tinguvu to kwetsima eka Aroni, va endla tinguvu to kwetsima hilaha Yehovha a leriseke Moxe.' },
    { n: 2, text: 'A endla ephod hi nsuku, ni ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave.' },
    { n: 3, text: 'Va fayetela nsuku, va endla swiphemu, va endla ntirho wa ntlhandlhi, va endla ntirho wa nsuku, ni ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave.' },
    { n: 4, text: 'Va endla swikhomo swimbirhi, swi hlanganisiweke emakumu ya yona mambirhi.' },
    { n: 5, text: 'Bhande ra ephod leri nga ehenhla ka yona, hi nsuku, ni ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave, hilaha Yehovha a leriseke Moxe.' },
    { n: 6, text: 'Va endla maribye ya onyx, ma vekiwe eswikhomweni swa nsuku, ma tsaleriwile tanihi ku tsala ka mfungho, mavito ya vana va Israyele.' },
    { n: 7, text: 'A ma veka ehenhla ka swikhomo swa ephod, maribye ya vutsundzuxo eka vana va Israyele, hilaha Yehovha a leriseke Moxe.' },
    { n: 8, text: 'A endla xifuva hi ntirho wa ntlhandlhi, hi nsuku, ni ntsemba wa vumfumi, ni ntsalu wa rila, ni ntsemba wa ntswamba, ni ntsemba wa xichave.' },
    { n: 9, text: 'Xi va xa mune wa matlhelo, xi phutsiwile; tinyanya ta n\u2019we ku leha ka xona, ni tinyanya ta n\u2019we ku anama ka xona.' },
    { n: 10, text: 'Va veka ehenhla ka xona swiphemu swa maribye swa mune: ribye ra sardius, ni topaz, ni emerald, i swiphemu swa mune.' },
    { n: 11, text: 'Xiphemu xa vumbirhi: turquoise, ni sapphire, ni diamond.' },
    { n: 12, text: 'Xiphemu xa vunharhu: jacinth, ni agate, ni amethyst.' },
    { n: 13, text: 'Xiphemu xa mune: beryl, ni onyx, ni jasper; ma vekiwa eswikhomweni swa nsuku.' },
    { n: 14, text: 'Maribye a ma va hi mavito ya vana va Israyele, khume-mbirhi hi mavito ya vona, tanihi ku tsala ka mfungho, rin\u2019we ni rin\u2019we ri va ni vito ra wona eka tinxaka ta khume-mbirhi.' },
    { n: 15, text: 'Va endla ehenhla ka xifuva swikhomo swa ku rhunga, swa nsuku lowu tengamela.' },
    { n: 16, text: 'Va endla swikhomo swimbirhi swa nsuku, ni swikhomo swimbirhi swa nsuku, va veka swikhomo swimbirhi emakumu mambirhi ya xifuva.' },
    { n: 17, text: 'Va veka swikhomo swimbirhi swa nsuku ehenhla ka swikhomo swimbirhi, va swi veka emakumu ya ephod.' },
    { n: 18, text: 'Swikhomo swimbirhi va swi veka emakumu mambirhi ya xifuva, etlhelweni ra ephod.' },
    { n: 19, text: 'Va endla swikhomo swimbirhi swa nsuku, va swi veka emakumu mambirhi ya ephod, etlhelweni ra bhande.' },
    { n: 20, text: 'Va hlanganisa xifuva ni swikhomo swa ephod hi ntsemba wa ntswamba, leswaku xi va ehenhla ka bhande ra ephod, hilaha Yehovha a leriseke Moxe.' },
    { n: 21, text: 'Va endla nkhombolo wa ephod hi ntsemba wa ntswamba ntsena.' },
    { n: 22, text: 'Yi va ni mbilu ehenhla, ni nkhombolo wu va wa ku rhunga, tanihi mbilu ya xihuku, leswaku yi nga handzuki.' },
    { n: 23, text: 'Ehenhla ka xifuva va endla timagranata ta ntsemba wa ntswamba, ni ntsemba wa vumfumi, ni ntsalu wa rila.' },
    { n: 24, text: 'Va endla ntsimbiri wa nsuku exikarhi ka timagranata, ntsimbiri wa nsuku ni timagranata, ehenhla ka xifuva ku rhendzela.' },
    { n: 25, text: 'Aroni a yi ambara loko a tirha, rito ra ntsimbiri ri twala loko a nghena endhawini yo kwetsima mahlweni ka Yehovha, ni loko a huma, hilaha Yehovha a leriseke Moxe.' },
    { n: 26, text: 'Va endla xifuwu xa nsuku lowo tengamela, va tsala ehenhla ka xona: \u201cKu Kwetsima ka Yehovha.\u201d' },
    { n: 27, text: 'Va xi veka hi ntsemba wa ntswamba ehenhla ka xihuku.' },
    { n: 28, text: 'Va rhunga nkhombolo hi ntsemba wa vumfumi, va endla xihuku hi ntsemba wa vumfumi, va endla bhande hi ntirho wa ku rhunga.' },
    { n: 29, text: 'Va endla nkhombolo eka vana va Aroni, va va endlela mabhante, va va endlela swihuku, swa ku dzunisa ni ku sasekisa, hilaha Yehovha a leriseke Moxe.' },
    { n: 30, text: 'Va endla mabhulukwe ya nhlonge, leswaku va funengeta mbilu ya vona; ma va kusukela elun\u2019wini ku ya fika emilengeni.' },
    { n: 31, text: 'Ntirho hinkwawo wa tabernakela ya nhlanganiso wu hela; vana va Israyele va endla hinkwaswo hilaha Yehovha a leriseke Moxe.' },
    { n: 32, text: 'Va tisa tabernakela eka Moxe, ni swibye swa yona hinkwaswo, ni swikhomo swa yona, ni timhandzi ta yona, ni swisekelo swa yona,' },
    { n: 33, text: 'ni xifunengeto xa nhlonge ya tihomu ta ntswamba, ni xifunengeto xa nhlonge ya tibadger, ni nkhombolo wa ndhawu yo kwetsima,' },
    { n: 34, text: 'ni areka ya vumbhoni ni timhandzi ta yona, ni xifunengeto,' },
    { n: 35, text: 'ni tafula ni swibye swa rona hinkwaswo, ni xinkwa xa vumbhoni,' },
    { n: 36, text: 'ni xitirho xa rivoningo ni swibye swa xona, ni rivoningo ni mafurha ya rivoningo,' },
    { n: 37, text: 'ni alitari ya nun\u2019hwelo ni mafurha ya ku tota, ni nun\u2019hwelo wa swirungo, ni nkhombolo wa munyangweni wa tabernakela,' },
    { n: 38, text: 'ni alitari ya koporo ni xikhomo xa koporo, ni timhandzi ta yona, ni swibye swa yona hinkwaswo, ni xibye xa mati ni xisekelo xa xona,' },
    { n: 39, text: 'ni makhumbi ya rivale, ni timhandzi ta rona, ni swisekelo swa rona, ni nkhombolo wa munyangweni wa rivale, ni swikhomo swa rona, ni tinguvu ta tona,' },
    { n: 40, text: 'ni tinguvu to kwetsima eka Aroni muprista, ni tinguvu ta vana va yena leswaku va va vaprista.' },
    { n: 41, text: 'Vana va Israyele va endla hinkwaswo hilaha Yehovha a leriseke Moxe.' },
    { n: 42, text: 'Moxe a vona ntirho hinkwawo, a vona leswaku va wu endle hilaha Yehovha a leriseke hakona; Moxe a va katekisa.' },
  ],
  40: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Hi siku ro sungula ra n’weti wo sungula, u ta yimisa tabernakela ya tabernakela ya nhlanganiso.”' },
    { n: 3, text: '“U ta veka areka ya vumbhoni endzeni, u yi funengeta hi nkhombolo.”' },
    { n: 4, text: '“U ta nghenisa tafula, u veka swilo swa rona; u ta nghenisa xitirho xa rivoningo, u lumeka rivoningo ra xona.”' },
    { n: 5, text: '“U ta veka alitari ya nsuku ya nun’hwelo mahlweni ka areka ya vumbhoni, u endla nkhombolo wa munyangweni wa tabernakela.”' },
    { n: 6, text: '“U ta veka alitari ya xitlhavelo xo hisiwa mahlweni ka munyango wa tabernakela ya nhlanganiso.”' },
    { n: 7, text: '“U ta veka xibye xa mati exikarhi ka tabernakela ya nhlanganiso ni alitari, u chela mati endzeni.”' },
    { n: 8, text: '“U ta veka rivale ku rhendzela, u endla nkhombolo wa munyangweni wa rivale.”' },
    { n: 9, text: '“U ta teka mafurha ya ku tota, u tota tabernakela ni hinkwaswo leswi nga endzeni, u swi kwetsimisa, swi va swo kwetsima.”' },
    { n: 10, text: '“U ta tota alitari ya xitlhavelo xo hisiwa ni swibye swa yona hinkwaswo, u kwetsimisa alitari, yi va yo kwetsima swinene.”' },
    { n: 11, text: '“U ta tota xibye xa mati ni xisekelo xa xona, u xi kwetsimisa.”' },
    { n: 12, text: '“U ta tisa Aroni ni vana va yena emunyangweni wa tabernakela ya nhlanganiso, u va hlantswa hi mati.”' },
    { n: 13, text: '“U ta ambexa Aroni tinguvu to kwetsima, u n’wi tota, u n’wi kwetsimisa leswaku a va muprista eka mina.”' },
    { n: 14, text: '“U ta tisa vana va yena, u va ambexa tinguvu.”' },
    { n: 15, text: '“U ta va tota hilaha u totikeke tata wa vona, leswaku va va vaprista eka mina, ku tota ka vona ku ta va vutirheli lebyi nga heriki eka tinxaka ta vona.”' },
    { n: 16, text: 'Moxe a endla hinkwaswo hilaha Yehovha a leriseke hakona.' },
    { n: 17, text: 'Hi lembe ra vumbirhi, hi n’weti wo sungula, hi siku ro sungula ra n’weti, tabernakela yi yimisiwa.' },
    { n: 18, text: 'Moxe a yimisa tabernakela, a veka swisekelo swa yona, a yimisa makhumbi ya yona, a nghenisa timhandzi ta yona, a yimisa timhandzi ta yona.' },
    { n: 19, text: 'A aneka ntsimba ehenhla ka tabernakela, a veka xifunengeto xa yona ehenhla, hilaha Yehovha a leriseke Moxe.' },
    { n: 20, text: 'A teka vumbhoni, a byi veka endzeni ka areka, a veka timhandzi eka areka, a veka xifunengeto ehenhla ka areka.' },
    { n: 21, text: 'A nghenisa areka etabernakela, a veka nkhombolo wa ku funengeta, a funengeta areka ya vumbhoni, hilaha Yehovha a leriseke Moxe.' },
    { n: 22, text: 'A veka tafula etabernakela ya nhlanganiso, etlhelweni ra n’walungu ra tabernakela, ehandle ka nkhombolo.' },
    { n: 23, text: 'A veka xinkwa ehenhla ka rona mahlweni ka Yehovha, hilaha Yehovha a leriseke Moxe.' },
    { n: 24, text: 'A veka xitirho xa rivoningo etabernakela ya nhlanganiso, mahlweni ka tafula, etlhelweni ra dzonga ra tabernakela.' },
    { n: 25, text: 'A lumeka rivoningo mahlweni ka Yehovha, hilaha Yehovha a leriseke Moxe.' },
    { n: 26, text: 'A veka alitari ya nsuku etabernakela ya nhlanganiso, mahlweni ka nkhombolo.' },
    { n: 27, text: 'A hisa nun’hwelo wa swirungo ehenhla ka yona, hilaha Yehovha a leriseke Moxe.' },
    { n: 28, text: 'A veka nkhombolo wa munyangweni wa tabernakela.' },
    { n: 29, text: 'A veka alitari ya xitlhavelo xo hisiwa emunyangweni wa tabernakela ya nhlanganiso, a nyikela xitlhavelo xo hisiwa ni magandzelo ya swakunwa, hilaha Yehovha a leriseke Moxe.' },
    { n: 30, text: 'A veka xibye xa mati exikarhi ka tabernakela ya nhlanganiso ni alitari, a chela mati endzeni xo hlantswela.' },
    { n: 31, text: 'Moxe ni Aroni ni vana va yena va hlantswa mavoko ya vona ni milenge ya vona eka xona.' },
    { n: 32, text: 'Loko va nghena etabernakela ya nhlanganiso, ni loko va tshinela ealitari, va hlantswa, hilaha Yehovha a leriseke Moxe.' },
    { n: 33, text: 'A aka rivale ku rhendzela tabernakela ni alitari, a veka nkhombolo wa munyangweni wa rivale. Moxe a heta ntirho.' },
    { n: 34, text: 'Mupapa wu funengeta tabernakela ya nhlanganiso, naswona ku kwetsima ka Yehovha ku tata tabernakela.' },
    { n: 35, text: 'Moxe a a nga koti ku nghena etabernakela ya nhlanganiso, hikuva mupapa a wu yimile ehenhla ka yona, naswona ku kwetsima ka Yehovha ku tate tabernakela.' },
    { n: 36, text: 'Loko mupapa wu suka ehenhla ka tabernakela, vana va Israyele va famba etindleleni hinkwato ta vona.' },
    { n: 37, text: 'Kambe loko mupapa wu nga suki, va nga fambi ku fika siku leri wu sukaka.' },
    { n: 38, text: 'Hikuva mupapa wa Yehovha a wu ri ehenhla ka tabernakela hi nhlekanhi, naswona ndzilo a wu ri ehenhla ka yona ni vusiku, mahlweni ka yindlu hinkwayo ya Israyele etindleleni hinkwato ta vona.' },
  ],
};
